-- Poems batch 122
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('30c7a462-6031-477f-8e4b-e7f8f6f2f4f2','雪後龜堂獨坐四首  其四','陸游','宋','宋诗','song-poetry','','[]','閉門屋漏不可居，出門雪泥深尺餘。',64,'全唐诗/poet.song.133000.json','["閉門屋漏不可居，出門雪泥深尺餘。", "興闌已回剡溪櫂，路滑罷借東家驢。", "竹窗兀兀無與語，澆愁賴有酒一壺。", "眼花耳熱睡至夜，吹火起讀殘編書。"]'),
('041dccea-e076-4a8e-807f-4c33fbaf3b61','二月一日作','陸游','宋','宋诗','song-poetry','','[]','狼籍梅花委道傍，山櫻已復占年光。',64,'全唐诗/poet.song.133000.json','["狼籍梅花委道傍，山櫻已復占年光。", "簷消積雪時聞滴，衣覆殘爐剩得香。", "老馬已衰寧識路，寒龜未死且搘床。", "柴荆終日無來客，賴有陶詩伴日長。"]'),
('e97f4d29-e341-4cbe-a539-3ffccaf3d624','過東鄰歸小憩','陸游','宋','宋诗','song-poetry','','[]','籃輿過鄰曲，綠野喜新晴。',48,'全唐诗/poet.song.133000.json','["籃輿過鄰曲，綠野喜新晴。", "暖日生花氣，豐年入碓聲。", "筑陂鄉竭作，買犢戶深耕。", "歸舍還尋睡，殘書傍枕橫。"]'),
('ce9016f8-cd21-4595-a179-e18bb28a7c2f','寄呂子和南廂','陸游','宋','宋诗','song-poetry','','[]','聖代多名德，君家不乏公。',48,'全唐诗/poet.song.133000.json','["聖代多名德，君家不乏公。", "還看短袍綠，來蹋軟塵紅。", "小忍便無事，力行方有功。", "官閑能念我，時寄尺書東。"]'),
('9423280e-8c4e-4fdd-8a7f-2a77ca11a9c8','自述','陸游','宋','宋诗','song-poetry','','[]','藜藿安貧陋，柴荆俯莽蒼。',48,'全唐诗/poet.song.133000.json','["藜藿安貧陋，柴荆俯莽蒼。", "露蓍朝筮易，掃地晝焚香。", "美睡天教懶，長歌客恕狂。", "歡然送餘日，醉死亦何傷。"]'),
('6e94bae9-dd23-419d-9004-4642ff5b69f3','呂氏子夔郎求詩','陸游','宋','宋诗','song-poetry','','[]','乃祖身兼將相崇，諸孫玉立有家風。',64,'全唐诗/poet.song.133000.json','["乃祖身兼將相崇，諸孫玉立有家風。", "此郎己復塵埃外，它日相期氣類中。", "行己勤勤須自省，讀書亹亹要新功。", "果能哮吼如獅子，一瓣香應嗣放翁。"]'),
('058bf62d-6137-48db-b8fd-06bfcec928dc','新晴','陸游','宋','宋诗','song-poetry','','[]','兼旬不雨亦常陰，一日新晴抵萬金。',64,'全唐诗/poet.song.133000.json','["兼旬不雨亦常陰，一日新晴抵萬金。", "浦面波紋春縠細，橋頭柳色麴塵深。", "關山滿眼愁千斛，歲月催人雪一簪。", "猶有强寬懷抱處，午窗睡起聽鳴禽。"]'),
('dbd1a491-29bc-48bc-adaf-5f69590e25ea','晚步湖堤歸偶作','陸游','宋','宋诗','song-poetry','','[]','酒盡知難折簡呼，出門仍苦要人扶。',64,'全唐诗/poet.song.133000.json','["酒盡知難折簡呼，出門仍苦要人扶。", "殘梅委地香誰惜，歸雁穿雲遠欲無。", "日落牛羊猶被野，農閑畚鍤正開湖。", "還家寂寞西窗晚，旋燎枯枝擁地爐。"]'),
('1bd3e684-d3c2-4092-b11c-3cf957cecc3d','春來食不足戲作','陸游','宋','宋诗','song-poetry','','[]','饑卧誰能羨屬饜，高懷飽食豈容兼。',64,'全唐诗/poet.song.133000.json','["饑卧誰能羨屬饜，高懷飽食豈容兼。", "分司祿在終難取，束帛恩深獨不霑。", "衰謝形容無藥駐，奔馳日月欠膠黏。", "兒童拍手看翁醉，山杏溪桃簇帽簷。"]'),
('85eed9d6-b509-4507-ac33-505a301c4a4f','散步湖堤上時方瀰湖水面稍渺瀰矣','陸游','宋','宋诗','song-poetry','','[]','老覺人間萬事輕，不妨閑處得閑行。',64,'全唐诗/poet.song.133000.json','["老覺人間萬事輕，不妨閑處得閑行。", "西山鳥沒暮雲合，南浦堤平春水生。", "孤操不渝無鶴怨，淡交耐久有鷗盟。", "先民幸處吾能勝，生長兵間老太平。"]'),
('256f32f8-974d-4c54-acff-27786dca2637','老學庵','陸游','宋','宋诗','song-poetry','','[]','老學衡茅底，秋毫敢自欺。',48,'全唐诗/poet.song.133000.json','["老學衡茅底，秋毫敢自欺。", "開編常默識，閉戶有餘師。", "大節艱危見，真心夢寐知。", "唐虞元在眼，生世未爲遲。"]'),
('287594ea-5fe1-43bb-badb-3fa1408dee2a','春晚','陸游','宋','宋诗','song-poetry','','[]','强尋殘夢苦難成，推枕搘藤繞舍行。',64,'全唐诗/poet.song.133000.json','["强尋殘夢苦難成，推枕搘藤繞舍行。", "新漲生波漁艇活，晨曦送暖客衣輕。", "烟迷芳草蒼茫色，鵲占高枝嚄唶聲。", "老病自憐猶嗜學，誦書家塾羨諸生。"]'),
('c4c1c91b-d533-4897-bc28-bf88ee6932ec','龜堂雨後作','陸游','宋','宋诗','song-poetry','','[]','澤國春多雨，龜堂病少悰。',48,'全唐诗/poet.song.133000.json','["澤國春多雨，龜堂病少悰。", "雖名舊朝士，其實老耕農。", "一點葦間火，數聲烟外鐘。", "詩材故不乏，處處起衰慵。"]'),
('6bca1dbb-9aff-4114-a95f-2318eaabd664','書感','陸游','宋','宋诗','song-poetry','','[]','我欲哭窮途，所懼世俗驚。',120,'全唐诗/poet.song.133000.json','["我欲哭窮途，所懼世俗驚。", "出門復入門，掩泪且吞聲。", "唐虞邈難繼，周孔不復生。", "承學百世下，我輩責豈輕。", "楊墨斥已殫，釋老猶縱橫。", "拔本塞其源，力盡志未平。", "吾道如皦日，薄食終必明。", "一木雖獨立，可支大厦傾。", "夷風方變夏，孰能作長城。", "卓哉易簀公，垂死猶力行。"]'),
('d5766cb5-59d1-4a32-b990-0eada1232d63','後書感','陸游','宋','宋诗','song-poetry','','[]','貧賤終身志不移，閉關涵泳賴書詩。',64,'全唐诗/poet.song.133000.json','["貧賤終身志不移，閉關涵泳賴書詩。", "唐虞未遠如親見，周孔猶存豈我欺。", "力學正須忘寢食，少年誤計事文辭。", "爾來朋友皆雲散，考質從誰盡所疑。"]'),
('e8073433-05b1-4182-98f2-7e955ee5fd1d','村居書喜','陸游','宋','宋诗','song-poetry','','[]','紅橋梅市曉山橫，白塔樊江春水生。',64,'全唐诗/poet.song.133000.json','["紅橋梅市曉山橫，白塔樊江春水生。", "花氣襲人知驟暖，鵲聲穿樹喜新晴。", "坊場酒賤貧猶醉，原野泥深老亦耕。", "最喜先期官賦足，經年無吏叩柴荆。"]'),
('66127f9f-f7b8-41ef-a717-a9bd29b955e0','中春偶書','陸游','宋','宋诗','song-poetry','','[]','鄰曲祈蠶候，陂塘浸種時。',48,'全唐诗/poet.song.133000.json','["鄰曲祈蠶候，陂塘浸種時。", "春寒薪炭覺，雨霽鼓鐘知。", "驢瘦衝泥怯，魚驚食釣遲。", "衰翁一味懶，耕養愧吾兒。"]'),
('81e72f68-1037-4135-be89-5cd1029c1028','夜泊','陸游','宋','宋诗','song-poetry','','[]','小聚近江干，中春尚爾寒。',48,'全唐诗/poet.song.133000.json','["小聚近江干，中春尚爾寒。", "釣船隨鷺宿，烟月伴鐘殘。", "冉冉歲時速，茫茫天地寬。", "推篷一搔首，無處著悲歡。"]'),
('96934bbf-5a6a-43cd-977c-3f06954b8be6','東岡櫻桃已過殊不知','陸游','宋','宋诗','song-poetry','','[]','病著寒侵怕出門，蕭蕭烟雨暗江村。',32,'全唐诗/poet.song.133000.json','["病著寒侵怕出門，蕭蕭烟雨暗江村。", "一樽闕與梅花別，過盡櫻桃不足言。"]'),
('d2199ecc-974d-4057-886e-bb9255f3338f','別嚴和之二首  其一','陸游','宋','宋诗','song-poetry','','[]','器之魂逝已難招，尚有和之慰寂寥。',32,'全唐诗/poet.song.133000.json','["器之魂逝已難招，尚有和之慰寂寥。", "今夜月明空嘆息，想君孤棹泊溪橋。"]'),
('ac774b29-3a6e-4a36-b282-6efbc5610588','別嚴和之二首  其二','陸游','宋','宋诗','song-poetry','','[]','千里風烟行路難，旅舟應過子陵灘。',32,'全唐诗/poet.song.133000.json','["千里風烟行路難，旅舟應過子陵灘。", "人間富貴知何物，莫負君家舊釣竿。"]'),
('59468508-3eab-42d5-9fb8-b02c8009b1d7','齋中雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','湖水日益長，柳色日益深。',72,'全唐诗/poet.song.133000.json','["湖水日益長，柳色日益深。", "好鳥西山來，飛鳴過前林。", "年華挽不留，陳迹曠難尋。", "花開少共賞，酒熟惟孤斟。", "王謝今編氓，曲水空山陰。", "一樽欲吊古，已矣子何心。"]'),
('f5a60817-c86f-4636-bb60-f89a67db5135','齋中雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','屯雲失南山，三日吹細雨。',72,'全唐诗/poet.song.133000.json','["屯雲失南山，三日吹細雨。", "歲月不貸人，蛙聲遽如許。", "一年復一年，老至不可禦。", "下溼病在脾，餘息僅如縷。", "枯皮裹瘦骨，半屬松下土。", "屋壞要當顛，安能强撐拄。"]'),
('e1084f9c-6c3b-42df-92a5-b44f53b018c8','齋中雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','書生每苦饑，得飯已可賀。',72,'全唐诗/poet.song.133000.json','["書生每苦饑，得飯已可賀。", "黄齏三百甕，自是天所破。", "有時尚不繼，得米無暇簸。", "昨者雪塞門，烟絕但僵卧。", "雖云迫溝壑，老學不敢惰。", "夜分喚鄰翁，我歌爾當和。"]'),
('bec6ac6d-7abe-40ab-ad56-edadb64e7d07','齋中雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','西窗日過中，饑坐生眼花。',84,'全唐诗/poet.song.133000.json','["西窗日過中，饑坐生眼花。", "援筆課小詩，墨燥字傾斜。", "須臾忽滿紙，翩翩若風鴉。", "雖無古人法，簡拙自一家。", "乃知雨漏壁，未愧錐畫沙。", "俄報豆飯熟，投筆喜莫涯。", "呼童拾澗薪，試我家山茶。"]'),
('d65a3bdd-f360-4c50-bd38-4baad76e3eb9','春晚','陸游','宋','宋诗','song-poetry','','[]','萍葉青浮水，蛙聲鬧徹明。',48,'全唐诗/poet.song.133000.json','["萍葉青浮水，蛙聲鬧徹明。", "川雲時聚散，天氣半陰晴。", "杏子爭梅結，鳩巢後鵲成。", "吾儕亦有役，過社更深耕。"]'),
('96bdccf4-0f6e-4ea4-88e7-aa45b7032f71','社日小飲','陸游','宋','宋诗','song-poetry','','[]','人生當惜老年時，醉插山花壓帽欹。',32,'全唐诗/poet.song.133000.json','["人生當惜老年時，醉插山花壓帽欹。", "世事恰如風過耳，微聾自好不須治。"]'),
('fc533580-b028-40a1-9542-40ee0785bc2b','山茶','陸游','宋','宋诗','song-poetry','','[]','雪裏開花到春晚，世間耐久孰如君。',32,'全唐诗/poet.song.133000.json','["雪裏開花到春晚，世間耐久孰如君。", "憑闌嘆息無人會，三十年前宴海雲。"]'),
('d813f512-9c2b-4a61-a779-4743914d9d5d','春夜','陸游','宋','宋诗','song-poetry','','[]','寂寂春將暮，迢迢夜未央。',48,'全唐诗/poet.song.133000.json','["寂寂春將暮，迢迢夜未央。", "膏殘燈焰短，杵急藥塵香。", "困思棲雙睫，羸軀寄一床。", "養慵新有味，初志悔軒昂。"]'),
('e2ac4632-52a9-4d6d-83f4-32b02fd956be','春遊','陸游','宋','宋诗','song-poetry','','[]','右軍不復見清真，賞會猶須我輩人。',64,'全唐诗/poet.song.133000.json','["右軍不復見清真，賞會猶須我輩人。", "幽夢斷時雞唱曉，短章成處鳥呼春。", "出山茶筍村墟鬧，上市蓴鱸匕筯新。", "速覓一壺隨處醉，風吹紅紫半成塵。"]'),
('ba07087a-44cd-4022-a19b-a05061cba5fc','北窗睡起','陸游','宋','宋诗','song-poetry','','[]','杏梢紅溼晝初長，睡過窗間半篆香。',64,'全唐诗/poet.song.133000.json','["杏梢紅溼晝初長，睡過窗間半篆香。", "久厭客遊歸自好，本無才術老何傷。", "依蒲不去群魚樂，點草還驚小蝶忙。", "堪笑放翁無一事，强將詩句占年光。"]'),
('4ce49ac1-f569-4af2-a3bb-77bf139386bf','北窗懷友','陸游','宋','宋诗','song-poetry','','[]','中年妄意慕軻雄，白首終希尺寸功。',64,'全唐诗/poet.song.133000.json','["中年妄意慕軻雄，白首終希尺寸功。", "落落要居流俗外，兢兢恐墮異端中。", "仰天俯地猶多愧，飯豆羹藜已過豐。", "幸有北窗堪講學，故交零落與誰同。"]'),
('811bd620-5ed7-4a19-bed8-193b6d0e8d87','舟中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','娥江西路石帆東，身寄鷗波浩蕩中。',64,'全唐诗/poet.song.133000.json','["娥江西路石帆東，身寄鷗波浩蕩中。", "疊疊沙痕留浦岸，疏疏日影透漁篷。", "詩人無復同盟在，酒債何時一洗空。", "已迫耄年宜易感，人生五十即稱翁。"]'),
('b9bb2589-64d0-45be-a4c6-eb94f2aa9a48','舟中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','晤語無人與遣愁，出門聊復弄輕舟。',64,'全唐诗/poet.song.133000.json','["晤語無人與遣愁，出門聊復弄輕舟。", "山穿烟雨參差出，水赴陂塘散漫流。", "隔葉雄雌鳴谷鳥，傍林子母過吳牛。", "數家清絕如圖畫，炊黍何妨得小留。"]'),
('baf52778-2c92-41ee-b5fd-6bf0d05b120b','湖村春興','陸游','宋','宋诗','song-poetry','','[]','桑柘相望雨露新，桃源自隱不緣秦。',64,'全唐诗/poet.song.133000.json','["桑柘相望雨露新，桃源自隱不緣秦。", "稻陂正滿初投種，蠶子方生未忌人。", "酒借鵝兒成淺色，魚憑雲母作修鱗。", "賽神歸晚比鄰醉，一笑猶關老子身。"]'),
('be421216-6937-4f7a-9996-e0504ec7afc3','鄰餉','陸游','宋','宋诗','song-poetry','','[]','結隊同秋穫，連穡聽夜舂。',48,'全唐诗/poet.song.133000.json','["結隊同秋穫，連穡聽夜舂。", "薄持聊共飽，熱啜却煩供。", "炊玉吳粳美，浮蛆社酒醲。", "時平多樂事，莫厭數從容。"]'),
('a4f58c8f-0301-41e9-8454-b5b4d38f0f34','久雨','陸游','宋','宋诗','song-poetry','','[]','風雨連旬日，屢空猶晏如。',48,'全唐诗/poet.song.133000.json','["風雨連旬日，屢空猶晏如。", "敢言苔及榻，僅免釜生魚。", "薺糝朝供鉢，松肪夜照書。", "百年如此過，作計未全疏。"]'),
('283a9739-d380-456c-87a2-2c0498321bb1','登山','陸游','宋','宋诗','song-poetry','','[]','困厄身垂老，登臨意未平。',48,'全唐诗/poet.song.133000.json','["困厄身垂老，登臨意未平。", "暮烟迷草色，宿雨壯溪聲。", "往古飛鴻沒，浮名脫髮輕。", "平生五字律，自笑尚關情。"]'),
('1c5abf84-9553-4c7f-a2b5-dec65d6b3082','讀易','陸游','宋','宋诗','song-poetry','','[]','大易中含造化機，王何元未造精微。',32,'全唐诗/poet.song.133000.json','["大易中含造化機，王何元未造精微。", "乾坤要自吾身看，卧聽雞鳴起索衣。"]'),
('0b5596e7-da1d-47be-9a53-bbab26ca1677','村居書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','四十餘年食太倉，賜骸恩許返耕桑。',64,'全唐诗/poet.song.133000.json','["四十餘年食太倉，賜骸恩許返耕桑。", "長絲出鬴蓴羹美，白雪翻匙稻飯香。", "酒戶知貧焚舊券，醫翁憐病獻新方。", "春殘睡足東窗下，聞道長安依舊忙。"]'),
('3f8e7905-c135-4f38-a0ca-b86bb10ecab5','村居書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','藥物枝梧病漸蘇，門前野老笑相呼。',64,'全唐诗/poet.song.133000.json','["藥物枝梧病漸蘇，門前野老笑相呼。", "春深水暖多魚婢，雨足年豐少麥奴。", "小飲杯盤隨事具，閑行巷陌倩人扶。", "題詩非復羌村句，誰與丹青作畫圖。"]'),
('224291e5-740e-40a6-a772-fb4fa89d6e60','春晚書村落間事','陸游','宋','宋诗','song-poetry','','[]','千古會稽城，閭閻樂太平。',48,'全唐诗/poet.song.133000.json','["千古會稽城，閭閻樂太平。", "豐年觀米價，霽色聽禽聲。", "俗儉憎浮侈，民淳力釣耕。", "豳詩有七月，字字要躬行。"]'),
('6ebe0934-2520-4e42-abf2-5ae80c51e253','雜興六首  其一','陸游','宋','宋诗','song-poetry','','[]','秦漢區區了目前，周家風化遂無傳。',32,'全唐诗/poet.song.133000.json','["秦漢區區了目前，周家風化遂無傳。", "君看八百年基業，盡在東山七月篇。"]'),
('7b6258f1-aa1b-4e92-bc08-008f4f96b318','雜興六首  其二','陸游','宋','宋诗','song-poetry','','[]','羲和分職授人時，斷自唐虞意可知。',32,'全唐诗/poet.song.133000.json','["羲和分職授人時，斷自唐虞意可知。", "獸舞鳳來餘事耳，西成東作要熙熙。"]'),
('4074dc34-58b1-48f7-932d-3e03b6d359a7','雜興六首  其三','陸游','宋','宋诗','song-poetry','','[]','老無添處仍逢病，春欲殘時未減寒。',32,'全唐诗/poet.song.133000.json','["老無添處仍逢病，春欲殘時未減寒。", "架上漢書渾忘盡，床頭周易却常看。"]'),
('2c419374-4a0e-4aad-a005-569df498f374','雜興六首  其四','陸游','宋','宋诗','song-poetry','','[]','一身逋負愁賒酒，滿眼關山悔上樓。',32,'全唐诗/poet.song.133000.json','["一身逋負愁賒酒，滿眼關山悔上樓。", "子細推來惟合睡，五更風雨已如秋。"]'),
('ce022bf4-8c7f-476d-a99d-d21ee288e167','雜興六首  其五','陸游','宋','宋诗','song-poetry','','[]','面顔日瘦口眼大，氣血頓衰鬚髮獰。',32,'全唐诗/poet.song.133000.json','["面顔日瘦口眼大，氣血頓衰鬚髮獰。", "不用凌烟寫冠劍，一蓑烟雨事春耕。"]'),
('0859aa16-aa7b-4be0-b7b7-1d7600ab833d','雜興六首  其六','陸游','宋','宋诗','song-poetry','','[]','故交零落形吊影，陳迹凄凉口語心。',32,'全唐诗/poet.song.133000.json','["故交零落形吊影，陳迹凄凉口語心。", "辛苦一生成底事，祈招空解誦愔愔。"]'),
('2b064acc-460b-4af6-954c-8abb0846a553','南堂獨坐','陸游','宋','宋诗','song-poetry','','[]','晨坐南堂雙眼明，南山山色滿柴荆。',64,'全唐诗/poet.song.133000.json','["晨坐南堂雙眼明，南山山色滿柴荆。", "片雲忽過失簾影，急雨初來聞竹聲。", "鸚鵡螺深生酒興，蟾蜍滴古助詩情。", "野人頻約天台去，幾緉青鞋了此行。"]'),
('0ab63ea3-34bf-40e2-8e82-5fc33e2f4598','春雨示鄰曲','陸游','宋','宋诗','song-poetry','','[]','春來天氣苦蕭森，如縷雲升便作霖。',64,'全唐诗/poet.song.133000.json','["春來天氣苦蕭森，如縷雲升便作霖。", "寒溜何曾住一滴，綠陰忽已遍千林。", "蓴絲箭茁垂垂老，蓼浦菱塘灧灧深。", "聞道南山花尚在，約君携酒試同尋。"]'),
('d49194f8-7b80-4212-a886-1d52107b46f6','讀書','陸游','宋','宋诗','song-poetry','','[]','堯庭君相都俞盛，闕里師生博約深。',32,'全唐诗/poet.song.133000.json','["堯庭君相都俞盛，闕里師生博約深。", "我讀殘編食忘味，朱絃三歎有遺音。"]'),
('35c72a4a-b74c-49e8-a2a9-08c337257273','新晴賞牡丹','陸游','宋','宋诗','song-poetry','','[]','杜門睡榻長蒼苔，滿眼新晴亦樂哉。',64,'全唐诗/poet.song.133000.json','["杜門睡榻長蒼苔，滿眼新晴亦樂哉。", "小市忽逢蓴菜出，曲欄初見牡丹開。", "不嫌雨後泥三尺，且趁春殘醉幾回。", "自揣明年猶健在，東箱更覓茜金栽。"]'),
('3d3233e1-86c2-499a-9e69-c7fb8884f849','對酒','陸游','宋','宋诗','song-poetry','','[]','神僊豈易學，富貴不容求。',48,'全唐诗/poet.song.133000.json','["神僊豈易學，富貴不容求。", "百歲儻未盡，一樽差可謀。", "鐘鳴上方晚，桂發小山秋。", "處處多幽趣，攢眉勿浪愁。"]'),
('a37a083d-7853-4106-8a4b-bfeb76f27e04','病起遇晴有作','陸游','宋','宋诗','song-poetry','','[]','十日春雨霪，百疾投間作。',96,'全唐诗/poet.song.133000.json','["十日春雨霪，百疾投間作。", "呻吟雖甚苦，飲啗尚自若。", "筋骸則已疲，正氣亦消鑠。", "行年垂八十，所恃豈在藥。", "魔軍累百萬，指顧可盡縛。", "君看仁義師，何至用韜略。", "川雲忽破散，平地見日脚。", "無人畫此翁，縹渺立孤鶴。"]'),
('516611dd-6959-4a16-b466-68f422fe6628','定命','陸游','宋','宋诗','song-poetry','','[]','定命元知不可移，更兼狂疾固難治。',64,'全唐诗/poet.song.133000.json','["定命元知不可移，更兼狂疾固難治。", "履穿衣弊窮居日，齒豁頭童大耋時。", "耕釣詩多悲境熟，功名夢少感年衰。", "今朝雨歇春泥散，剩伴兒童鬭草嬉。"]'),
('edcaa85a-bb5c-4f2e-a776-100632eccc7d','假山小池二首  其一','陸游','宋','宋诗','song-poetry','','[]','鑿池容斛水，壘石效遥岑。',48,'全唐诗/poet.song.133000.json','["鑿池容斛水，壘石效遥岑。", "鳥喜如相命，魚驚忽自沉。", "風來生細籟，雲度作微陰。", "便恐桃源近，無人與共尋。"]'),
('372a8d08-be7a-46a1-9543-692e446de331','假山小池二首  其二','陸游','宋','宋诗','song-poetry','','[]','蓮嶽三峰峙，桃源一路分。',48,'全唐诗/poet.song.133000.json','["蓮嶽三峰峙，桃源一路分。", "池偷鏡湖月，石带沃洲雲。", "魚隊深猶見，禽聲靜更聞。", "巖幽林箐密，疑可下湘君。"]'),
('5ed18944-c563-41c2-a906-5bb9f12938fe','春欲盡天氣始佳作詩自娛','陸游','宋','宋诗','song-poetry','','[]','浮雲飛盡見青天，拄杖閑拈瘦倚肩。',64,'全唐诗/poet.song.133000.json','["浮雲飛盡見青天，拄杖閑拈瘦倚肩。", "漸喜綠秧分䆉䅉，又看畫柱坼鞦韆。", "雞豚雜遝祈蠶社，鼓笛喧譁競渡船。", "惟有此翁無一事，閉門贏得日高眠。"]'),
('d7a50a14-d96a-4504-9cd3-0d101bff7213','自詠','陸游','宋','宋诗','song-poetry','','[]','生草覆蝸廬，長鬚駕鹿車。',48,'全唐诗/poet.song.133000.json','["生草覆蝸廬，長鬚駕鹿車。", "貧猶思施樂，老不廢觀書。", "登覽携童稚，歌呼和里閭。", "躬耕亦何得，聊以遂吾初。"]'),
('4ca0b0d2-95ec-40c9-b8b8-18c6f716a430','西村勞農','陸游','宋','宋诗','song-poetry','','[]','川雲散盡十分晴，繚出溪頭信意行。',64,'全唐诗/poet.song.133000.json','["川雲散盡十分晴，繚出溪頭信意行。", "片片飛花隨步遠，離離芳草上牆生。", "村深日暖單衣爽，路轉沙平兩履輕。", "膰肉芬香坊酒釅，因來聊得餉春耕。"]'),
('3e9eebcd-f497-4bad-a079-9c0b35c17162','題廬陵蕭彥毓秀才詩卷後二首  其一','陸游','宋','宋诗','song-poetry','','[]','詩句雄豪易取名，爾來閑澹獨蕭卿。',32,'全唐诗/poet.song.133000.json','["詩句雄豪易取名，爾來閑澹獨蕭卿。", "蘇州死後風流絕，幾許工夫學得成。"]'),
('caa08e87-f988-43b7-b46e-f5540134aeba','題廬陵蕭彥毓秀才詩卷後二首  其二','陸游','宋','宋诗','song-poetry','','[]','法不孤生自古同，癡人乃欲鏤虛空。',32,'全唐诗/poet.song.133000.json','["法不孤生自古同，癡人乃欲鏤虛空。", "君詩妙處吾能識，正在山程水驛中。"]'),
('8298d1f6-f1e0-48f9-aec8-da715cbeb2d4','舍北溪上垂釣','陸游','宋','宋诗','song-poetry','','[]','大耋還家萬事非，垂竿好在綠苔磯。',64,'全唐诗/poet.song.133000.json','["大耋還家萬事非，垂竿好在綠苔磯。", "風和山雉挾雌過，村晚吳牛將犢歸。", "春漲新添塘灧灧，夕雲仍带雨霏霏。", "此生自笑狂顛足，依舊人間一布衣。"]'),
('1b55607c-dc47-4701-a078-57114d0f5f35','三月二十二日作','陸游','宋','宋诗','song-poetry','','[]','雨過草爭出，溪湍魚逆行。',48,'全唐诗/poet.song.133000.json','["雨過草爭出，溪湍魚逆行。", "輕舟摘蓴菜，小市聽鶯聲。", "萬事已無夢，一樽猶有情。", "吾兒能講學，不必說無生。"]'),
('8a9f6244-e202-416f-bc2e-95d522d7b03c','書感','陸游','宋','宋诗','song-poetry','','[]','頭顱已可知，牙齒今復落。',216,'全唐诗/poet.song.133000.json','["頭顱已可知，牙齒今復落。", "十步或再休，啜粥不及勺。", "身依一蒲團，壁挂兩芒屩。", "對客輒坐睡，有問莫能酢。", "念昔少壯時，心慕宦遊樂。", "初登平津館，晚入征西幕。", "雨暗駱谷烽，霜清散關柝。", "登高望中原，氣已吞雍雒。", "寧知事大謬，憔悴理征橐。", "單車去梁益，健席下沔鄂。", "還朝見故人，大馬黄金絡。", "後來固多士，鵷鷺照臺閣。", "婆娑郎吏間，祇自取嘲噱。", "歷思從來事，無鐵可打錯。", "幸得還故園，快若解束縛。", "閭里通有無，情厚不爲薄。", "泥行事春耕，日曝畢秋穫。", "隔牆喚鄰翁，濁酒聊共酌。"]'),
('9d2d65c1-0dec-4389-b223-cf45b29134c6','寒食','陸游','宋','宋诗','song-poetry','','[]','小市禁烟餘，東郊展墓初。',48,'全唐诗/poet.song.133000.json','["小市禁烟餘，東郊展墓初。", "桐陰覆碧井，泉脈入清渠。", "貧悴停遊舫，龍鍾廢荷鉏。", "西窗斜日在，且復勘殘書。"]'),
('01583126-4464-4508-92d1-c76f5146a35c','西村暮歸','陸游','宋','宋诗','song-poetry','','[]','天氣清和修禊後，土風淳古結繩前。',64,'全唐诗/poet.song.133000.json','["天氣清和修禊後，土風淳古結繩前。", "村村陂足分秧水，戶戶門通入郭船。", "亭障盜消常息鼓，坊場酒賤不論錢。", "行人爭看山翁醉，頭枕槐根卧道邊。"]'),
('a0da06d3-cc7a-4bf4-8165-f554a44327f3','舍外彌望皆青秧白水喜而有賦','陸游','宋','宋诗','song-poetry','','[]','此地天教著放翁，舍傍烟樹晚空濛。',64,'全唐诗/poet.song.133000.json','["此地天教著放翁，舍傍烟樹晚空濛。", "一無可恨得歸老，寸有所長能忍窮。", "東作已趨堯舊俗，南薰方詠舜遺風。", "謝安勳業能多少，枉是匆匆起剡中。"]'),
('a648fad3-b9ad-45a2-93ab-e91ba48838cc','寄題太和陳誠之秀才遠明樓','陸游','宋','宋诗','song-poetry','','[]','宦遊再有江西役，南望廬陵每慨然。',64,'全唐诗/poet.song.133000.json','["宦遊再有江西役，南望廬陵每慨然。", "未見高樓出雲雨，但驚妙語雜風烟。", "諸公何止元和盛，獨我初非正始賢。", "筆力深知太遼絕，此詩它日勿同編。"]'),
('8f0c36e0-deb6-408f-a389-c2ba60ee33fb','蝸舍','陸游','宋','宋诗','song-poetry','','[]','蝸舍茨生草，龜腸飽淖糜。',48,'全唐诗/poet.song.133000.json','["蝸舍茨生草，龜腸飽淖糜。", "麥因多雨損，蠶遇閏年遲。", "徙義憂無勇，求仁戒自欺。", "此生雖欲盡，吾志未應衰。"]'),
('6935fdc7-1781-4520-9848-51d48a7beeeb','東岡','陸游','宋','宋诗','song-poetry','','[]','東岡竹千竿，大者圍過尺。',72,'全唐诗/poet.song.133000.json','["東岡竹千竿，大者圍過尺。", "微風生其間，蕭蕭戛寒碧。", "我閑適一到，散髮坐磐石。", "萬事不累心，清嘯遂至夕。", "此君本傲世，獨我有夙昔。", "老惰恐作疏，時來寓琴弈。"]'),
('c2e9caf2-c082-46e7-913a-6b8def0efeb9','首夏','陸游','宋','宋诗','song-poetry','','[]','亂山深處著柴荆，岸幘披衣露氣清。',64,'全唐诗/poet.song.133000.json','["亂山深處著柴荆，岸幘披衣露氣清。", "宴坐有書聊作伴，出遊無客獨題名。", "陰陰密樹花初盡，灧灧方池水已平。", "幾許人間堪笑事，今朝百舌頓無聲。"]'),
('f8600250-11f5-4dd1-800f-91b87ed37283','贈曾溫伯邢德允','陸游','宋','宋诗','song-poetry','','[]','髮似秋蕪不受耘，茶山曾許與斯文。',64,'全唐诗/poet.song.133000.json','["髮似秋蕪不受耘，茶山曾許與斯文。", "回思歲月一甲子，尚記門牆三沐熏。", "卷裏聖賢能覿面，人間富貴實浮雲。", "二君才氣俱超絕，豈待衰翁誦所聞。"]'),
('51b7a31e-5fbd-404b-a1d9-9214d5e56956','自述三首  其一','陸游','宋','宋诗','song-poetry','','[]','古井無由浪，浮雲一掃空。',48,'全唐诗/poet.song.133000.json','["古井無由浪，浮雲一掃空。", "詩書修孔業，場圃嗣豳風。", "懼在饑寒外，憂形寤寐中。", "吾年雖日逝，猶冀有新功。"]'),
('158be8b2-7c1b-481e-83f7-a514766816b0','自述三首  其二','陸游','宋','宋诗','song-poetry','','[]','舊業還耕釣，殘年迫耄期。',48,'全唐诗/poet.song.133000.json','["舊業還耕釣，殘年迫耄期。", "筋骸衰後覺，力量夢中知。", "客約溪亭飲，僧招竹院棋。", "未爲全省事，終勝宦遊時。"]'),
('cb718e2b-3bd3-4d2b-b786-a97e6056452a','自述三首  其三','陸游','宋','宋诗','song-poetry','','[]','屏迹歸休後，頤生寂寞中。',48,'全唐诗/poet.song.133000.json','["屏迹歸休後，頤生寂寞中。", "忍貧辭半俸，學古得全功。", "西埭村醅釅，東陂小彴通。", "經行有佳趣，稚子也能同。"]'),
('4869f05e-949e-4980-ab4c-7c6a29afd089','示客','陸游','宋','宋诗','song-poetry','','[]','一點昏燈兩部蛙，客來相對半甌茶。',64,'全唐诗/poet.song.133000.json','["一點昏燈兩部蛙，客來相對半甌茶。", "典衣未贖身饒蝨，治米無工飯有沙。", "每爲采菱浮野艇，時因賣藥宿山家。", "青鞋到處堪乘興，不獨雲門與若耶。"]'),
('c5ebb120-eb4f-434c-b008-5e930178c2a1','對食戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','香粳炊熟泰州紅，苣甲蓴絲放箸空。',32,'全唐诗/poet.song.133000.json','["香粳炊熟泰州紅，苣甲蓴絲放箸空。", "不爲休官須惜費，從來簡儉作家風。"]'),
('be834266-6ed4-4450-bfaa-fb2bad72c97f','對食戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','米如玉粒喜新舂，菜出烟畦旋摘供。',32,'全唐诗/poet.song.133000.json','["米如玉粒喜新舂，菜出烟畦旋摘供。", "但使胸中無愧怍，一餐美敵紫駝峰。"]'),
('1271eab5-daa0-4926-b93c-199c60cace11','對酒戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','杖頭高挂百青銅，小立旗亭滿袖風。',32,'全唐诗/poet.song.133000.json','["杖頭高挂百青銅，小立旗亭滿袖風。", "莫笑村醪薄無力，衰顔也得暫時紅。"]'),
('88b4f194-9a43-4a53-a1fd-b4076400f3d1','對酒戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','亂插酴醿壓帽偏，鵝黄酒色映觵船。',32,'全唐诗/poet.song.133000.json','["亂插酴醿壓帽偏，鵝黄酒色映觵船。", "醺然一枕虛堂睡，頓覺情懷似少年。"]'),
('bf1da52a-6a83-4ae5-982f-77d0936790e8','夏初湖村雜題八首  其一','陸游','宋','宋诗','song-poetry','','[]','市遠村深客到稀，草堂終日掩柴扉。',32,'全唐诗/poet.song.133000.json','["市遠村深客到稀，草堂終日掩柴扉。", "釀成新蜜蜂兒靜，分盡殘泥燕子歸。"]'),
('72ae5f78-cd25-4e4f-a192-c2644d823bf4','夏初湖村雜題八首  其二','陸游','宋','宋诗','song-poetry','','[]','嫩日輕風夏未深，曲廊倚杖得閑吟。',32,'全唐诗/poet.song.133000.json','["嫩日輕風夏未深，曲廊倚杖得閑吟。", "地偏草茂無人迹，一對茭雞下綠陰。"]'),
('de0b73f0-ef38-4ac3-9438-97ae9cea76c0','夏初湖村雜題八首  其三','陸游','宋','宋诗','song-poetry','','[]','寒泉自換菖蒲水，活火閑煎橄欖茶。',32,'全唐诗/poet.song.133000.json','["寒泉自換菖蒲水，活火閑煎橄欖茶。", "自是閑人足閑趣，本無心學野僧家。"]'),
('6a94994c-6843-4901-9b25-994b51ba33f8','夏初湖村雜題八首  其四','陸游','宋','宋诗','song-poetry','','[]','日落溪南生暮烟，幅巾蕭散立橋邊。',32,'全唐诗/poet.song.133000.json','["日落溪南生暮烟，幅巾蕭散立橋邊。", "聽殘賽廟鼕鼕鼓，數盡歸村隻隻船。"]'),
('68951e84-09e9-433b-9cc6-c1b00f3ec578','夏初湖村雜題八首  其五','陸游','宋','宋诗','song-poetry','','[]','胎髮茸茸漆不如，夏初安健勝春初。',32,'全唐诗/poet.song.133000.json','["胎髮茸茸漆不如，夏初安健勝春初。", "雙瞳懶看公卿面，却解燈前讀細書。"]'),
('534bf55c-c39f-4973-97bd-bbd20bb09dac','夏初湖村雜題八首  其六','陸游','宋','宋诗','song-poetry','','[]','從來抵死愛湖山，敢料天教半世閑。',32,'全唐诗/poet.song.133000.json','["從來抵死愛湖山，敢料天教半世閑。", "杜曲桑麻雖苦薄，灞橋風雪如相關。"]'),
('f09369be-ac50-42ec-bcc9-3ec0ea2b51c8','夏初湖村雜題八首  其七','陸游','宋','宋诗','song-poetry','','[]','幽禽兩兩已成巢，新竹森森漸放梢。',32,'全唐诗/poet.song.133000.json','["幽禽兩兩已成巢，新竹森森漸放梢。", "稻壟作陂先蓄水，野堂防漏却添茅。"]'),
('a4101af4-bb7d-4c77-b8e0-c2168ac37dc6','夏初湖村雜題八首  其八','陸游','宋','宋诗','song-poetry','','[]','門巷蕭條長綠苔，經旬清坐罷傳杯。',32,'全唐诗/poet.song.133000.json','["門巷蕭條長綠苔，經旬清坐罷傳杯。", "麴生風味那忘得，少待吾家芍藥開。"]'),
('4f6a3a53-b80a-4cd8-8d8b-ffacfd2ed0b3','溪上露坐','陸游','宋','宋诗','song-poetry','','[]','水際風生爽拂裾，比鄰自集不勞呼。',64,'全唐诗/poet.song.133000.json','["水際風生爽拂裾，比鄰自集不勞呼。", "昏鴉杳杳飛初定，遠樹離離望欲無。", "新竹出林時解籜，小荷翻露已成珠。", "橋東一徑蒼苔滑，歸舍還須稚子扶。"]'),
('705c2e40-2bf9-452d-a889-26774d504e92','北齋書志示兒輩','陸游','宋','宋诗','song-poetry','','[]','初夏佳風日，頹然坐北齋。',48,'全唐诗/poet.song.133000.json','["初夏佳風日，頹然坐北齋。", "百年從落魄，萬事忌安排。", "鄉俗能尊老，君恩許賜骸。", "饑寒雖未免，何足繫吾懷。"]'),
('6d09c52b-7046-4f13-ac73-770aad728e90','作盆池養科斗數十戲作','陸游','宋','宋诗','song-poetry','','[]','小小盆池不畜魚，題詩聊記破苔初。',32,'全唐诗/poet.song.133000.json','["小小盆池不畜魚，題詩聊記破苔初。", "未聽兩部鼓吹樂，且看一編科斗書。"]'),
('71b0ff54-674b-4e9d-9cc4-b0acac4c69bf','枕上','陸游','宋','宋诗','song-poetry','','[]','風竹無時靜，月窗終夜明。',48,'全唐诗/poet.song.133000.json','["風竹無時靜，月窗終夜明。", "時時聽驚鵲，一一數殘更。", "吳楚民猶困，燕齊虜未平。", "功名天所命，吾志固難成。"]'),
('6a0da5ff-0170-4b3f-bc64-d6db602f4d1b','晨起','陸游','宋','宋诗','song-poetry','','[]','終夜厭姑惡，經春無秭歸。',48,'全唐诗/poet.song.133000.json','["終夜厭姑惡，經春無秭歸。", "溪雲生慘慘，林日澹暉暉。", "物外孤懷勝，人間百慮非。", "鄰翁剡中去，爲我買漁衣。"]'),
('9ec27eef-8855-4bb0-a76f-c9b62d71ecad','喜晴','陸游','宋','宋诗','song-poetry','','[]','葛衣初著喜新晴，寂寂虛堂一榻橫。',64,'全唐诗/poet.song.133000.json','["葛衣初著喜新晴，寂寂虛堂一榻橫。", "乍坼孤花藏葉罅，晚歸雙燕拂簾旌。", "舞空不斷游絲直，掠地還飛落絮輕。", "剩欲倚闌尋好句，清笳已復動高城。"]'),
('629e56e3-be99-4ccd-ae09-6fb04a1dcaeb','讀夏書','陸游','宋','宋诗','song-poetry','','[]','巨浸稽天日沸騰，九州人死若丘陵。',32,'全唐诗/poet.song.133000.json','["巨浸稽天日沸騰，九州人死若丘陵。", "一朝財得居平土，峻宇雕牆已遽興。"]'),
('9d011534-40d4-4cfc-a8de-86daf65aff43','幽栖','陸游','宋','宋诗','song-poetry','','[]','何處是幽栖，城南路少西。',48,'全唐诗/poet.song.133000.json','["何處是幽栖，城南路少西。", "楊花穿戶入，燕子避簾低。", "棋局聊相對，茶爐亦自携。", "溪頭雲易合，晚雨又成泥。"]'),
('1ba4aab3-cade-4ba5-bdf7-a857dd9f024d','閑詠園中草木六首  其一','陸游','宋','宋诗','song-poetry','','[]','翦刀葉畔戲魚回，帔子花頭舞蝶來。',32,'全唐诗/poet.song.133000.json','["翦刀葉畔戲魚回，帔子花頭舞蝶來。", "領略年光屬閑客，一樽自勸不須推。"]'),
('4c58c03b-a143-486a-b629-4815c3dca463','閑詠園中草木六首  其二','陸游','宋','宋诗','song-poetry','','[]','麝香萱草移東郭，錦子葵花買上原。',32,'全唐诗/poet.song.133000.json','["麝香萱草移東郭，錦子葵花買上原。", "兒喚乃翁閑一看，欣然曳杖出籬門。"]'),
('6667cdba-e5cb-4a88-a575-05d27436a0f2','閑詠園中草木六首  其三','陸游','宋','宋诗','song-poetry','','[]','一樹山櫻鳥啄殘，懸鈎半舍亦甘酸。',32,'全唐诗/poet.song.133000.json','["一樹山櫻鳥啄殘，懸鈎半舍亦甘酸。", "兒童采得爭來餉，應念衰翁舌本乾。"]'),
('b79cf60e-63f8-4479-981f-ad5d5437ac62','閑詠園中草木六首  其四','陸游','宋','宋诗','song-poetry','','[]','綠侵小徑蟆衣草，青絡疏籬鬼带藤。',32,'全唐诗/poet.song.133000.json','["綠侵小徑蟆衣草，青絡疏籬鬼带藤。", "未暇開編尋本草，且將名品問山僧。"]'),
('983cd1a7-4450-496f-9d8a-06261bf43dda','閑詠園中草木六首  其五','陸游','宋','宋诗','song-poetry','','[]','日高未辦續晨炊，一碗村醅且療饑。',32,'全唐诗/poet.song.133000.json','["日高未辦續晨炊，一碗村醅且療饑。", "盤箸索然君勿笑，桑間紫椹正纍纍。"]'),
('3fc65f28-d639-4e86-a062-9c0106af586d','閑詠園中草木六首  其六','陸游','宋','宋诗','song-poetry','','[]','仲夏園中百草靈，風吹露坼各青青。',32,'全唐诗/poet.song.133000.json','["仲夏園中百草靈，風吹露坼各青青。", "勸君辦取金鴉觜，不問昌陽與豨苓。"]'),
('53bba71d-681d-4e97-aa90-74fd614720b1','夜雨','陸游','宋','宋诗','song-poetry','','[]','初夏雨淋浪，簷聲繞四廊。',48,'全唐诗/poet.song.133000.json','["初夏雨淋浪，簷聲繞四廊。", "感深頭易白，睡少漏偏長。", "紅捲簾旌溼，潤生衣焙香。", "清吟欲排悶，三嘆不成章。"]'),
('ceaf43b2-d3d1-49e9-8279-d107ee1dba81','晨起','陸游','宋','宋诗','song-poetry','','[]','海燕翩將乳，戎葵粲已繁。',48,'全唐诗/poet.song.133000.json','["海燕翩將乳，戎葵粲已繁。", "魚船初入市，蓴擔未過門。", "年耄停朝課，家貧省小餐。", "所欣行藥處，秧稻遍村村。"]'),
('db898757-22f5-4547-976a-34b5db0ffc07','放翁','陸游','宋','宋诗','song-poetry','','[]','拜賜頭銜號放翁，家傳不墜散人風。',64,'全唐诗/poet.song.133000.json','["拜賜頭銜號放翁，家傳不墜散人風。", "問年已過從心後，遇境但行無事中。", "馬老豈堪空冀北，鶴飛猶得返遼東。", "道傍跌宕煩君看，閱盡時人臉尚紅。"]'),
('14330123-3794-415e-a429-76cfe175453e','過鄰家','陸游','宋','宋诗','song-poetry','','[]','老病在臂踝，終日不喜動。',120,'全唐诗/poet.song.133000.json','["老病在臂踝，終日不喜動。", "溪雲忽過前，袖手以目送。", "今晨光景佳，霽色入鳥哢。", "駕言出柴荆，暫作湖山夢。", "東村望鶴巢，西阜過獾峒。", "父老意欣然，爲我撥春甕。", "豈惟澆舌燥，亦用軟脚痛。", "形骸去繩檢，談笑得少縱。", "吳蠶初上簇，陂稻亦己種。", "端五數日間，更約同解糭。"]'),
('f66a9455-fc23-4f53-bd01-d0aec9b0d591','東園','陸游','宋','宋诗','song-poetry','','[]','晨起東園去，消磨夏日長。',48,'全唐诗/poet.song.133000.json','["晨起東園去，消磨夏日長。", "隨鋤泉眼出，上爪藥苗香。", "琴挂山齋壁，龜搘道室床。", "始知彭澤令，真足傲羲皇。"]'),
('7b658323-fb15-4402-ae25-3a5d0ed9fc8f','曉出至湖桑埭','陸游','宋','宋诗','song-poetry','','[]','殘年孤寂不堪言，時喚平頭駕短轅。',64,'全唐诗/poet.song.133000.json','["殘年孤寂不堪言，時喚平頭駕短轅。", "老氣猶能作羆卧，壯懷誰復記鴻軒。", "櫂歌縹渺城西路，烟樹參差埭北村。", "堪笑怪奇消未盡，夜來還夢屬櫜鞬。"]'),
('0b182caa-9ce9-4f8d-87d9-7101cd7d80d7','雨夜觀史','陸游','宋','宋诗','song-poetry','','[]','讀書雨夜一燈昏，嘆息何由起九原。',64,'全唐诗/poet.song.133000.json','["讀書雨夜一燈昏，嘆息何由起九原。", "邪正古來觀大節，是非死後有公言。", "未能劇論希捫蝨，且復長歌學叩轅。", "它日安知無志士，經過指點放翁門。"]'),
('d77a470a-3c2e-423d-a572-5a11ef2e2e4e','雨復作','陸游','宋','宋诗','song-poetry','','[]','今日雲歸恰喜晴，小池忽見水紋生。',32,'全唐诗/poet.song.133000.json','["今日雲歸恰喜晴，小池忽見水紋生。", "窗昏又輟讎書課，卧聽蕭蕭打葉聲。"]'),
('b725326d-2827-402c-b036-7ebf34977ebc','園中','陸游','宋','宋诗','song-poetry','','[]','稚竹侵簷綠，新桐覆井凉。',48,'全唐诗/poet.song.133000.json','["稚竹侵簷綠，新桐覆井凉。", "閑身少羈束，隨處得徜徉。", "山鵲惺惚語，藤花掩冉香。", "吾詩有餘思，小復立西廂。"]'),
('6341d793-ed86-41e4-a170-00c6e62fb883','湖上遇道翁乃峽中舊所識也','陸游','宋','宋诗','song-poetry','','[]','大罵長歌儘放顛，時時一語却超然。',64,'全唐诗/poet.song.133000.json','["大罵長歌儘放顛，時時一語却超然。", "掃空百局無棋敵，倒盡千鍾是酒仙。", "巴峽相逢如昨日，山陰重見亦前緣。", "細思合辱先生友，五十年來不負天。"]'),
('485a8193-5187-4231-816a-778c59b10513','老學庵北作假山既成即雨彌月不止','陸游','宋','宋诗','song-poetry','','[]','古者封禪歲，乾封輒枯旱。',168,'全唐诗/poet.song.133000.json','["古者封禪歲，乾封輒枯旱。", "不言絕民食，徒欲曬日觀。", "我今作小山，纔及仞有半。", "下潴數斗水，草木稍葱蒨。", "蕞爾何足言，造物亦幽贊。", "冥冥一月雨，陰翳迷昏旦。", "芳草爭抽萌，珍木亦擢幹。", "龜魚出復沒，鳥雀聚仍散。", "彼天初何私，遺我耳目玩。", "遂令閭巷間，日厭鵓鴣喚。", "淖深樵蘇絕，有米不能爨。", "爲小乃害大，未可以理斷。", "憂懼塞胸中，當食屢興嘆。", "培塿固易平，荷鍤愧吾懦。"]'),
('3d9144bc-15f2-48ee-888f-6e4e7a7e918a','苦雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','儘道迎梅雨，能無一日晴。',48,'全唐诗/poet.song.133000.json','["儘道迎梅雨，能無一日晴。", "窗昏愁細字，簷滴亂疏更。", "未怪蛙爭席，真憂水冒城。", "何由收積潦，簫鼓賽西成。"]'),
('826d9188-dc40-40ca-9bfc-1b99a90059fe','苦雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','烟水茫無際，空階滴不休。',48,'全唐诗/poet.song.133000.json','["烟水茫無際，空階滴不休。", "一窗閑隱几，四月澹如秋。", "箔冷蠶遲績，泥深麥未收。", "家貧村酒薄，曷解老農憂。"]'),
('155aacde-143c-4494-bdac-62cbfff04e75','五月初作','陸游','宋','宋诗','song-poetry','','[]','鄰舍舂新麥，家人拾晚蠶。',48,'全唐诗/poet.song.133000.json','["鄰舍舂新麥，家人拾晚蠶。", "推移逢夏五，賦與嘆朝三。", "遣日須棋局，忘憂賴酒甔。", "幽居有高致，多取未爲貪。"]'),
('e68d6e57-fef4-4d66-a2c0-efaead9c4979','遊西村贈隱者','陸游','宋','宋诗','song-poetry','','[]','水清沙凈見遊魚，槐柳陰陰五月初。',64,'全唐诗/poet.song.133000.json','["水清沙凈見遊魚，槐柳陰陰五月初。", "人似登仙惟火食，俗如太古欠巢居。", "熟聞高卧常扃戶，剩欲頻來共荷鉏。", "從此夢遊端有地，淵明不獨愛吾廬。"]'),
('f463fa25-fbb4-4323-a2d8-f3b681b21d5e','彷徉','陸游','宋','宋诗','song-poetry','','[]','家世由來出楚狂，湖山垂老得彷徉。',64,'全唐诗/poet.song.133000.json','["家世由來出楚狂，湖山垂老得彷徉。", "讀書坐懶常中廢，得句因衰己旋忘。", "萬化隨緣寓蟲臂，百年何處異羊腸。", "忍饑到死知無恨，免使人嘲作飯囊。"]'),
('0ba1446c-e45b-4cbf-8222-55610e162b74','碌碌','陸游','宋','宋诗','song-poetry','','[]','碌碌初何取，悠悠信所之。',48,'全唐诗/poet.song.133000.json','["碌碌初何取，悠悠信所之。", "安貧無鬼笑，守道有天知。", "暑服黄縑製，晨餐赤米炊。", "今朝潦水退，村路得遨嬉。"]'),
('d4a26769-f405-4c04-91c7-15465bbbabed','讀陳蕃傳','陸游','宋','宋诗','song-poetry','','[]','莫笑書生一卷書，唐虞事業正關渠。',32,'全唐诗/poet.song.133000.json','["莫笑書生一卷書，唐虞事業正關渠。", "漢廷若有真王佐，天下何須費掃除。"]'),
('64615dba-78e6-48e4-8ea0-6c69d0f3d2bb','夏日晨起','陸游','宋','宋诗','song-poetry','','[]','華胥歸路萬山青，拈得烏藤繞舍行。',64,'全唐诗/poet.song.133000.json','["華胥歸路萬山青，拈得烏藤繞舍行。", "兩眥尚餘殘睡美，一襟初受曉凉生。", "陰陰院落新桐影，寂寂房櫳乳燕聲。", "已罷小餐停卯酒，龜腸蟬腹不勝清。"]'),
('38e6b05c-40f6-4d42-a5bc-83a0d0838158','醉舞','陸游','宋','宋诗','song-poetry','','[]','短帽簪花舞道傍，年垂八十尚清狂。',64,'全唐诗/poet.song.133000.json','["短帽簪花舞道傍，年垂八十尚清狂。", "茸茸胎髮朝盈櫛，炯炯神光夕照梁。", "令尹閱人三仕已，太山在我一毫芒。", "藥苗麥飯初何欠，全取愚儒百鍊剛。"]'),
('89032d74-62ab-4ede-8f28-7341471aebd4','北窗微陰','陸游','宋','宋诗','song-poetry','','[]','露滴林梢花送香，風吹池面雨輸凉。',64,'全唐诗/poet.song.133000.json','["露滴林梢花送香，風吹池面雨輸凉。", "蠹書一卷作老伴，麥飯半盂支日長。", "學道莫如心自肯，杜門真與世相忘。", "君恩不報雖知愧，稊米安能益太倉。"]'),
('cb90001a-d48c-4c19-82dc-80e3efc60c07','夏夜','陸游','宋','宋诗','song-poetry','','[]','乞骸安晚節，養疾卧空村。',48,'全唐诗/poet.song.133000.json','["乞骸安晚節，養疾卧空村。", "月暗梟鳴樹，船歸犬吠門。", "藜羹加糝美，黍酒带醅渾。", "稚子能勤學，燈前與細論。"]'),
('a432b8bd-73c8-4caf-9aa3-52a275f50074','村居','陸游','宋','宋诗','song-poetry','','[]','鵯鵊穿林語，𪀉鵝並水鳴。',48,'全唐诗/poet.song.133000.json','["鵯鵊穿林語，𪀉鵝並水鳴。", "饋漿憐道暍，裹飯助鄰耕。", "零落橋危斷，欹斜屋半傾。", "君毋笑偷惰，猶足盡吾生。"]'),
('082ede83-2c80-45ff-899c-0573297d05c9','晚興','陸游','宋','宋诗','song-poetry','','[]','羸病時時劇，歡悰日日疏。',48,'全唐诗/poet.song.133000.json','["羸病時時劇，歡悰日日疏。", "睡憑書紹介，愁賴酒驅除。", "小蹇追凉處，輕衫出浴初。", "無人堪晤語，且復狎樵漁。"]'),
('ba1c179d-b492-4bc9-bb10-8ff8bb8c21ae','溪上','陸游','宋','宋诗','song-poetry','','[]','散髮倚胡床，風生水面凉。',48,'全唐诗/poet.song.133000.json','["散髮倚胡床，風生水面凉。", "單衣縫白紵，雙屨織青芒。", "荷葉猶微赤，藤花已半黄。", "歸來村路晚，漁火耿蒼茫。"]'),
('96839e1d-5e4f-41c0-ae7f-e5c045e0be43','貧甚戲作長句示鄰曲','陸游','宋','宋诗','song-poetry','','[]','百屋堆錢四壁空，人生志願孰能同。',64,'全唐诗/poet.song.133000.json','["百屋堆錢四壁空，人生志願孰能同。", "蕭條齒髮難藏老，冷落杯盤可諱窮。", "斸筍不思鄣夏日，典衣那計禦霜風。", "知心幸有鄰翁在，一笑相從草莽中。"]'),
('73e5736f-7019-4664-88b4-8fb15246801c','縱筆','陸游','宋','宋诗','song-poetry','','[]','冉冉殘年迫耄期，肱雖三折未成醫。',64,'全唐诗/poet.song.133000.json','["冉冉殘年迫耄期，肱雖三折未成醫。", "北山愚公世方笑，東郭順子吾所師。", "萬里元非破賊手，一生無奈造物兒。", "梅雨初晴湖水滿，未妨把酒細哦詩。"]'),
('967eb4f3-a400-421d-8fee-5cff4ca80930','入都','陸游','宋','宋诗','song-poetry','','[]','葵莧登盤酒可賒，豈知扶病又離家。',64,'全唐诗/poet.song.133000.json','["葵莧登盤酒可賒，豈知扶病又離家。", "朝行打岸濤頭惡，夜宿垂天斗柄斜。", "不恨山林淹歲月，但悲道路困風沙。", "鄰翁好爲看耕隴，行矣東歸一笑譁。"]'),
('80b86f29-340b-4ca5-b922-5b3a46af9bd7','開局','陸游','宋','宋诗','song-poetry','','[]','八十年光敢自期，鏡中久已髮成絲。',64,'全唐诗/poet.song.133000.json','["八十年光敢自期，鏡中久已髮成絲。", "誰令歸蹋京塵路，又見新開史局時。", "舊吏僅存多不識，殘編重對只成悲。", "免朝愈覺君恩厚，閑看中庭木影移。"]'),
('6522cdc4-6cb8-4f7c-9f66-9eb307aa85b4','感舊','陸游','宋','宋诗','song-poetry','','[]','四十三年夢，今朝又喚回。',48,'全唐诗/poet.song.133000.json','["四十三年夢，今朝又喚回。", "平橋穿小市，細雨壓輕埃。", "老喜詩情在，慵愁史課催。", "時時還自笑，白首接鄒枚。"]'),
('49f22575-f684-4736-9e2d-21d2e0d6e4ab','贈陸伯政','陸游','宋','宋诗','song-poetry','','[]','夜窗燈火老徒勤，自憫何時可策勳。',64,'全唐诗/poet.song.133000.json','["夜窗燈火老徒勤，自憫何時可策勳。", "未喪斯文天壽我，豈無餘子我思君。", "約通殘譜言猶在，細讀新詩筆欲焚。", "早晚皇恩許歸去，相呼同卧石帆雲。"]'),
('90f74714-3748-419b-963a-5a7b7c0c5bf7','雨夜','陸游','宋','宋诗','song-poetry','','[]','暮雨濯殘熱，史官非坐曹。',48,'全唐诗/poet.song.133000.json','["暮雨濯殘熱，史官非坐曹。", "忍慚靡粟帛，偷暇近詩騷。", "屋老孤燈闇，風顛萬木號。", "明朝有奇事，江閣看秋濤。"]'),
('a22f5ccb-516f-4ad7-b43e-dbd40da8f051','自局中歸馬上口占','陸游','宋','宋诗','song-poetry','','[]','幼輿只合著山巖，誤被恩光不蓋慚。',64,'全唐诗/poet.song.133000.json','["幼輿只合著山巖，誤被恩光不蓋慚。", "人怪衰翁煩尺一，心知造物賦朝三。", "飛騰豈少摩雲鶻，蹙縮方同作繭蠶。", "安得公朝閔枯朽，早教歸卧舊茆庵。"]'),
('89efebc7-4fb9-4b6e-a4ec-8e21305f278f','秋雨','陸游','宋','宋诗','song-poetry','','[]','久占烟波弄釣舟，業風吹作鳳城遊。',64,'全唐诗/poet.song.133000.json','["久占烟波弄釣舟，業風吹作鳳城遊。", "不知苑外芙蕖老，但見牆陰苜蓿秋。", "黄把裹書俄復至，朱顔辭鏡不容留。", "晚窗又聽蕭蕭雨，一點昏燈相對愁。"]'),
('40e25fc7-ecdf-4f38-8cde-1bd38dff6672','秋夜','陸游','宋','宋诗','song-poetry','','[]','庭院蕭條夜氣清，卧聽宮漏下宮城。',32,'全唐诗/poet.song.133000.json','["庭院蕭條夜氣清，卧聽宮漏下宮城。", "旅懷生怕還鄉夢，留取殘燈伴雨聲。"]'),
('f5d46ebc-1647-4568-8314-0592de5ea147','求月桂','陸游','宋','宋诗','song-poetry','','[]','重重汗簡擁衰翁，百里家山夢不通。',32,'全唐诗/poet.song.133000.json','["重重汗簡擁衰翁，百里家山夢不通。", "病眼可令常寂寞，煩君爲致數枝紅。"]'),
('64776dd4-aefc-4a5d-918a-21bcc5c1868b','秋思二首  其一','陸游','宋','宋诗','song-poetry','','[]','烏帽翩翩九陌塵，杖藜誰記岸綸巾。',64,'全唐诗/poet.song.133000.json','["烏帽翩翩九陌塵，杖藜誰記岸綸巾。", "遺簪見取終安用，弊帚雖微亦自珍。", "廊廟似聞憐老病，雲山漸欲屬閑身。", "牆隅苜蓿秋風晚，獨倚門扉感慨頻。"]'),
('5e788dd3-2eec-46a7-9e2f-7632aa97673a','秋思二首  其二','陸游','宋','宋诗','song-poetry','','[]','霜露初侵季子裘，山川空賦仲宣樓。',64,'全唐诗/poet.song.133000.json','["霜露初侵季子裘，山川空賦仲宣樓。", "夢回最怯聞衣杵，病起常憂負酒籌。", "日月往來雙轉轂，乾坤成壞一浮漚。", "書生事業無多許，二寸毛錐老未休。"]'),
('61c860a3-98a7-4922-865c-d2ef341ee909','史院書懷','陸游','宋','宋诗','song-poetry','','[]','後死與斯文，猶能讀典墳。',48,'全唐诗/poet.song.133000.json','["後死與斯文，猶能讀典墳。", "雖慚千載事，要是一生勤。", "石磑霏霏雪，銅爐裊裊雲。", "扶衰又秋晚，何以報吾君。"]'),
('0f339c2b-df45-4615-8c80-12b4edc1af48','楚辭所謂桂數見於唐人詩句及圖畫間今不復見矣作二絕句屬山僧野人試求之  其一','陸游','宋','宋诗','song-poetry','','[]','小山桂枝今所無，一生到處問樵夫。',32,'全唐诗/poet.song.133000.json','["小山桂枝今所無，一生到處問樵夫。", "細思不獨人間少，月裏何曾有兩株。"]'),
('991fe416-63bc-4be6-b259-6c21aa8aadae','楚辭所謂桂數見於唐人詩句及圖畫間今不復見矣作二絕句屬山僧野人試求之  其二','陸游','宋','宋诗','song-poetry','','[]','丹葩綠葉鬰團團，消得姮娥種廣寒。',32,'全唐诗/poet.song.133000.json','["丹葩綠葉鬰團團，消得姮娥種廣寒。", "行盡天涯年八十，至今未遇一枝看。"]'),
('a39acec6-96e9-4313-afce-c778e1d0cc69','雨夜','陸游','宋','宋诗','song-poetry','','[]','細雨催扃戶，昏燈照擁衾。',48,'全唐诗/poet.song.133000.json','["細雨催扃戶，昏燈照擁衾。", "倦知秋漏永，瘦怯曉寒深。", "林鵲依簷宿，莎蟲入戶吟。", "此時搔短髮，誰會欲歸心。"]'),
('f2818753-7c8e-44e3-82b1-192ce1e507be','九月初作四首  其一','陸游','宋','宋诗','song-poetry','','[]','菊佩糕盤節物催，老懷撫事一悠哉。',64,'全唐诗/poet.song.133000.json','["菊佩糕盤節物催，老懷撫事一悠哉。", "年光半付殘編去，詩句時從倦枕來。", "零落朋儔今孰在，寂寥事業世方咍。", "兩叢月桂門前買，自下中庭破綠苔。"]'),
('0e13c37e-a6e2-4c34-a8b2-7731ea1a578a','九月初作四首  其二','陸游','宋','宋诗','song-poetry','','[]','九月都門凜欲霜，羸軀恩免立鵷行。',64,'全唐诗/poet.song.133000.json','["九月都門凜欲霜，羸軀恩免立鵷行。", "細書付吏謄初稿，和藥呼兒對古方。", "陋巷閉門常謝客，高齋掃地獨焚香。", "此生自計終何取，似有山林一日長。"]'),
('927bf5ec-84fb-4c5d-9017-974a7ac4e944','九月初作四首  其三','陸游','宋','宋诗','song-poetry','','[]','碧海仙蓬感舊遊，暮年心事轉悠悠。',64,'全唐诗/poet.song.133000.json','["碧海仙蓬感舊遊，暮年心事轉悠悠。", "登高此去無多日，扶病重來又過秋。", "十里樓臺迷巷陌，萬家砧杵戒衣裘。", "平生剩欠觀書債，四庫留人未許休。"]'),
('cbd1017c-be84-4cdc-8c67-e806a717dd95','九月初作四首  其四','陸游','宋','宋诗','song-poetry','','[]','富貴功名未足云，平生一飯不忘君。',64,'全唐诗/poet.song.133000.json','["富貴功名未足云，平生一飯不忘君。", "哦詩高韵凄金石，把釣幽情渺水雲。", "落葉打窗秋已暮，歸鴉泊樹日將曛。", "欲知老病常多感，革带今年減幾分。"]'),
('58b1747c-5cd5-45ac-a7a9-c59346992ee5','暮秋','陸游','宋','宋诗','song-poetry','','[]','十日都門雨，風烟已暮秋。',48,'全唐诗/poet.song.133000.json','["十日都門雨，風烟已暮秋。", "甑香新菽粟，篝暖故衣裘。", "意氣臨書健，形骸顧影愁。", "何時剡中路，秣蹇憩山郵。"]'),
('63b20d83-396b-4fea-af6d-e21d8bcbab62','重九不出遣懷','陸游','宋','宋诗','song-poetry','','[]','人生各自適飛潜，魚腹熊蹯豈得兼。',64,'全唐诗/poet.song.133000.json','["人生各自適飛潜，魚腹熊蹯豈得兼。", "並舍晚風傳藥杵，小窗殘日射書籤。", "昏瞳但怪花爭墜，衰鬢應無白可添。", "采菊泛觴終覺懶，不妨閑卧下疏簾。"]'),
('af8ea00c-28ab-46b5-a09e-af52edb3e4e6','暇日','陸游','宋','宋诗','song-poetry','','[]','身健官閑荷主恩，蕭然不異在家園。',64,'全唐诗/poet.song.133000.json','["身健官閑荷主恩，蕭然不異在家園。", "一池新墨生吟思，半篆殘香入夢魂。", "舊友無書知獨冷，小兒有命會孤鶱。", "藜羹粗足餘何事，鐘動三茅又斂昏。"]'),
('837a5c63-ab88-43ec-85b4-9000b55c1128','憶三山','陸游','宋','宋诗','song-poetry','','[]','柳橋南北弄烟霏，門不常關客自稀。',64,'全唐诗/poet.song.133000.json','["柳橋南北弄烟霏，門不常關客自稀。", "遣僕遠馱黄檗出，呼兒閑取白鷗歸。", "片雲忽起迷丹竈，潦水初生沒釣磯。", "一出可憐時屢變，又看刀尺製秋衣。"]'),
('448c6db5-4414-452a-b18c-fec5fc94610a','示子聿','陸游','宋','宋诗','song-poetry','','[]','故山誰伴隱茅茨，幸有吾家大耳兒。',64,'全唐诗/poet.song.133000.json','["故山誰伴隱茅茨，幸有吾家大耳兒。", "雨暗小窗分夜課，雪迷長鑱共朝饑。", "名場未捷寧妨學，史限雖嚴不廢詩。", "我死汝應傳鉢袋，勉持愚直報明時。"]'),
('7c4287f8-f252-413e-a953-47552c29ece3','車中作','陸游','宋','宋诗','song-poetry','','[]','秋天近霜霰，吳地少風塵。',48,'全唐诗/poet.song.133000.json','["秋天近霜霰，吳地少風塵。", "時駕小車出，始知閑客真。", "新交孰傾蓋，往事漫霑巾。", "處處皆堪隱，桃源莫問津。"]'),
('dc693420-dd1e-4225-a350-7e6fa60fad5b','初寒偶出','陸游','宋','宋诗','song-poetry','','[]','霜氣凋關樹，晴光入市樓。',48,'全唐诗/poet.song.133000.json','["霜氣凋關樹，晴光入市樓。", "閑人無造請，佳日亦遨遊。", "湖白方新出，淮𧍧亦易求。", "秋來幸無病，作意試新篘。"]'),
('733ba158-9be9-4f78-b12a-212a68a13155','史院晚出','陸游','宋','宋诗','song-poetry','','[]','已乞殘骸老故丘，誤恩重作道山遊。',64,'全唐诗/poet.song.133000.json','["已乞殘骸老故丘，誤恩重作道山遊。", "龍津雨過橋如拭，鳳闕烟消瓦欲流。", "直舍小眠鐘報午，歸途微冷葉飛秋。", "心知伏櫪無千里，縱有王良也合休。"]'),
('a8570a33-7495-4f06-bcd5-9d3aeac73655','贈洞微山人','陸游','宋','宋诗','song-poetry','','[]','我年六十四，獲譴輸鬼薪。',168,'全唐诗/poet.song.133000.json','["我年六十四，獲譴輸鬼薪。", "束書出東門，揮手謝國人。", "笑指身上衣，不復染京塵。", "時有一老翁，祝我當自珍。", "却後十五年，迎君浙江濱。", "我笑語是翁，豈說他生身。", "事果不可知，邂逅如隔辰。", "鶴髮無餘鬒，鶉衣仍苦貧。", "秋風旱河頭，握手一笑新。", "買酒烹雞豚，往事得具陳。", "試數同朝舊，零落增悲辛。", "與翁雖俱老，肝膽猶輪囷。", "千里亦命駕，何况託近鄰。", "秋高佳風月，相過莫厭頻。"]'),
('21e757ae-79b7-4409-84d8-cb43a2a37a39','九月十四日夜雞初鳴夢一故人相語曰我爲蓮華博士蓋鏡湖新置官也我且去矣君能暫爲之乎月得酒千壺亦不惡也既覺惘然作絕句記之','陸游','宋','宋诗','song-poetry','','[]','白首歸修汗簡書，每因囊粟戲侏儒。',32,'全唐诗/poet.song.133000.json','["白首歸修汗簡書，每因囊粟戲侏儒。", "不知月給千壺酒，得似蓮華博士無。"]'),
('8f82922b-f3ff-4384-aa92-85795eb4d215','初寒對酒','陸游','宋','宋诗','song-poetry','','[]','晨起常教置一壺，色如鵝氄滑如酥。',64,'全唐诗/poet.song.133000.json','["晨起常教置一壺，色如鵝氄滑如酥。", "侍郎取榼不須笑，司業與錢還復酤。", "霜路預愁騎款段，雪舟每憶釣菰蒲。", "寒花滿帽君無笑，醉倒偏宜稚子扶。"]'),
('ba101ca5-45d1-4874-ad33-aaee7cc63b72','午晴試筆','陸游','宋','宋诗','song-poetry','','[]','葉脫園林夜夜霜，風和巷陌日猶長。',64,'全唐诗/poet.song.133000.json','["葉脫園林夜夜霜，風和巷陌日猶長。", "軒車但怪容孤鶴，稊米安能益太倉。", "此去得非窮李廣，向來元是老馮唐。", "明窗攬筆聊揮灑，颯颯驚蛇又數行。"]'),
('2da7f2e1-2ebf-496e-b34d-7055c039d4b8','夜吟二首  其一','陸游','宋','宋诗','song-poetry','','[]','似睡不睡客欹枕，欲落未落月挂簷。',32,'全唐诗/poet.song.133000.json','["似睡不睡客欹枕，欲落未落月挂簷。", "詩到此時當得句，羈愁病思恰相兼。"]'),
('66de2e86-5f3a-4f84-91e2-3e3206c14db3','夜吟二首  其二','陸游','宋','宋诗','song-poetry','','[]','六十餘年妄學詩，工夫深處獨心知。',32,'全唐诗/poet.song.133000.json','["六十餘年妄學詩，工夫深處獨心知。", "夜來一笑寒燈下，始是金丹換骨時。"]'),
('cba74f3a-b6d8-4e11-8d8c-ba8dcb951a51','閑詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','身似地行僊，心非欲界天。',48,'全唐诗/poet.song.133000.json','["身似地行僊，心非欲界天。", "輿竿聲軋軋，巾角影翩翩。", "買菊穿苔種，懷茶就井煎。", "歸來書繞坐，隨處一欣然。"]'),
('11d8cc07-93ca-4627-8df1-abde77125690','閑詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','久入春農社，新腰老衲包。',48,'全唐诗/poet.song.133000.json','["久入春農社，新腰老衲包。", "紙裁微放矮，硯斲正須䫜。", "髯簿能爲祟，方兄任絕交。", "吾詩無傑句，聊復當談嘲。"]'),
('2540015d-c54b-4d93-8054-95ec4b55306c','遊張園','陸游','宋','宋诗','song-poetry','','[]','冷局歸差早，名園得緩行。',48,'全唐诗/poet.song.133000.json','["冷局歸差早，名園得緩行。", "穿林山驟出，度峽路微平。", "霜近柳無色，風生蒲有聲。", "出門還戃怳，滿路夕陽明。"]'),
('60af3972-4fbb-48c1-8017-81fcd748f11a','客至','陸游','宋','宋诗','song-poetry','','[]','官閑身自得，客至眼殊明。',48,'全唐诗/poet.song.133000.json','["官閑身自得，客至眼殊明。", "靜算棋生死，閑分酒濁清。", "悠然劇談罷，偶爾小詩成。", "但恨桑麻事，無人與共評。"]'),
('8ca87134-1eea-47dc-90d6-ea90646f10ab','客去','陸游','宋','宋诗','song-poetry','','[]','客來拈麈尾，客去拂床眠。',48,'全唐诗/poet.song.133000.json','["客來拈麈尾，客去拂床眠。", "孤夢歸湖上，殘書墮枕邊。", "幽禽窺戶語，落日傍窗妍。", "暫爾名朝士，終然是地僊。"]'),
('25639412-2e84-4863-bcc4-a6b67622fa8a','無客','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今日了無客，翛然麈柄閑。',48,'全唐诗/poet.song.133000.json','["今日了無客，翛然麈柄閑。", "硯涵鴝鵒眼，香斮鷓鴣斑。", "木落風初勁，雲低雨尚慳。", "西湖未暇到，卧看曲屏山。"]'),
('3a766618-11ce-45a6-9558-318149256a0a','次韵黄宮教見贈','陸游','宋','宋诗','song-poetry','','[]','士固未易料，世乃有若人。',96,'全唐诗/poet.song.133000.json','["士固未易料，世乃有若人。", "高標與曠懷，豈復容疏親。", "邂逅京塵中，握手一笑新。", "我雖讀古書，妙處愧斲輪。", "敢學狂接輿，歌鳳笑泣麟。", "空持鼻端堊，庶幾遇郢斤。", "獨立臨洪流，欲濟茫無津。", "君其幸教之，勿棄老病身。"]'),
('39d961dc-40f5-4fb9-871c-0c6ae4294a66','書直舍壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','三黜愧公議，再來仍冷官。',48,'全唐诗/poet.song.133000.json','["三黜愧公議，再來仍冷官。", "志無重奮發，身有轉衰殘。", "加飯支餘息，添衣禦早寒。", "歸休應漸近，不是强心寬。"]'),
('2c55c40c-df16-4a89-a44b-020d9483f8d8','書直舍壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','道山西下路，杳杳歷重廊。',48,'全唐诗/poet.song.133000.json','["道山西下路，杳杳歷重廊。", "地寂聞傳漏，簾疏有斷香。", "渠清水馬健，屋老瓦松長。", "欲出重欹枕，無何覓故鄉。"]'),
('3c168f2e-3e1c-4284-a929-ad37d5c9776a','韓太傅生日','陸游','宋','宋诗','song-poetry','','[]','珥貂中使傳天語，一片驚塵飛輦路。',128,'全唐诗/poet.song.133000.json','["珥貂中使傳天語，一片驚塵飛輦路。", "清霜粲瓦初作寒，天爲明時生帝傅。", "黄金飾奩雕玉觴，上尊御食傳恩光。", "紫駝之峰玄熊掌，不數沙苑千群羊。", "通天寶带連城價，受賜雍容看拜下。", "神皇外孫風骨殊，凜凜英姿不容畫。", "問今何人致太平，綿地萬里皆春耕。", "身際風雲手扶日，異姓真王功第一。"]'),
('7c4d83e0-1d60-492c-b4c7-559eae1d7fbb','懷故山','陸游','宋','宋诗','song-poetry','','[]','老怯京塵化素衣，無端拋擲釣魚磯。',64,'全唐诗/poet.song.133000.json','["老怯京塵化素衣，無端拋擲釣魚磯。", "碧雲又見日將暮，芳草不知人念歸。", "萬事莫論羈枕夢，一身方墮亂書圍。", "岷山學士無消息，空想燈前語入微。"]'),
('22eaa4a0-d667-47ff-836a-20447bca860b','西齋遣興','陸游','宋','宋诗','song-poetry','','[]','桐葉秋先霣，菊花寒更香。',48,'全唐诗/poet.song.133000.json','["桐葉秋先霣，菊花寒更香。", "酒邊聊兀兀，身外本茫茫。", "小憩元非睡，長吟偶似狂。", "忽然思把卷，一笑就窗光。"]'),
('1a05fc7a-d14d-49b8-b3a3-24c77fde812e','雨夜作','陸游','宋','宋诗','song-poetry','','[]','十月多蚊蚋，昏昏氣未平。',48,'全唐诗/poet.song.133000.json','["十月多蚊蚋，昏昏氣未平。", "正須三日雨，却用一霜晴。", "閑館蕭條意，空階點滴聲。", "鐘殘撫枕嘆，歸夢幾時成。"]'),
('2b8c8366-cbb8-4307-9729-64999e52b5ef','掩戶','陸游','宋','宋诗','song-poetry','','[]','蔗漿那解破餘酲，一讀南華眼自明。',64,'全唐诗/poet.song.133000.json','["蔗漿那解破餘酲，一讀南華眼自明。", "香縷映窗凝不散，墨丸入硯細無聲。", "太山蟻垤初何有，佛國魔宮本亦平。", "此段光明誰障得，曠懷還與老書生。"]'),
('969770d9-b2e2-4c3d-a5f8-326d122e32eb','卧疾','陸游','宋','宋诗','song-poetry','','[]','舊疾乘衰作，長貧與懶宜。',48,'全唐诗/poet.song.133000.json','["舊疾乘衰作，長貧與懶宜。", "羈愁惟付酒，史課未妨詩。", "雨入殘更滴，霜逢閏歲遲。", "新春真耄及，不用卜歸期。"]'),
('6f70e5c7-1d48-4ce2-a3e8-cb492e01df4e','晚歸','陸游','宋','宋诗','song-poetry','','[]','無事經秋別鏡湖，詩囊隨處累奚奴。',64,'全唐诗/poet.song.133000.json','["無事經秋別鏡湖，詩囊隨處累奚奴。", "樓頭寒日低將盡，陌上殘泥踏欲無。", "軒冕豈容關喜慍，簞瓢亦未費枝梧。", "畫橋綠浦歸來晚，一盞昏燈得自娛。"]'),
('88812df2-67da-4320-b4a3-c8366a1710c2','寂寂','陸游','宋','宋诗','song-poetry','','[]','接客厭紛紛，客去喜寂寂。',48,'全唐诗/poet.song.133000.json','["接客厭紛紛，客去喜寂寂。", "今朝下簾坐，疏雨時一滴。", "地爐擁破褐，自笑懶無敵。", "新春儻得歸，更面九年壁。"]'),
('19a08bd0-474d-44f5-8430-0f996b67a517','獨坐有懷杜伯高','陸游','宋','宋诗','song-poetry','','[]','畫橋通小市，深院欲黄昏。',48,'全唐诗/poet.song.133000.json','["畫橋通小市，深院欲黄昏。", "愛月先移燭，留香每閉門。", "李侯有佳句，樂令善清言。", "老病貪搘枕，何由共一樽。"]'),
('c2caaf61-43fb-4afb-866d-6a28b3c40a86','李允蹈判院送酒四斗予答書乃誤以爲二斗作小詩識愧','陸游','宋','宋诗','song-poetry','','[]','冷官誰顧雀羅門，一紙惟君肯見存。',32,'全唐诗/poet.song.133000.json','["冷官誰顧雀羅門，一紙惟君肯見存。", "堪笑放翁昏至此，乘壺誤寫作朋樽。"]'),
('89d27861-9318-4341-942b-414721408827','感舊贈超師','陸游','宋','宋诗','song-poetry','','[]','一聲清蹕出行宮，百尺黄旗繡戲龍。',32,'全唐诗/poet.song.133000.json','["一聲清蹕出行宮，百尺黄旗繡戲龍。", "我赴文場君受戒，道邊曾共望高宗。"]'),
('fe8ea3af-cd7d-41dc-8d0b-4d6163e076f2','雜書四首  其一','陸游','宋','宋诗','song-poetry','','[]','世味漸闌如嚼蠟，惟詩直恐死方休。',32,'全唐诗/poet.song.133000.json','["世味漸闌如嚼蠟，惟詩直恐死方休。", "四時風月元無盡，萬里江山更擬遊。"]'),
('4ec891a6-dfe5-44e1-b09e-32c9c10b9a1f','雜書四首  其二','陸游','宋','宋诗','song-poetry','','[]','一身頂踵無非病，兩飯齏鹽亦闕供。',32,'全唐诗/poet.song.133000.json','["一身頂踵無非病，兩飯齏鹽亦闕供。", "正可清言學夷甫，不須豪氣似元龍。"]'),
('0fcffe90-3c18-4096-8ff3-ca64a9b4d65e','雜書四首  其三','陸游','宋','宋诗','song-poetry','','[]','枳籬莎徑入荆扉，中有村翁百結衣。',32,'全唐诗/poet.song.133000.json','["枳籬莎徑入荆扉，中有村翁百結衣。", "誰識新年歡喜事，一雞一犬伴東歸。"]'),
('4b411b4b-16b4-40bb-ad80-a3ddc5c04fa6','雜書四首  其四','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','身似匡廬老病僧，閉門一衲坐騰騰。',32,'全唐诗/poet.song.133000.json','["身似匡廬老病僧，閉門一衲坐騰騰。", "雨聲驚斷長安夢，惆悵西窗夜半燈。"]'),
('19d51cfd-b601-4f30-b9ac-dbeb436932c7','送子虡赴金壇丞','陸游','宋','宋诗','song-poetry','','[]','與汝爲父子，忽逾五十年。',144,'全唐诗/poet.song.133000.json','["與汝爲父子，忽逾五十年。", "平生知幾別，此別益酸然。", "念汝髮亦白，執手河橋邊。", "西行過臨平，想汝小繫船。", "悠悠陽羨路，渺渺雲陽川。", "京江昔所遊，想像在目前。", "今茲兩使君，幸有宿昔緣。", "汝雖登門晚，世好亦牽聯。", "顧於賞罰間，其肯爲汝偏。", "夙夜佐而長，努力忘食眠。", "醇如新豐酒，清若鶴林泉。", "棠宜使可愛，蒲正不須鞭。"]'),
('cd5ca529-f12b-4f7a-9183-a9c17d2cb350','今日史課偶少暇戲作五字','陸游','宋','宋诗','song-poetry','','[]','仲夏入都門，堂瓦忽已霜。',96,'全唐诗/poet.song.133000.json','["仲夏入都門，堂瓦忽已霜。", "史館方掄才，我亦廁其傍。", "三日敗一筆，手胝視芒芒。", "吏來督日程，炙冷不及嘗。", "今辰偶少靜，掃地欲焚香。", "市聲塞我門，騶呼過我牆。", "鄙性不耐喧，戃怳意欲狂。", "天生兩窮耳，只堪聽啼螿。"]'),
('053700e7-8bc0-46c1-b339-ee37e22c38c9','入局','陸游','宋','宋诗','song-poetry','','[]','殘年困簡牘，靜坐憶漁樵。',48,'全唐诗/poet.song.133000.json','["殘年困簡牘，靜坐憶漁樵。", "鄙意慚輕出，殊恩免早朝。", "微霜凋綠樹，寒日滿朱橋。", "悵望滄波友，弓旌豈易招。"]'),
('575c2c43-e45d-411f-acf1-f0d4206d106d','縱筆四首  其一','陸游','宋','宋诗','song-poetry','','[]','胸中略無一點事，眼底常展數行書。',32,'全唐诗/poet.song.133000.json','["胸中略無一點事，眼底常展數行書。", "半饑半飽便可爾，衣食何須求有餘。"]'),
('40908393-a04c-481d-890c-abea0b4da72f','縱筆四首  其二','陸游','宋','宋诗','song-poetry','','[]','小兒讀書耕且養，老夫入朝仕易農。',32,'全唐诗/poet.song.133000.json','["小兒讀書耕且養，老夫入朝仕易農。", "明春史成許歸去，父子相逐歌年豐。"]'),
('4fd0161b-8fd8-4016-8fac-4cae679b64d7','縱筆四首  其三','陸游','宋','宋诗','song-poetry','','[]','晝倦夜常成美睡，病多老却未全衰。',32,'全唐诗/poet.song.133000.json','["晝倦夜常成美睡，病多老却未全衰。", "歸從冊府猶披卷，了却官書更賦詩。"]'),
('370fc727-a083-4288-85f9-1c712e16be6d','縱筆四首  其四','陸游','宋','宋诗','song-poetry','','[]','坊遠不聞宮漏聲，三茅鐘殘窗欲明。',32,'全唐诗/poet.song.133000.json','["坊遠不聞宮漏聲，三茅鐘殘窗欲明。", "山童睡熟呼不應，添水拂書翁自行。"]'),
('a38aa794-6d6c-470f-8c9c-e574fd321e0e','送襄陽鄭帥唐老','陸游','宋','宋诗','song-poetry','','[]','鄭侯骨相非復常，伏犀貫額面正方。',192,'全唐诗/poet.song.133000.json','["鄭侯骨相非復常，伏犀貫額面正方。", "聲名赫奕動天子，家世富貴連椒房。", "武能防秋北平道，文合落筆中書堂。", "畿西謀帥國大事，當宁久弄黄金章。", "一朝丹詔自天下，兩班仰首看騰驤。", "鄭侯此行端可羨，繡旗皂纛戈如霜。", "三更傳令出玉帳，平旦按陣來毬場。", "宿兵萬竈盡貔虎，牧馬千群皆驌驦。", "酒酣賦詩幕府和，縱橫健筆誰能當。", "雖然鄭侯志意遠，虎視直欲吞北荒。", "榆林雁門塞垣紫，孟津砥柱河流黄。", "出師有路吾能說，直自襄陽向洛陽。"]'),
('0f1dbb39-7c77-4d8d-b913-4fe0e7644e72','掩門四首  其一','陸游','宋','宋诗','song-poetry','','[]','身瘦不勝笏，官閑常掩門。',48,'全唐诗/poet.song.133000.json','["身瘦不勝笏，官閑常掩門。", "漢廷雖好老，楚澤未招魂。", "硯潤蟾疏滴，香殘鴨尚溫。", "箇中殊會意，恨欠阿戎言。"]'),
('1988736a-37c8-4b50-8920-116194467cd5','掩門四首  其二','陸游','宋','宋诗','song-poetry','','[]','簌簌落高槐，陰陰長綠苔。',48,'全唐诗/poet.song.133000.json','["簌簌落高槐，陰陰長綠苔。", "只言門晝掩，不道客誰來。", "足痹思尋壑，愁生欠撥醅。", "吾兒能問事，梨栗且炮煨。"]'),
('0bcefaaa-26da-409c-bc22-c3402300c844','掩門四首  其三','陸游','宋','宋诗','song-poetry','','[]','舉手可及屋，積書高拄頤。',48,'全唐诗/poet.song.133000.json','["舉手可及屋，積書高拄頤。", "忽聞疏雨滴，怳記故山時。", "點染聊成字，呻吟僅似詩。", "不關才思盡，碌碌本亡奇。"]'),
('6bc78941-54a4-49f2-8794-80db677477fa','掩門四首  其四','陸游','宋','宋诗','song-poetry','','[]','寡求忘市遠，易足任囊空。',48,'全唐诗/poet.song.133000.json','["寡求忘市遠，易足任囊空。", "院吏催呈史，家僮笑忍窮。", "鬢毛驚盡白，倉粟飫陳紅。", "賴有三峨夢，時時到枕中。"]'),
('9b68bd35-b899-4b81-9469-aa610448957c','自嘲','陸游','宋','宋诗','song-poetry','','[]','野老家風子未知，天教甫里出孫枝。',64,'全唐诗/poet.song.133000.json','["野老家風子未知，天教甫里出孫枝。", "遍遊竹院尋僧語，時拂楸枰約客棋。", "是處登臨有風月，平生敭歷半宮祠。", "即今箇事渾如昨，喚作朝官却自疑。"]'),
('6ad2178a-aa81-44aa-9e63-4968cada8bce','乍晴出遊','陸游','宋','宋诗','song-poetry','','[]','八十山翁病不支，出門也賦喜晴詩。',64,'全唐诗/poet.song.133000.json','["八十山翁病不支，出門也賦喜晴詩。", "小樓酒旆闌街處，深巷人家曬練時。", "本借微風欹帽影，却乘新暖弄鞭絲。", "歸來幸有流香在，剩伴兒童一笑嬉。"]'),
('7f868729-ef74-4b96-8332-cf3b1d8d9512','送客至湖州市','陸游','宋','宋诗','song-poetry','','[]','偶駕雞栖送客行，迢迢十里出關城。',64,'全唐诗/poet.song.133000.json','["偶駕雞栖送客行，迢迢十里出關城。", "誰知小市蕭條處，剩有豐年笑語聲。", "聊借野風吹醉頰，更憑陂水濯塵纓。", "故廬想見春回近，鄰曲家家已遍耕。"]'),
('57e1e99b-337c-45a0-bb61-bbe0dab0ee5d','題史院壁四首  其一','陸游','宋','宋诗','song-poetry','','[]','命薄謀常拙，年衰力轉微。',48,'全唐诗/poet.song.133000.json','["命薄謀常拙，年衰力轉微。", "鷁飛元合退，羝乳偶成歸。", "汗簡慚靡日，流塵怯染衣。", "無端霜夜月，應照舊苔磯。"]'),
('1214e08a-6964-4332-b4fb-00ee3bf55132','題史院壁四首  其二','陸游','宋','宋诗','song-poetry','','[]','槁木忘榮謝，閑雲任卷舒。',48,'全唐诗/poet.song.133000.json','["槁木忘榮謝，閑雲任卷舒。", "慵爲繞枝鵲，寧作蠹書魚。", "羈旅心常折，親朋夢亦疏。", "溪頭釣船在，恐負此心初。"]'),
('1fe0539c-2a02-4c69-b7a9-ebb6bc9c5d69','題史院壁四首  其三','陸游','宋','宋诗','song-poetry','','[]','白髮無餘鬒，蒼顔失故丹。',48,'全唐诗/poet.song.133000.json','["白髮無餘鬒，蒼顔失故丹。", "旅遊多敗意，大屋每饒寒。", "出畏霜侵褐，歸乘日暖鞍。", "若非時得句，何以慰衰殘。"]'),
('18f8d878-3f98-49e2-99af-2467e1075d73','題史院壁四首  其四','陸游','宋','宋诗','song-poetry','','[]','苔遊平分路，銅環半掩扉。',48,'全唐诗/poet.song.133000.json','["苔遊平分路，銅環半掩扉。", "殘蕪寒不死，敗葉落還飛。", "責重何由塞，愁生但念歸。", "非無茅一把，世事苦相違。"]'),
('4fb89e84-866b-45b0-a6c6-5fca31ed39e2','寄二子','陸游','宋','宋诗','song-poetry','','[]','大兒新作鶴林遊，仲子經年戍吉州。',64,'全唐诗/poet.song.133000.json','["大兒新作鶴林遊，仲子經年戍吉州。", "日日望書常至暮，時時入夢却添愁。", "得官本自輕齊虜，對景寧當似楚囚。", "識取乃翁行履處，一生任運笑人謀。"]'),
('151f5e18-efbc-46a8-a072-6fcaf5170a78','訪客至北門抵暮乃歸','陸游','宋','宋诗','song-poetry','','[]','北郭那辭十里遥，上車且用慰無聊。',64,'全唐诗/poet.song.133000.json','["北郭那辭十里遥，上車且用慰無聊。", "九衢浩浩市聲合，四野酣酣雪意驕。", "清鏡新磨臨綠浦，長虹橫絕度朱橋。", "歸來熟睡明方起，卧聽鄰牆趁早朝。"]'),
('f04db753-4da9-48a9-bd29-80bf68980644','恩除秘書監','陸游','宋','宋诗','song-poetry','','[]','群僊鶴駕去難追，白首重來不自知。',64,'全唐诗/poet.song.133000.json','["群僊鶴駕去難追，白首重來不自知。", "才藝荒唐癡獨絕，功名蹭蹬老如期。", "海邊鄭叟窮耽酒，吳下韋郎晚學詩。", "扶上木天君莫笑，衰殘不似壯遊時。"]'),
('d3f73419-212c-433f-b8cb-cfe8fb801f92','寄題儒榮堂','陸游','宋','宋诗','song-poetry','','[]','軍容基禍廟謀疏，尚記文登遣使初。',64,'全唐诗/poet.song.133000.json','["軍容基禍廟謀疏，尚記文登遣使初。", "只道大功隨指顧，至今遺種費誅鋤。", "還朝不遣參麟筆，寓直空聞上石渠。", "剩辦殺青君記取，龍庭焚盡始成書。"]'),
('6d0815f7-1b6c-4284-824d-05bb2330a988','夙興','陸游','宋','宋诗','song-poetry','','[]','鐘已樓頭動，燈猶帳外殘。',48,'全唐诗/poet.song.133000.json','["鐘已樓頭動，燈猶帳外殘。", "霜濃愁枕冷，病起覺衣寬。", "鶴怨憑誰解，鷗盟恐已寒。", "君恩等天地，應許納微官。"]'),
('037e28cf-d0e0-4367-85f1-5a487c84db88','館中書懷','陸游','宋','宋诗','song-poetry','','[]','流落逢明主，恩光集晚途。',48,'全唐诗/poet.song.133000.json','["流落逢明主，恩光集晚途。", "題名驚手戰，拜閣藉人扶。", "枉辱三華組，終歸一腐儒。", "庫書時取讀，猶足補東隅。"]'),
('57c954d3-c6cb-4dc6-80f1-1765f1bdbd16','雜興十首以貧堅志士節病長高人情爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','仕宦遍四方，每出歸愈貧。',72,'全唐诗/poet.song.133000.json','["仕宦遍四方，每出歸愈貧。", "寒暑更質衣，笑倒鄰里人。", "今年作史官，坐糜太倉陳。", "無如思歸何，日夜望絕麟。", "區區牛馬走，齪齪蟣蝨臣。", "恩深老不報，肝膽空輪囷。"]'),
('92e7e48a-8b88-49ff-89f0-947f893f2fe6','雜興十首以貧堅志士節病長高人情爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','孟子闢楊墨，吾道方粲然。',72,'全唐诗/poet.song.133000.json','["孟子闢楊墨，吾道方粲然。", "韓愈排佛老，不失聖所傳。", "伐木當伐根，攻敵當攻堅。", "坐視日月食，孰探天地全。", "一木信難恃，要憂大厦顛。", "安得孟韓輩，出爲吾黨先。"]'),
('20d24abc-afee-46fe-b065-4c08d3c5ea23','雜興十首以貧堅志士節病長高人情爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','聖人固多能，藝乃以不試。',72,'全唐诗/poet.song.133000.json','["聖人固多能，藝乃以不試。", "嗟予少貧賤，日月成坐棄。", "矧今耄已及，甘食而美睡。", "道衰朋友散，斯文凜將墜。", "閉戶輒竟日，孰與講仁智。", "厭厭生意盡，何暇議李志。"]'),
('0f0cb9d9-1144-4c4d-b830-66f54489e682','雜興十首以貧堅志士節病長高人情爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','少年喜結交，患難謂可倚。',72,'全唐诗/poet.song.133000.json','["少年喜結交，患難謂可倚。", "寧知事大謬，親友化虎兕。", "出仕五十年，危不以讒死。", "始畏囊中錐，寧取道傍李。", "老來多新知，英彥終可喜。", "豈以二三君，遂疑天下士。"]'),
('566fccce-dc09-45a1-91ed-c40ab72a0db6','雜興十首以貧堅志士節病長高人情爲韵  其五','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔我遊廬山，夜遇東林雪。',72,'全唐诗/poet.song.133000.json','["昔我遊廬山，夜遇東林雪。", "灰深火正熟，膏減燈半滅。", "童驚林虎過，僧惜澗松折。", "至今每追想，可解肺肝熱。", "那知蓬山夢，忽繼此清絕。", "殊勝蘇子卿，餐氈持漢節。"]'),
('33aa157c-12b0-4781-a1ca-cfd275fe70ce','雜興十首以貧堅志士節病長高人情爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','觀人如觀玉，拙眼喜譏評。',72,'全唐诗/poet.song.133000.json','["觀人如觀玉，拙眼喜譏評。", "得失顧在人，玉固非所病。", "慶曆嘉祐間，人才於斯盛。", "王回僅一招，石介棄不聘。", "乃知天下士，成敗各有命。", "願君姑安之，天定豈不勝。"]'),
('f630d6c5-03b7-4eca-b0c4-579d5f81a2c5','雜興十首以貧堅志士節病長高人情爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','兩山如峨眉，一水若車輞。',72,'全唐诗/poet.song.133000.json','["兩山如峨眉，一水若車輞。", "吾昔廬其間，百里臨莽蒼。", "少年手藝木，條幹日夜長。", "咿啞駕獨轅，迢遞摇兩槳。", "平生會心地，今乃寄夢想。", "何時喚鄰翁，烟水行布網。"]'),
('c954a165-b45d-4bdb-8739-f7feb3565ec2','雜興十首以貧堅志士節病長高人情爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','貨財不可居，祿位不可饕。',72,'全唐诗/poet.song.133000.json','["貨財不可居，祿位不可饕。", "我爾本一家，何至皋蘭鏖。", "小夫謀人國，紛紛日煎熬。", "或謂性本惡，或謂經無褒。", "誤人方自此，孰如飲醇醪。", "清言亦自佳，遺事非徒高。"]'),
('a2fa4b62-be6a-46c3-9a7f-a1c2a8aa928e','雜興十首以貧堅志士節病長高人情爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','魯山粹而博，韶美曠且真。',72,'全唐诗/poet.song.133000.json','["魯山粹而博，韶美曠且真。", "石渠東觀中，久矣無若人。", "飛僊驂鳳鸞，豈久混世塵。", "空餘文章在，常與日月新。", "我雖不足數，疇昔忝交親。", "尚想秋燈下，對影欹幅巾。"]'),
('49dad997-a3a8-4c42-a9f3-87de9780b3e0','雜興十首以貧堅志士節病長高人情爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','君子尚大節，又甚惡不情。',72,'全唐诗/poet.song.133000.json','["君子尚大節，又甚惡不情。", "魯連故可人，用意終近名。", "千載高夷齊，采薇忘其生。", "周公述易象，所以貴幽貞。", "去聖雖已遠，江左見淵明。", "我讀飲酒詩，朱弦有遺聲。"]'),
('ca6026bd-a1cd-43dc-802b-02a74996277b','送任夷仲大監','陸游','宋','宋诗','song-poetry','','[]','往者江淮未徹兵，丹陽邂逅識耆英。',64,'全唐诗/poet.song.133000.json','["往者江淮未徹兵，丹陽邂逅識耆英。", "叩門偶綴諸公後，倒屣曾蒙一笑迎。", "敢意癡頑成後死，相從彷彿若平生。", "小詩話別初何有，一段清愁伴櫓聲。"]'),
('21f6332c-3383-4462-9314-72934a7b63fb','謝韓實之直閣送燈二首  其一','陸游','宋','宋诗','song-poetry','','[]','玉作華星綴絳繩，樓臺交映暮天澄。',32,'全唐诗/poet.song.133000.json','["玉作華星綴絳繩，樓臺交映暮天澄。", "東都父老今誰在，腸斷當時諫浙燈。"]'),
('43b771c6-0fe1-4e7b-89e4-d76a4fc6fdb5','謝韓實之直閣送燈二首  其二','陸游','宋','宋诗','song-poetry','','[]','舊友年來不作疏，華燈乃肯寄蝸廬。',32,'全唐诗/poet.song.133000.json','["舊友年來不作疏，華燈乃肯寄蝸廬。", "寧知此老蕭條甚，二尺檠前正讀書。"]'),
('ed3f80ce-5e3e-40cf-a6dd-62f382096f94','道山直舍','陸游','宋','宋诗','song-poetry','','[]','身世從來一蠹魚，討論猶記入朝初。',32,'全唐诗/poet.song.133000.json','["身世從來一蠹魚，討論猶記入朝初。", "自憐報國無他技，又領蘭臺四庫書。"]'),
('9917355a-6105-43d9-bbe0-51cc5ad1cdf5','館中營繕方一新而右文殿生芝草甚異','陸游','宋','宋诗','song-poetry','','[]','丹碧參差盛一時，殿楹三秀見金芝。',32,'全唐诗/poet.song.133000.json','["丹碧參差盛一時，殿楹三秀見金芝。", "漢庭漫道多才傑，天馬何勞作頌詩。"]'),
('9d1a9586-ce6f-4f89-b4df-6d06f48cdd85','戲述淵明鴻漸遺事','陸游','宋','宋诗','song-poetry','','[]','桑苧柴桑一世豪，區區玩物亦徒勞。',32,'全唐诗/poet.song.133000.json','["桑苧柴桑一世豪，區區玩物亦徒勞。", "品茶未及毀茶妙，飲酒何如止酒高。"]'),
('0e1dc92f-7fce-46e6-a6db-8010fa318479','雪夜','陸游','宋','宋诗','song-poetry','','[]','雪屋透窗明，風簾撮夜聲。',24,'全唐诗/poet.song.133000.json','["雪屋透窗明，風簾撮夜聲。", "披衣擁爐坐，忘却在都城。"]'),
('bc526d5f-0c42-4450-b2ec-288e4bf790f1','直舍獨坐思成都','陸游','宋','宋诗','song-poetry','','[]','錦城花絮送吳船，屈指東歸又幾年。',64,'全唐诗/poet.song.133000.json','["錦城花絮送吳船，屈指東歸又幾年。", "群玉峰頭身老矣，百花潭上夢依然。", "青衫尚記稱狂客，白髮寧知作老僊。", "所恨酒腸非復昔，閑遊空負杖頭錢。"]'),
('e74ddacd-cec2-48f7-8578-359fb3b3c70f','嘆老','陸游','宋','宋诗','song-poetry','','[]','鏡裏蕭蕭白髮新，默思舊事似前身。',64,'全唐诗/poet.song.133000.json','["鏡裏蕭蕭白髮新，默思舊事似前身。", "齒殘對客豁可耻，臂弱學書肥失真。", "漸覺文辭乖律呂，豈惟議論少精神。", "平生師友凋零盡，鼻堊揮斤未有人。"]'),
('1620e57b-f9cf-4e97-a26d-72e4bb973b45','冬曉','陸游','宋','宋诗','song-poetry','','[]','恩免宵興趁曉班，養慵終覺愧吾顔。',64,'全唐诗/poet.song.133000.json','["恩免宵興趁曉班，養慵終覺愧吾顔。", "浮名半世虛催老，高卧何時復得閑。", "兩岸夕陽漁浦市，數峰寒靄沃洲山。", "扁舟來往無窮樂，此事天公豈所慳。"]'),
('f54f360d-57d6-4ae7-a9a6-a3e00b4485aa','有懷梁益舊遊','陸游','宋','宋诗','song-poetry','','[]','土堠纍纍隻復雙，悠然殘夢對寒缸。',64,'全唐诗/poet.song.133000.json','["土堠纍纍隻復雙，悠然殘夢對寒缸。", "亂山落日葭萌驛，古渡悲風桔柏江。", "虎印雪泥餘過迹，樹經野火有空腔。", "四方行役男兒事，常笑韓公賦下瀧。"]'),
('206622a0-be6b-4d8a-966c-1e00e4b0e98e','孤坐無聊每思江湖之適','陸游','宋','宋诗','song-poetry','','[]','世上元無第一籌，此身只合卧滄洲。',64,'全唐诗/poet.song.133000.json','["世上元無第一籌，此身只合卧滄洲。", "櫓摇漁浦蒼茫月，帆带松江浩蕩秋。", "有酒人家皆可醉，無僧山寺亦閑遊。", "老來閱盡榮枯事，萬變惟應一笑酬。"]'),
('3152065d-a8e9-4b20-bd92-39111bef80fa','夢韓无咎如在京口時既覺枕上作短歌','陸游','宋','宋诗','song-poetry','','[]','隆興之初客江皋，連榱結駟皆賢豪。',128,'全唐诗/poet.song.133000.json','["隆興之初客江皋，連榱結駟皆賢豪。", "坐中无咎我所畏，日夜酬唱兼詩騷。", "有時贈我玉具劍，間亦報之金錯刀。", "舊遊忽墮五更夢，舉首但覺鐵甕高。", "樽前美人亦黄土，吾輩鬼錄將安逃。", "死生一訣信已矣，所恨膏火常煎熬。", "平生不愛葱嶺話，方術亦陋葛與陶。", "但當東歸棄百事，爛醉海上觀雲濤。"]'),
('d2eee120-2e5c-4edc-9424-146113a44bfc','出東城並江而歸','陸游','宋','宋诗','song-poetry','','[]','上車容假寐，出郭當閑遊。',48,'全唐诗/poet.song.133000.json','["上車容假寐，出郭當閑遊。", "遠笛臨風起，高帆到岸收。", "人歸花市路，客醉酒家樓。", "徑就東窗卧，孤燈欲話愁。"]'),
('5692e768-47d4-4379-aa80-381194aa67ce','子聿欲暫歸山陰見乃翁作惡遂不行贈以此詩','陸游','宋','宋诗','song-poetry','','[]','鐘鳴豈復夜行時，文字相娛賴此兒。',64,'全唐诗/poet.song.133000.json','["鐘鳴豈復夜行時，文字相娛賴此兒。", "欲去復留知汝孝，未言先泣嘆吾衰。", "兩篇易象能忘老，百畝山畬可免饑。", "但報家僮多釀酒，一欄紅藥是歸期。"]'),
('36ee1975-b841-4d09-9fdf-5c4a4c30086f','題趙生畫','陸游','宋','宋诗','song-poetry','','[]','東都畫手排浮萍，天子獨賞一趙生。',128,'全唐诗/poet.song.133000.json','["東都畫手排浮萍，天子獨賞一趙生。", "幅縑尺紙皆厚賜，眾史妒媢都人驚。", "爾來一筆不復見，好事往往空聞名。", "奇哉此獨出劫火，論價直恐千金輕。", "老廉博士最別識，一見自謂雙眼明。", "老夫寓居旱河上，矮軸正向幽窗橫。", "飯餘捫腹看不厭，林外重閣高崢嶸。", "憑誰喚住兩禪客，水邊共聽烟鐘聲。"]'),
('b35405ee-47bf-4af3-b07d-d29bd0d21b96','題宣律師畫像','陸游','宋','宋诗','song-poetry','','[]','秀目大頭顱，英姿舉世無。',24,'全唐诗/poet.song.133000.json','["秀目大頭顱，英姿舉世無。", "平生一瓦鉢，何處有天厨。"]'),
('3d64bc13-ef83-40b6-82be-1374f348f87c','暇日弄筆戲書三首  其一','陸游','宋','宋诗','song-poetry','','[]','天地爲我廬，江山爲我客。',48,'全唐诗/poet.song.133000.json','["天地爲我廬，江山爲我客。", "北斗以酌酒，恨我飲量窄。", "人生但閉戶，烏用分菽麥。", "贈君玉函方，憒憒無皂白。"]'),
('503cedfc-4f81-4b29-9522-42a51ba60d6d','暇日弄筆戲書三首  其二','陸游','宋','宋诗','song-poetry','','[]','草書學張顛，行書學楊風。',48,'全唐诗/poet.song.133000.json','["草書學張顛，行書學楊風。", "平生江湖心，聊寄筆硯中。", "龍蛇入我腕，疋素忽已窮。", "餘勢尚隱轔，此興嗟誰同。"]'),
('a3d87398-7ed3-4645-a839-1ee57b24c88a','暇日弄筆戲書三首  其三','陸游','宋','宋诗','song-poetry','','[]','胸懷幾雲夢，形骸一槁木。',48,'全唐诗/poet.song.133000.json','["胸懷幾雲夢，形骸一槁木。", "雖客長安城，未始忘退縮。", "古來豪傑士，强半死空谷。", "耐事勿動心，貧賤豈汝獨。"]'),
('a11ad172-9341-4317-bed6-0d957b4541ce','立春前後連日風雨','陸游','宋','宋诗','song-poetry','','[]','河岸春生綠，齋扉雨送昏。',48,'全唐诗/poet.song.133000.json','["河岸春生綠，齋扉雨送昏。", "手鈔書半淡，巾漉酒微渾。", "餅餌連春日，歌呼近上元。", "所嗟今夕夢，不在石帆村。"]'),
('b02ea230-295a-495c-9bfc-e00bb4e10d22','武林','陸游','宋','宋诗','song-poetry','','[]','皇輿久駐武林宮，汴雒當時未易同。',64,'全唐诗/poet.song.133000.json','["皇輿久駐武林宮，汴雒當時未易同。", "廣陌有風塵不起，長河無凍水常通。", "樓臺飛舞祥烟外，鼓笛喧呼明月中。", "六十年間幾來往，都人誰解記衰翁。"]'),
('8ddf9e56-3fff-4f40-bd0b-7a393b84158e','立春後十二日命駕至郊外戲書觸目三首  其一','陸游','宋','宋诗','song-poetry','','[]','身兼老病常歸卧，天半陰晴偶出遊。',64,'全唐诗/poet.song.133000.json','["身兼老病常歸卧，天半陰晴偶出遊。", "鸚鵡碧籠當戶外，鞦韆畫柱出牆頭。", "年華冉冉飛雙翼，夢境悠悠寄一漚。", "旅食都門那可久，少留應爲賦春愁。"]'),
('ff0c42a5-bcb5-4df3-88a0-551bb3d81108','立春後十二日命駕至郊外戲書觸目三首  其二','陸游','宋','宋诗','song-poetry','','[]','宮雲縹渺漏聲遲，夢裏華胥却自疑。',64,'全唐诗/poet.song.133000.json','["宮雲縹渺漏聲遲，夢裏華胥却自疑。", "春淺風光先盎盎，時平節物共熙熙。", "畫簾不捲聞人語，玉勒徐行避酒旗。", "閱盡輩流身獨健，恍如隨計入都時。"]'),
('fe3ca38a-7270-418a-8203-f6380e7fc5eb','立春後十二日命駕至郊外戲書觸目三首  其三','陸游','宋','宋诗','song-poetry','','[]','丹成不服怕升天，豈料乘風到日邊。',64,'全唐诗/poet.song.133000.json','["丹成不服怕升天，豈料乘風到日邊。", "九陌樓臺生細靄，萬家弦管送流年。", "香車寶馬沿湖路，繡幕金罍出郭船。", "折簡亦思招客醉，不堪春困又成眠。"]'),
('e744758a-c8e8-4e8a-8402-ab4348f03682','春夜','陸游','宋','宋诗','song-poetry','','[]','客向燈前老，愁從枕上生。',48,'全唐诗/poet.song.133000.json','["客向燈前老，愁從枕上生。", "雨聲添好睡，花氣散餘酲。", "舊事談誰聽，新詩鍊不成。", "惟當速歸老，鄰父待同耕。"]'),
('5af240f6-d75c-4a60-88cc-d39158952817','訪客至近郊','陸游','宋','宋诗','song-poetry','','[]','訪客西郊路，停車小苑門。',48,'全唐诗/poet.song.133000.json','["訪客西郊路，停車小苑門。", "閑雲寧有雨，淡日不成暄。", "鷺下青蘋浦，鴉啼綠樹村。", "還家未索莫，隨分具魚飧。"]'),
('3b570331-496e-46ca-8a54-c2f6b4dcb0dd','車中作','陸游','宋','宋诗','song-poetry','','[]','雨過未生塵，寒輕不著人。',48,'全唐诗/poet.song.133000.json','["雨過未生塵，寒輕不著人。", "斷雲飛苑路，高柳暗天津。", "憔悴非平日，呻吟又一春。", "絲毫寧有補，空負耦耕身。"]'),
('8cd1a0fc-8c3b-4397-9096-7abcb8446003','倦飛','陸游','宋','宋诗','song-poetry','','[]','倦飛何意閉樊籠，冉冉年光過眼空。',64,'全唐诗/poet.song.133000.json','["倦飛何意閉樊籠，冉冉年光過眼空。", "酒盡不妨沽巷口，詩成多是在車中。", "曾腰白羽心猶壯，不養丹砂頰自紅。", "所嘆暮年交舊盡，燈前情話與誰同。"]'),
('a4dada22-7dac-448f-a7a9-3bebad234969','遣興','陸游','宋','宋诗','song-poetry','','[]','馬迹車塵不到門，暮年萬事付乾坤。',64,'全唐诗/poet.song.133000.json','["馬迹車塵不到門，暮年萬事付乾坤。", "讀書浪苦只取笑，識字雖多誰與論。", "骨相元非金馬客，夢魂空繞石帆村。", "濁醪幸有鄰翁共，莫厭從來老瓦盆。"]'),
('58d4b712-a6eb-4e54-b301-af3776d182c6','癸亥正月十日夜夢三山竹林中筍出甚盛欣然有作','陸游','宋','宋诗','song-poetry','','[]','新春身不到家園，東崦西村役夢魂。',32,'全唐诗/poet.song.133000.json','["新春身不到家園，東崦西村役夢魂。", "一夜四山雷雨起，滿林無數長龍孫。"]'),
('ea272005-689e-451c-a6ca-f09cc3a1d2c2','謝徐志父帳幹惠詩編','陸游','宋','宋诗','song-poetry','','[]','平生聞若人，筆墨極奇峭。',156,'全唐诗/poet.song.133000.json','["平生聞若人，筆墨極奇峭。", "相望二千里，安得接談笑。", "一朝獲其詩，驚喜踰素料。", "夜窗取吟諷，寒燈耿相照。", "舂容清廟歌，縹緲蘇門嘯。", "蹴天浙江濤，照野楚山燒。", "每篇十過讀，玩味頭屢掉。", "正如啜名酒，雖愛不忍釂。", "看君亦華髮，氣壓萬年少。", "予昔從茶山，辱賞三語妙。", "文章老不進，憔悴今可吊。", "誰知牛車鐸，黄鐘乃同調。", "願君時來過，勿恤俗子誚。"]'),
('254e4fe9-cb39-4aed-b0c8-40210ef3330f','河橋晚歸','陸游','宋','宋诗','song-poetry','','[]','曲巷連新市，層樓近小橋。',48,'全唐诗/poet.song.133000.json','["曲巷連新市，層樓近小橋。", "青帘猶滴雨，綠浦恰通潮。", "簾影晴方見，笙聲冷未調。", "斜陽覓歸路，偏愛玉驄驕。"]'),
('94bd1096-2ca9-4cfb-a559-c9d642a9f16c','謝王子林判院惠詩編','陸游','宋','宋诗','song-poetry','','[]','文章有定價，議論有至公。',144,'全唐诗/poet.song.133000.json','["文章有定價，議論有至公。", "我不如誠齋，此評天下同。", "王子江西秀，詩有誠齋風。", "今年入修門，軒軒若飛鴻。", "人言誠齋詩，浩然與俱東。", "字字若長城，梯衝何由攻。", "我望已畏之，謹避不欲逢。", "一日來叩門，錦囊出幾空。", "我欲與馳逐，未交力已窮。", "太息謂王子，諸人無此功。", "騎驢上灞橋，買酒醉新豐。", "知子定有人，詎必老鈍翁。"]'),
('9cbfd352-0284-4048-8438-c75195f403ba','紹興癸亥余以進士來臨安年十九明年上元從舅光州通守唐公仲俊招觀燈後六十年嘉泰壬戌被命起造朝明年癸亥復見燈夕遊人之盛感嘆有作','陸游','宋','宋诗','song-poetry','','[]','隨計當時入帝城，笙歌燈火夜連明。',32,'全唐诗/poet.song.133000.json','["隨計當時入帝城，笙歌燈火夜連明。", "寧知六十餘年後，老眼重來看太平。"]'),
('8ee4d708-3455-428d-990c-8f7450b65717','出謁晚歸','陸游','宋','宋诗','song-poetry','','[]','萬卷縱橫眼欲盲，偶隨尺一起柴荆。',64,'全唐诗/poet.song.133000.json','["萬卷縱橫眼欲盲，偶隨尺一起柴荆。", "淵魚脫水知難悔，野鶴乘車只自驚。", "苑路落梅輕有態，御溝流水細無聲。", "紅塵朝暮何時了，促駕歸來洗破觥。"]'),
('77032766-a689-4631-90f2-29a312ed4671','思歸示子聿','陸游','宋','宋诗','song-poetry','','[]','平生愛山水，遊陟老不厭。',192,'全唐诗/poet.song.133000.json','["平生愛山水，遊陟老不厭。", "此外惟讀書，垂死尚關念。", "方昔少壯時，萬里携一劍。", "自從還故山，日夜就收斂。", "蒙恩置三館，寒灰忽光焰。", "龍鍾氣纔屬，筆力安得贍。", "同舍多賢豪，揣分無乃玷。", "春來百疾作，沉痼困鍼砭。", "思歸入夢寐，歷歷數過店。", "問津始胥濤，繫纜望禹窆。", "小江齏餅美，梅市將酒釅。", "雲破山嶙峋，雨足湖瀲灧。", "二月柳勝槎，三月花如染。", "拄杖幸可扶，吾生尚何欠。", "更當與稚子，晨暮事鉛槧。", "天爵古所尊，榮名勿多占。"]'),
('822b2cf3-3729-4d65-888e-a3462408f9fe','上元後連數日小雨作寒戲作四首  其一','陸游','宋','宋诗','song-poetry','','[]','呼兒取酒敵春寒，病起駝裘剩覺寬。',32,'全唐诗/poet.song.133000.json','["呼兒取酒敵春寒，病起駝裘剩覺寬。", "萬事不妨高枕卧，始知老子耐悲歡。"]'),
('f79a1189-61af-4d22-b934-74705c0517fe','上元後連數日小雨作寒戲作四首  其二','陸游','宋','宋诗','song-poetry','','[]','春風催暖入園林，一片雲生又作陰。',32,'全唐诗/poet.song.133000.json','["春風催暖入園林，一片雲生又作陰。", "留得梅花三日住，誰云造物本無心。"]'),
('6ddf7fb1-d015-4018-934b-24e4d5a56168','上元後連數日小雨作寒戲作四首  其三','陸游','宋','宋诗','song-poetry','','[]','烟籠天闕青鴛溼，水漲官河畫鷁浮。',32,'全唐诗/poet.song.133000.json','["烟籠天闕青鴛溼，水漲官河畫鷁浮。", "解賦春陰三十首，不應惟有宋鄜州。"]'),
('dcd09e61-e34b-45c5-a338-2c181f3a99f9','上元後連數日小雨作寒戲作四首  其四','陸游','宋','宋诗','song-poetry','','[]','擬撥殘書出郭行，浮雲忽已敗春晴。',32,'全唐诗/poet.song.133000.json','["擬撥殘書出郭行，浮雲忽已敗春晴。", "窮閻今雨無車馬，卧聽深泥濺履聲。"]'),
('da85116b-f7ab-417d-b480-9b5bb12fe3ff','出湧金門','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','出湧金門一黯然，初來猶是紹興前。',32,'全唐诗/poet.song.133000.json','["出湧金門一黯然，初來猶是紹興前。", "都人百萬今誰在，惟有西湖似昔年。"]'),
('a99b5c1d-c120-4647-bdc7-caa349c457c3','書志示子聿','陸游','宋','宋诗','song-poetry','','[]','誤上蓬山亦已叨，所悲故里隔胥濤。',64,'全唐诗/poet.song.133000.json','["誤上蓬山亦已叨，所悲故里隔胥濤。", "還家未失屠羊業，報國元無汗馬勞。", "載筆敢言宗史漢，閉門猶得讀莊騷。", "小兒願與翁偕隱，正恐聲名未易逃。"]'),
('b1c9e518-f636-4578-98cf-cdacd816e76a','入春念歸尤切有作','陸游','宋','宋诗','song-poetry','','[]','六朝覆育忝遺民，扶憊歸來雪鬢新。',64,'全唐诗/poet.song.133000.json','["六朝覆育忝遺民，扶憊歸來雪鬢新。", "對酒無歡翻作病，愛詩何得但窮人。", "腰錢自昔妨騎鶴，絕筆何時到獲麟。", "鄉俗嬉遊重端五，剩烹糰糭喚比鄰。"]'),
('5654e090-903c-49ef-ac92-eb2499e26e10','書房雜詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','賦性無他嗜，傳家但古書。',48,'全唐诗/poet.song.133000.json','["賦性無他嗜，傳家但古書。", "堯咨洪水際，羲畫結繩餘。", "異學方攘斥，浮文亦掃除。", "挑燈北窗下，聊得遂吾初。"]'),
('089be3ad-332a-467b-b1b9-08651590bcfb','書房雜詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','久客思鄉井，殘軀怯歲年。',48,'全唐诗/poet.song.133000.json','["久客思鄉井，殘軀怯歲年。", "家能常食粥，口固不言錢。", "鐵補曾穿硯，韋聯屢絕編。", "卧聞兒講學，起坐失沉綿。"]'),
('179342d5-9c20-4826-9a6b-9143b5edd99b','獨立思故山','陸游','宋','宋诗','song-poetry','','[]','溪水初生與岸平，橋頭新柳已藏鶯。',64,'全唐诗/poet.song.133000.json','["溪水初生與岸平，橋頭新柳已藏鶯。", "詩緣遇興玲瓏和，酒爲逢知爛熳傾。", "青箬買來衝雨釣，烏犍租得及時耕。", "今朝獨立東風裏，嘆息無人會此情。"]'),
('67052e21-5dea-407e-912a-c2c85f6d7576','寓嘆','陸游','宋','宋诗','song-poetry','','[]','俗心浪自作棼絲，世事元知似弈棋。',64,'全唐诗/poet.song.133000.json','["俗心浪自作棼絲，世事元知似弈棋。", "舊業蕭然歸亦樂，餘年至此死何悲。", "古人可作將誰慕，造物無心豈汝私。", "已决殘春故溪去，短蓑垂釣月明時。"]'),
('83d529c1-7d31-489b-85e4-b60e572a2e45','後寓嘆','陸游','宋','宋诗','song-poetry','','[]','貂蟬未必出兜鍪，要是蒼鷹憶下韝。',64,'全唐诗/poet.song.133000.json','["貂蟬未必出兜鍪，要是蒼鷹憶下韝。", "彭澤往歸端爲酒，輕車已老豈須侯。", "千年精衛心平海，三日於菟氣食牛。", "會與高人期物外，摩挲銅狄灞城秋。"]'),
('b096ba4e-0443-4e24-823e-6c70eda57068','新歲頗健寄青城故人','陸游','宋','宋诗','song-poetry','','[]','驕氣年來痛自鋤，似能略契度關書。',64,'全唐诗/poet.song.133000.json','["驕氣年來痛自鋤，似能略契度關書。", "神光出眥夜穿帳，胎髮滿頭晨映梳。", "吾道元知非土苴，此身那可付丘墟。", "岷山幸有丹爐在，青壁何時共結廬。"]'),
('ed940710-570b-4de8-b629-9c0b6b68d33e','新年七十有九','陸游','宋','宋诗','song-poetry','','[]','中歲抱沉綿，詎敢望七十。',120,'全唐诗/poet.song.133000.json','["中歲抱沉綿，詎敢望七十。", "造物偶脫遺，俯仰耄已及。", "寧知辱弓旌，扶憊去鄉邑。", "受恩不知報，懷抱空怏悒。", "天門邈難窺，地芥亦懶拾。", "隨身一詩囊，副以兩藥笈。", "何當復得謝，浩蕩脫維縶。", "擘浪畫楫飛，穿雲青鞋溼。", "餘年尚有幾，登覽當汲汲。", "狂吟題寺廊，大筆蘸墨汁。"]'),
('54165cf7-9122-4db8-b7a1-9c2c0da8efd5','春日訪客于逆旅及郊寺感而有賦','陸游','宋','宋诗','song-poetry','','[]','底事經年客帝鄉，風光淡沲日初長。',64,'全唐诗/poet.song.133000.json','["底事經年客帝鄉，風光淡沲日初長。", "野歌作氣老猶壯，花氣撩人醒亦狂。", "店壁拂塵尋舊字，寺樓極目送斜陽。", "告歸不過殘春事，杜曲桑麻亦未荒。"]'),
('0aa618be-9a75-4c9e-b2ad-191cd1633a87','二月二日夢中作','陸游','宋','宋诗','song-poetry','','[]','零落薔薇委道傍，更堪微雨漬殘香。',32,'全唐诗/poet.song.133000.json','["零落薔薇委道傍，更堪微雨漬殘香。", "象床玉尺人何在，腸斷新裁錦一方。"]'),
('3dd2444f-da7c-4fc6-a1f9-77b128126719','對酒作','陸游','宋','宋诗','song-poetry','','[]','羨門安期何在哉，河流上泝崑崙開。',96,'全唐诗/poet.song.133000.json','["羨門安期何在哉，河流上泝崑崙開。", "白雲不與隱居老，孤鶴自下遼天來。", "春江風物正閑美，綠浦潮平柁初起。", "暮吹長笛發巴陵，曉挂高帆渡湘水。", "世間萬變更故新，會當太息摩銅人。", "脫裘取酒藉芳草，與子共醉壺中春。"]'),
('6c23621b-98e4-45ad-9a4c-f1194deaa440','西湖春遊','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','靈隱前，天竺後，鬼削神剜作巖岫。',99,'全唐诗/poet.song.133000.json','["靈隱前，天竺後，鬼削神剜作巖岫。", "冷泉亭中一尊酒，一日可敵千年壽。", "清明後，上巳前，千紅百紫爭妖妍。", "鼕鼕鼓聲鞠場邊，鞦韆一蹴如登仙。", "人生得意須年少，白髮蘢鍾空自笑。", "君不見灞亭耐事故將軍，醉尉怒訶如不聞。"]'),
('a445d5ed-945c-4f2d-aa73-06ce57c4977f','春晚用對酒韵','陸游','宋','宋诗','song-poetry','','[]','吾今歸哉復歸哉，草堂正對湖山開。',96,'全唐诗/poet.song.133000.json','["吾今歸哉復歸哉，草堂正對湖山開。", "座銘漆園養生主，屏列柴桑歸去來。", "一閑可敵八珍美，驪駒在門端可起。", "不緣老病日日增，世味從來淡如水。", "故人誰非白頭新，况復眼中無故人。", "但餘一恨未免嘆，掩關睡過今年春。"]'),
('4f81c61b-2414-4049-a097-dcfa29ac5f44','題館中直舍壁','陸游','宋','宋诗','song-poetry','','[]','幾年憔悴去清班，敢辱君恩誤賜環。',64,'全唐诗/poet.song.133000.json','["幾年憔悴去清班，敢辱君恩誤賜環。", "但厭軟塵隨倦馬，不愁弱水隔神山。", "下帷寢飯群書裏，退食雍容眾雋間。", "行矣東歸竟何補，低回未免愧吾顔。"]'),
('c4f2de17-2887-4ddb-a1bd-e69418fd5110','春晚懷故山','陸游','宋','宋诗','song-poetry','','[]','吾廬烟樹間，正占湖一曲。',120,'全唐诗/poet.song.133000.json','["吾廬烟樹間，正占湖一曲。", "遠山何所似，䰀鬌千髻綠。", "近山更可人，連娟兩眉蹙。", "澗蟠偃蓋松，路暗圍尺竹。", "海棠雖妍華，態度終不俗。", "最奇女郎花，宛有世外躅。", "雖云懶出遊，閉戶樂事足。", "年來殊失計，久耗太倉粟。", "淖糜不救口，斷簡欲滿屋。", "兀兀不知春，青燈伴幽獨。"]'),
('38d0bd55-76e6-46be-89fc-3256d9af5c90','春社日效宛陵先生體四首 社雨','陸游','宋','宋诗','song-poetry','','[]','開歲纔幾時，春社忽已及。',48,'全唐诗/poet.song.133000.json','["開歲纔幾時，春社忽已及。", "茫茫草色深，蕭蕭雨聲急。", "扶犁行白水，不惜芒屨溼。", "村童更可憐，赤脚牛背立。"]'),
('09796318-50bd-4f47-b5f7-475a72c7fe66','春社日效宛陵先生體四首 社鼓','陸游','宋','宋诗','song-poetry','','[]','酒旗三家市，烟草十里陂。',48,'全唐诗/poet.song.133000.json','["酒旗三家市，烟草十里陂。", "林間鼓鼕鼕，迨此春社時。", "飲福父老醉，嵬峨相扶持。", "君勿輕此聲，可配豐年詩。"]'),
('8143c1cf-d21d-4f38-a1b1-6b94abd6fc68','春社日效宛陵先生體四首 社酒','陸游','宋','宋诗','song-poetry','','[]','農家耕作苦，雨暘每關念。',48,'全唐诗/poet.song.133000.json','["農家耕作苦，雨暘每關念。", "種黍蹋麴糵，終歲勤收斂。", "社甕雖草草，酒味亦醇釅。", "長歌南陌頭，百年應不厭。"]'),
('56bd4bf7-3ad8-40e9-a62d-d5c993ac2b37','春社日效宛陵先生體四首 社肉','陸游','宋','宋诗','song-poetry','','[]','社日取社豬，燔炙香滿村。',48,'全唐诗/poet.song.133000.json','["社日取社豬，燔炙香滿村。", "饑鴉集街樹，老巫立廟門。", "雖無牲牢盛，古禮亦略存。", "醉歸懷餘肉，霑遺徧諸孫。"]'),
('cc565f6e-af16-4e23-9570-415c0bd322fe','局中春興','陸游','宋','宋诗','song-poetry','','[]','天知病眼困風沙，借與蓬山閱物華。',64,'全唐诗/poet.song.133000.json','["天知病眼困風沙，借與蓬山閱物華。", "微暖已迎新到燕，輕陰猶護欲殘花。", "幽窗寂寂書圍座，倦枕時時夢過家。", "立馬庭前還小駐，不妨閑試半甌茶。"]'),
('6d45da42-6521-4658-9aa3-3b77ae24e3a4','久客','陸游','宋','宋诗','song-poetry','','[]','憔悴閑坊底，蕭條久客心。',48,'全唐诗/poet.song.133000.json','["憔悴閑坊底，蕭條久客心。", "燕歸知社過，葉密覺春深。", "燈火愁殘史，塵埃嘆素琴。", "餘生猶有幾，去日苦駸駸。"]'),
('ebf50f72-4b00-496b-a5d0-e506693869a1','幽居','陸游','宋','宋诗','song-poetry','','[]','花過鶯初懶，泥新燕正忙。',48,'全唐诗/poet.song.133000.json','["花過鶯初懶，泥新燕正忙。", "病餘猶止酒，睡起獨焚香。", "拄杖嫌園窄，棋枰喜日長。", "北窗元可樂，不是傲羲皇。"]'),
('e19e6d83-c08a-4abd-9c33-d1318c6e93dc','春日絕句八首  其一','陸游','宋','宋诗','song-poetry','','[]','吏來屢敗哦詩興，雨作常妨載酒行。',32,'全唐诗/poet.song.133000.json','["吏來屢敗哦詩興，雨作常妨載酒行。", "忽見家家插楊柳，始知今日是清明。"]'),
('6968f9fa-7d68-4b54-b39a-79bb94aea308','春日絕句八首  其二','陸游','宋','宋诗','song-poetry','','[]','二十四番花有信，一百七日食猶寒。',32,'全唐诗/poet.song.133000.json','["二十四番花有信，一百七日食猶寒。", "眼中不是無春色，嘆息衰翁自鮮歡。"]'),
('cd179da7-782a-4e48-afad-e3c7042d0cfe','春日絕句八首  其三','陸游','宋','宋诗','song-poetry','','[]','門前喚擔買芳菲，白髮猶堪插一枝。',32,'全唐诗/poet.song.133000.json','["門前喚擔買芳菲，白髮猶堪插一枝。", "舊厭蛙聲今喜聽，牆陰特地作盆池。"]'),
('3f89a267-21b2-4e2b-b693-e8c473870efe','春日絕句八首  其四','陸游','宋','宋诗','song-poetry','','[]','故園蛺蝶最多種，百草長時花亂開。',32,'全唐诗/poet.song.133000.json','["故園蛺蝶最多種，百草長時花亂開。", "窮巷春風元不到，一雙誰遣過牆來。"]'),
('38ffe89d-0f5f-425e-90a9-ae83c2da36c9','春日絕句八首  其五','陸游','宋','宋诗','song-poetry','','[]','桃李吹成九陌塵，客中又過一年春。',32,'全唐诗/poet.song.133000.json','["桃李吹成九陌塵，客中又過一年春。", "餘寒漠漠城南路，只見鞦韆不見人。"]'),
('179b2628-d20b-4c99-a9ba-dae0e3f3eb18','春日絕句八首  其六','陸游','宋','宋诗','song-poetry','','[]','便恐東皇促駕回，小軒無事且銜杯。',32,'全唐诗/poet.song.133000.json','["便恐東皇促駕回，小軒無事且銜杯。", "不知何處桃花落，一片飛從屋角來。"]'),
('6bdd06fb-4b56-42b6-a8b4-2a71481398b3','春日絕句八首  其七','陸游','宋','宋诗','song-poetry','','[]','介亭南畔排衙石，剝蘚剜苔覓舊題。',32,'全唐诗/poet.song.133000.json','["介亭南畔排衙石，剝蘚剜苔覓舊題。", "讀罷南豐數行字，滿山煙雨共凄迷。"]'),
('fa1d2d3f-6b47-42cf-93a2-f3dcc36f5f53','春日絕句八首  其八','陸游','宋','宋诗','song-poetry','','[]','楊家園裏醉殘春，醉倩傍人拾墮巾。',32,'全唐诗/poet.song.133000.json','["楊家園裏醉殘春，醉倩傍人拾墮巾。", "紅紫飄零不須嘆，東君渠自是行人。"]'),
('00de7778-7693-4761-b2eb-a3d9e569c216','嘆老','陸游','宋','宋诗','song-poetry','','[]','晨起梳頭滿鏡霜，豈堪著脚少年場。',64,'全唐诗/poet.song.133000.json','["晨起梳頭滿鏡霜，豈堪著脚少年場。", "酒徒分散情疏索，棋敵憑陵意頡頏。", "寓世極知均醉夢，餘生只合老耕桑。", "石帆山下蓴絲長，待我還東泊野航。"]'),
('3dcdc83e-2d77-4c18-b9d5-0b71dc1fc5f0','春雨中偶賦','陸游','宋','宋诗','song-poetry','','[]','老子年來百事慵，不妨詩課尚能供。',64,'全唐诗/poet.song.133000.json','["老子年來百事慵，不妨詩課尚能供。", "殘花已覺胭脂淡，煮酒初嘗琥珀濃。", "羸病不堪連日雨，孤愁偏怯五更鐘。", "舊交只有烏藤在，且伴禪床莫化龍。"]'),
('87d877d4-e413-4c4d-b050-54d0a2a5d027','戲詠落花','陸游','宋','宋诗','song-poetry','','[]','終年栽接待新春，一日隨風委路塵。',32,'全唐诗/poet.song.133000.json','["終年栽接待新春，一日隨風委路塵。", "愁殺主翁渠不管，爭如只作看花人。"]'),
('43430463-597e-4418-a937-0aab31b58684','思歸示兒輩','陸游','宋','宋诗','song-poetry','','[]','睡味甜如蜜，人情冷似漿。',48,'全唐诗/poet.song.133000.json','["睡味甜如蜜，人情冷似漿。", "流年垂及耄，客子固多傷。", "興發雞豚社，心闌翰墨場。", "吾兒姑力穡，莫羨笏堆床。"]'),
('f1a6b996-0fa5-4ad3-8719-5abd15a80f84','東軒花時將過感懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','小軒風月得婆娑，盡付流年與嘯歌。',64,'全唐诗/poet.song.133000.json','["小軒風月得婆娑，盡付流年與嘯歌。", "細數一春今過半，正令百歲亦無多。", "還家常恐難全璧，閱世深疑已爛柯。", "只欲閉門搘倦枕，晚風無奈落花何。"]'),
('2d9a2d24-9240-4efe-94b9-e10f65bdecf5','東軒花時將過感懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','社雨晴時燕子飛，園林何許覓芳菲。',64,'全唐诗/poet.song.133000.json','["社雨晴時燕子飛，園林何許覓芳菲。", "江山良是人誰在，天地無私春又歸。", "殘史有期成汗簡，修門即日挂朝衣。", "人生念念皆堪悔，敢效淵明嘆昨非。"]'),
('351efc0a-ecff-4999-a25f-6a65fdbb7608','江亭','陸游','宋','宋诗','song-poetry','','[]','千載濤江上，書生誦所聞。',48,'全唐诗/poet.song.133000.json','["千載濤江上，書生誦所聞。", "鑄形尊越蠡，抉眼悼荆員。", "高鳥衝烟沒，輕舟壓浪分。", "何由從此逝，揮手謝諸君。"]'),
('0ee0f60c-6cc4-4bc9-a1eb-c01263baed86','對食','陸游','宋','宋诗','song-poetry','','[]','天賦元無滿谷羊，不煩粱肉汙龜腸。',64,'全唐诗/poet.song.133000.json','["天賦元無滿谷羊，不煩粱肉汙龜腸。", "忽逢客釜蒓羹美，遥憶山厨麥飯香。", "正有一簞元自足，縱嘲三韭亦何傷。", "江邊烟岫參差路，便喚漁舟莫治裝。"]'),
('0e3933ee-d2e8-42f2-b3a9-41928e1fbbe8','飽食','陸游','宋','宋诗','song-poetry','','[]','飽食無功愧汗青，燈前顧影嘆伶俜。',64,'全唐诗/poet.song.133000.json','["飽食無功愧汗青，燈前顧影嘆伶俜。", "馬衰猶養疑知路，龜久當捐爲不靈。", "腰下徒誇綬若若，鏡中何止髮星星。", "石帆回首初非遠，要及清秋斸茯苓。"]'),
('241db3c4-7abb-4706-9127-9ae406643028','記夢','陸游','宋','宋诗','song-poetry','','[]','旅夢遊何地，分明禹廟傍。',48,'全唐诗/poet.song.133000.json','["旅夢遊何地，分明禹廟傍。", "不嫌村餉薄，但愛野蔬香。", "筍市連山塢，菱歌起夕陽。", "一蓑元所樂，枉道懶衣裳。"]'),
('e46050f7-d00b-451f-9d06-d6eec1d2e931','初夜暫就枕','陸游','宋','宋诗','song-poetry','','[]','街鼓鼕鼕欲斷時，官閑惟與睡相宜。',64,'全唐诗/poet.song.133000.json','["街鼓鼕鼕欲斷時，官閑惟與睡相宜。", "褰帷卧看初升月，轉枕重思未穩詩。", "偃仰少安真得策，欠伸徐起頓忘疲。", "悠然已在羲皇上，莫遣兒曹取次知。"]'),
('c4f8baef-5eb9-4349-87da-846ea02f7b80','次林伯玉侍郎韵賦西湖春遊','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖一別不知年，陳迹重尋麥嶺邊。',64,'全唐诗/poet.song.133000.json','["西湖一別不知年，陳迹重尋麥嶺邊。", "山遠往來雙白鷺，波平俯仰兩青天。", "殘骸自覺難支久，一笑相從亦宿緣。", "旅食京華詩思盡，羨公落筆思如泉。"]'),
('79504a6e-a725-4fda-90be-c79753165a6b','湖中微雨戲作','陸游','宋','宋诗','song-poetry','','[]','搓罷青梅指爪香，一杯聊復答年光。',32,'全唐诗/poet.song.133000.json','["搓罷青梅指爪香，一杯聊復答年光。", "莫言老子無人顧，猶得西施作淡粧。"]'),
('89dc8493-6598-4559-baef-c31bd82bf6af','與兒輩泛舟遊西湖一日間晴陰屢易','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','逢著園林即款扉，酌泉煮筍欲忘歸。',64,'全唐诗/poet.song.133000.json','["逢著園林即款扉，酌泉煮筍欲忘歸。", "楊花正與人爭路，鳩語還催雨點衣。", "古寺題名那復在，後生識面自應稀。", "傷心六十餘年事，雙塔依然在翠微。"]'),
('dec627c8-494b-4a2b-975b-66716be03e64','贈呂次翁','陸游','宋','宋诗','song-poetry','','[]','君得金丹雖未仙，放翁邂逅與忘年。',64,'全唐诗/poet.song.133000.json','["君得金丹雖未仙，放翁邂逅與忘年。", "空能處處誇詩句，不解時時贈酒錢。", "馬駿極知生冀土，鶴飛會見上遼天。", "爾來筆硯塵埃滿，剩欲相從乞一聯。"]'),
('d7c5a97f-b2c5-47ca-842a-ad3a30ab6143','得子聿到家山後書','陸游','宋','宋诗','song-poetry','','[]','日日春陰愁出戶，汝今恰遇十分晴。',64,'全唐诗/poet.song.133000.json','["日日春陰愁出戶，汝今恰遇十分晴。", "桑林紫葚纍纍熟，稻垅青秧漫漫平。", "夢好定知行路健，書來深慰倚門情。", "柯橋道上山如畫，早晚歸舟聽櫓聲。"]'),
('991deacd-e231-4299-9f44-a527382bc9b8','題齋壁三首  其一','陸游','宋','宋诗','song-poetry','','[]','小屋閑坊旋卜居，老人也看作吾廬。',64,'全唐诗/poet.song.133000.json','["小屋閑坊旋卜居，老人也看作吾廬。", "客知貪睡多留刺，兒未來歸自檢書。", "草賦萬言那直水，屬文三紙尚無驢。", "京塵日念家山樂，况值腰鐮割麥初。"]'),
('b1da6c45-1184-4b3f-86eb-ce558b69d3b2','題齋壁三首  其二','陸游','宋','宋诗','song-poetry','','[]','殘髮蕭蕭不滿簪，衰年亦自惜光陰。',64,'全唐诗/poet.song.133000.json','["殘髮蕭蕭不滿簪，衰年亦自惜光陰。", "作碑諛墓已絕筆，紬史藏山猶苦心。", "穿破綠錢多稚筍，驚飛紅雨有幽禽。", "北窗睡起摩挲眼，更覺清風直萬金。"]'),
('1ca23d3a-b509-4d8a-aac2-4a00b4022fd9','題齋壁三首  其三','陸游','宋','宋诗','song-poetry','','[]','一櫂秋風去已遲，釣竿恐失野人期。',64,'全唐诗/poet.song.133000.json','["一櫂秋風去已遲，釣竿恐失野人期。", "朝回補睡尋幽夢，客去偷閑練近詩。", "浮世本知緣苦薄，頹齡已與志俱衰。", "平生所慕孤山老，剩欲懷茶奠舊祠。"]'),
('851c27b2-206d-41d9-acf7-d5475666f600','小飲','陸游','宋','宋诗','song-poetry','','[]','門生嘲喜眠，官長罵耽酒。',72,'全唐诗/poet.song.133000.json','["門生嘲喜眠，官長罵耽酒。", "人生自適爾，嘲罵亦何有。", "蒸我乳下豚，翦我雨中韭。", "杯盤雖不豐，吾兒起爲壽。", "車馬滿長安，誰肯顧衰朽。", "作詩付汝藏，千金珍弊帚。"]'),
('ce3e1e65-37cf-41db-8f62-2d703b5b4381','贈傳神水鑒','陸游','宋','宋诗','song-poetry','','[]','寫照今誰下筆親，喜君分得卧雲身。',64,'全唐诗/poet.song.133000.json','["寫照今誰下筆親，喜君分得卧雲身。", "口中無齒難藏老，頰上加毛自有神。", "誤遣汗青成國史，未妨著白號山人。", "它時更欲求奇迹，畫我溪頭把釣緡。"]'),
('bfc1bdba-5acd-4fe7-9548-b23e0fba0f20','春晚','陸游','宋','宋诗','song-poetry','','[]','新綠成陰小雨時，幅巾蕭散與閑宜。',64,'全唐诗/poet.song.133000.json','["新綠成陰小雨時，幅巾蕭散與閑宜。", "燕歸赴訴經年別，鶯晚分疏出谷遲。", "曉枕呼兒投宿酒，暮窗留客算殘棋。", "翛然此意風塵表，正恐羲皇未必知。"]'),
('7567435f-7934-49d1-a6b2-690da9c38534','天竺曉行二首  其一','陸游','宋','宋诗','song-poetry','','[]','三茆聽徹五更鐘，二竺穿窮九里松。',32,'全唐诗/poet.song.133000.json','["三茆聽徹五更鐘，二竺穿窮九里松。", "無復官樓沽酒美，但煩湖水照衰容。"]'),
('71d9ea3b-9e42-4291-b4c6-04d354fb09a5','天竺曉行二首  其二','陸游','宋','宋诗','song-poetry','','[]','筍輿咿軋水雲間，慚愧忙身得暫閑。',32,'全唐诗/poet.song.133000.json','["筍輿咿軋水雲間，慚愧忙身得暫閑。", "堪笑風中一黄葉，知看天外幾青山。"]'),
('3ea76eff-7f4e-4342-b2c4-218fdf63020e','初見石榴花','陸游','宋','宋诗','song-poetry','','[]','吳中四月尚餘寒，細雨霏霏怯倚闌。',32,'全唐诗/poet.song.133000.json','["吳中四月尚餘寒，細雨霏霏怯倚闌。", "老子真成興不淺，榴花折得一枝看。"]'),
('22409bdd-bd92-49ab-9374-d25d46db78e8','夢遊三首  其一','陸游','宋','宋诗','song-poetry','','[]','太華峰頭秋氣新，醉臨絕壁岸綸巾。',32,'全唐诗/poet.song.133000.json','["太華峰頭秋氣新，醉臨絕壁岸綸巾。", "世間萬事惟堪笑，禹迹茫茫九片塵。"]'),
('207a4182-6540-4f72-b3e0-376168b3650a','夢遊三首  其二','陸游','宋','宋诗','song-poetry','','[]','九秋風露洗頭盆，萬里雲烟腰带鞓。',32,'全唐诗/poet.song.133000.json','["九秋風露洗頭盆，萬里雲烟腰带鞓。", "小甕松醪知已熟，與君爛醉不須醒。"]'),
('ef314752-0f8f-476c-9865-ec55ef6cf723','夢遊三首  其三','陸游','宋','宋诗','song-poetry','','[]','客途幽夢苦凄凄，滿眼山川意却迷。',32,'全唐诗/poet.song.133000.json','["客途幽夢苦凄凄，滿眼山川意却迷。", "條華朝驅雲外騎，河潼夜聽月中雞。"]'),
('241af5c9-6105-4b5e-874f-b59112f97ee9','江亭晚思','陸游','宋','宋诗','song-poetry','','[]','本自無閑况有忙，遠坊兀兀送年光。',64,'全唐诗/poet.song.133000.json','["本自無閑况有忙，遠坊兀兀送年光。", "太空不礙雲舒卷，高枕寧論夢短長。", "山破霽烟千萬疊，鳥橫潮浦兩三行。", "年來自笑詩情減，愁絕奚奴古錦囊。"]'),
('38b0dc7b-b96f-4aee-ab1b-5b2d7413f2a8','上章納祿恩畀外祠遂以五月初東歸五首  其一','陸游','宋','宋诗','song-poetry','','[]','身似霜松老不枯，乞骸猶得侍清都。',64,'全唐诗/poet.song.133000.json','["身似霜松老不枯，乞骸猶得侍清都。", "百錢濁酒渾家醉，六月飛蚊徹曉無。", "美睡不愁閑客攪，出遊自有小兒扶。", "買山尚恐巢由笑，敢問君王覓鏡湖。"]'),
('a541db47-9e0f-4534-96a1-648476d0f1e1','上章納祿恩畀外祠遂以五月初東歸五首  其二','陸游','宋','宋诗','song-poetry','','[]','黄紙淋漓字似鴉，即今真箇是還家。',64,'全唐诗/poet.song.133000.json','["黄紙淋漓字似鴉，即今真箇是還家。", "園廬漸近湖山好，鄰曲來迎鼓笛譁。", "籩實傍籬收豆莢，盤蔬臨水采芹芽。", "皇家養老非忘汝，不必青門學種瓜。"]'),
('e5e21db1-2551-4707-a297-dfb167b91341','上章納祿恩畀外祠遂以五月初東歸五首  其三','陸游','宋','宋诗','song-poetry','','[]','群玉峰頭孤夢斷，五雲溪上野舟回。',64,'全唐诗/poet.song.133000.json','["群玉峰頭孤夢斷，五雲溪上野舟回。", "傍人鷗鳥自然熟，到處藕花無數開。", "麥飯不饜常面槁，柴門閑掩自心灰。", "雨來正作盆山地，不怕冥冥半月梅。"]'),
('65ccc2ac-951c-4b6b-9096-248bc6e559d1','上章納祿恩畀外祠遂以五月初東歸五首  其四','陸游','宋','宋诗','song-poetry','','[]','身是風前一斷蓬，經年竊食竟何功。',64,'全唐诗/poet.song.133000.json','["身是風前一斷蓬，經年竊食竟何功。", "倚天青嶂迎船出，撲馬紅塵轉眼空。", "網戶餉魚勝丙穴，旗亭送酒等郫筒。", "死前幸作扶犁叟，免使淮南笑發蒙。"]'),
('dfe5d421-e0d5-447a-84e2-2a630d64d26d','上章納祿恩畀外祠遂以五月初東歸五首  其五','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','此身惟有一躬耕，乞得餘年樂太平。',64,'全唐诗/poet.song.133000.json','["此身惟有一躬耕，乞得餘年樂太平。", "東觀並遊收昨夢，西湖重到付來生。", "一堤草露明晨照，半浦荷風颭晚晴。", "歷歷歸途皆勝事，江亭先聽櫂歌聲。"]'),
('857e1fbb-1797-4746-a4d4-ebeaad4a7ebd','江亭','陸游','宋','宋诗','song-poetry','','[]','旅食京華興已闌，喜扶衰憊出重關。',64,'全唐诗/poet.song.133000.json','["旅食京華興已闌，喜扶衰憊出重關。", "江波蘸岸綠堪染，山色迎人秀可餐。", "濠上觀魚非至樂，管中窺豹豈全斑。", "此行便問天台路，剩采靈芝換病顔。"]'),
('b7967008-40a6-43d2-bed6-ab312650f0c4','題三茆邵道士雲隱二首  其一','陸游','宋','宋诗','song-poetry','','[]','興盡當年句曲秋，却歸罨畫弄扁舟。',32,'全唐诗/poet.song.133000.json','["興盡當年句曲秋，却歸罨畫弄扁舟。", "有時信脚來沙際，拾得殘雲補破裘。"]'),
('ce815c19-7bc8-4329-894a-7dd619d3ac46','題三茆邵道士雲隱二首  其二','陸游','宋','宋诗','song-poetry','','[]','尚嫌勾漏養丹砂，况種劉郎去後花。',32,'全唐诗/poet.song.133000.json','["尚嫌勾漏養丹砂，况種劉郎去後花。", "罨畫溪頭雲萬頃，不知何處是君家。"]'),
('4fcecacf-31e8-4c6b-bd2c-a9f7b6fd4eb8','受外祠敕','陸游','宋','宋诗','song-poetry','','[]','放浪江湖迹已陳，今朝剩喜結銜新。',64,'全唐诗/poet.song.133000.json','["放浪江湖迹已陳，今朝剩喜結銜新。", "讀騷未敢稱名士，拜賜猶應號散人。", "歸去還騎款段馬，醉顛重岸接䍦巾。", "行行漸近雲門寺，愈信人生有宿因。"]'),
('158c8f8b-0b62-43f0-87b1-11826e36e4a5','感寓二首  其一','陸游','宋','宋诗','song-poetry','','[]','人生難控摶，古謂七十稀。',72,'全唐诗/poet.song.133000.json','["人生難控摶，古謂七十稀。", "壽夭雖小異，要亦同所歸。", "君看銜山日，耿耿有餘暉。", "投床方息偃，晨起復求衣。", "萬家同一役，負水關門扉。", "智叟與愚公，畢竟孰是非。"]'),
('f4149f50-43a4-481f-8fe7-c54a4dc989c5','感寓二首  其二','陸游','宋','宋诗','song-poetry','','[]','老氏有至言，所貴知我稀。',72,'全唐诗/poet.song.133000.json','["老氏有至言，所貴知我稀。", "鄙夫急自衒，豈復擇所歸。", "君看珠在淵，草木借光輝。", "所以古達人，懷玉被褐衣。", "吾廬大澤中，歲苦水半扉。", "朱門固自好，我亦未必非。"]'),
('de8592f5-74b3-409b-8000-1c5fa4a9f783','肉食','陸游','宋','宋诗','song-poetry','','[]','平生愛枯淡，老病未免肉。',72,'全唐诗/poet.song.133000.json','["平生愛枯淡，老病未免肉。", "殺戒苦難持，貪境則易熟。", "鄙夫五鼎少，達士一瓢足。", "紛紛刀机間，斷者豈復續。", "習聞謂當然，乍見可痛哭。", "長安多貴人，得此試一讀。"]'),
('4239851b-9b62-4970-b9f6-e9691a0339a8','贈成封州','陸游','宋','宋诗','song-poetry','','[]','綠髮臨邊固已奇，不應憔悴客京師。',64,'全唐诗/poet.song.133000.json','["綠髮臨邊固已奇，不應憔悴客京師。", "極知自有封侯骨，但要無忘耕壟時。", "意氣覆氈書捷布，風流橫槊賦新詩。", "平生每恨相從少，滿眼關山又語離。"]'),
('525e6b1b-a3fc-48e1-bfd7-85b5e6d5b1a6','予以壬戌六月十四日入都門癸亥五月十四日去國而中有閏月蓋相距正一年矣慨然有賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','三百六十日，扶衰得出都。',48,'全唐诗/poet.song.133000.json','["三百六十日，扶衰得出都。", "略無新伎倆，仍是舊形模。", "世事蠻攻觸，人情越事吳。", "勿言蓴菜老，檥櫂醉湘湖。"]'),
('03e85f55-ef4f-4b83-a91c-8837fbdb0cf1','予以壬戌六月十四日入都門癸亥五月十四日去國而中有閏月蓋相距正一年矣慨然有賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','一百七十里，我行誰謂賒。',48,'全唐诗/poet.song.133000.json','["一百七十里，我行誰謂賒。", "期年初去國，度宿即還家。", "事似談春夢，身如寄客槎。", "石帆村好在，重理舊桑麻。"]'),
('8cff9189-83e1-4212-8a3b-17791fbbd57b','雨中別同朝諸公二首  其一','陸游','宋','宋诗','song-poetry','','[]','今日別交舊，街泥盈尺深。',48,'全唐诗/poet.song.133000.json','["今日別交舊，街泥盈尺深。", "極知當作惡，追恨闕相尋。", "笑語關幽夢，江山入苦吟。", "新秋纔一月，留句待清砧。"]'),
('6fbdb984-a43b-4f32-92b4-9173ada2208a','雨中別同朝諸公二首  其二','陸游','宋','宋诗','song-poetry','','[]','雨點萬珠落，水聲群馬奔。',48,'全唐诗/poet.song.133000.json','["雨點萬珠落，水聲群馬奔。", "纔能脫危路，未遽定驚魂。", "一掃枕中夢，即歸江上村。", "村醪莫嫌薄，隨事有雞豚。"]'),
('af7ed537-48ac-4524-9f65-0ae18f98b49f','出城','陸游','宋','宋诗','song-poetry','','[]','羈枕不成寐，羸驂曉出城。',48,'全唐诗/poet.song.133000.json','["羈枕不成寐，羸驂曉出城。", "驛門深閉草，苑樹密藏鶯。", "老病安閑散，疏慵負聖明。", "津亭凝望久，惟是待潮平。"]'),
('3e78938d-174f-44e4-8150-e22b8f8d74da','宿北錢清','陸游','宋','宋诗','song-poetry','','[]','晡時理舟檝，甲夜泊錢清。',48,'全唐诗/poet.song.133000.json','["晡時理舟檝，甲夜泊錢清。", "齏餅依然美，漁燈特地明。", "酒旗闌道出，風浪拍船鳴。", "未說鄉閭喜，江山亦有情。"]'),
('ace41ac2-ef3e-4e02-bfc0-599ab63debda','老伶','陸游','宋','宋诗','song-poetry','','[]','老伶頭已白，相識不論年。',48,'全唐诗/poet.song.133000.json','["老伶頭已白，相識不論年。", "時出隨童稚，猶能習管弦。", "烟林梅市路，風幔放翁船。", "餘酒堪同醉，君無惜醉眠。"]'),
('3a08c9c6-8dcb-493b-adc9-899781f0cb14','舟行錢清柯橋之間','陸游','宋','宋诗','song-poetry','','[]','逾年夢想會稽城，喜挂高帆浩蕩行。',64,'全唐诗/poet.song.133000.json','["逾年夢想會稽城，喜挂高帆浩蕩行。", "未見東西雙白塔，先經南北兩錢清。", "兒童鼓笛迎歸艦，父老壺觴敘別情。", "想到吾廬猶未夜，竹間正看夕陽明。"]'),
('ed465f85-87e5-4fd4-b893-bcb3af9770a8','寓蓬萊館','陸游','宋','宋诗','song-poetry','','[]','道山方夢斷，稅駕復蓬萊。',48,'全唐诗/poet.song.133000.json','["道山方夢斷，稅駕復蓬萊。", "海上羝應乳，遼東鶴已回。", "客驚添鬢雪，自笑久心灰。", "底事妨人睡，樓頭暮角哀。"]'),
('95032ce6-1dfb-4155-9e7f-591b089cde62','乍自京塵中得歸故山作五字識喜','陸游','宋','宋诗','song-poetry','','[]','門巷如秋爽，軒窗抵海寬。',48,'全唐诗/poet.song.133000.json','["門巷如秋爽，軒窗抵海寬。", "初還綬若若，已覺面團團。", "引睡拈書卷，偷閑把釣竿。", "人生快意事，五月出長安。"]'),
('aea6aa7e-d985-4d6e-bc9d-ebbfe6bd0cfa','初歸雜詠七首  其一','陸游','宋','宋诗','song-poetry','','[]','雪滿漁蓑雨墊巾，超然無處不清真。',64,'全唐诗/poet.song.133000.json','["雪滿漁蓑雨墊巾，超然無處不清真。", "胸中那可有一事，天下故應無兩人。", "騎馬每行秋棧路，喚船還渡暮江津。", "酒樓僧壁留詩徧，八十年來自在身。"]'),
('8a205bfc-12a6-4368-aad9-c4a53820e1ce','初歸雜詠七首  其二','陸游','宋','宋诗','song-poetry','','[]','齒豁頭童儘耐嘲，即今爛飯用匙抄。',64,'全唐诗/poet.song.133000.json','["齒豁頭童儘耐嘲，即今爛飯用匙抄。", "朱門漫設千杯酒，青壁寧無一把茅。", "偶爾作官羞問馬，頹然對客但稱貓。", "此身定向山中死，不用磨錢擲卦爻。"]'),
('641bed6b-a94b-4c99-854d-8a0a27badf7e','初歸雜詠七首  其三','陸游','宋','宋诗','song-poetry','','[]','八十可憐心尚孩，看山看水不知回。',64,'全唐诗/poet.song.133000.json','["八十可憐心尚孩，看山看水不知回。", "軟炊香甑桃花飯，淺酌清尊竹葉醅。", "平地本知多陷阱，群兒隨處覓梯媒。", "曠懷只待秋風起，十丈蒲帆海上開。"]'),
('ed504b97-cfd7-41eb-9040-4e636b2eed4f','初歸雜詠七首  其四','陸游','宋','宋诗','song-poetry','','[]','換盡朱顔兩鬢皤，流年如此奈君何。',64,'全唐诗/poet.song.133000.json','["換盡朱顔兩鬢皤，流年如此奈君何。", "早從學問求開益，晚悟文章要詆訶。", "每憶壯遊成獨笑，間逢老伴亦高歌。", "更餘一恨君知否，千載浯溪石未磨。"]'),
('2e8042ba-9e81-4fc4-b91e-ca98a2df5910','初歸雜詠七首  其五','陸游','宋','宋诗','song-poetry','','[]','窗下初收剝啄棋，疏簾窣地晝陰移。',64,'全唐诗/poet.song.133000.json','["窗下初收剝啄棋，疏簾窣地晝陰移。", "下巖石潤揮毫後，正焙茶香落磑時。", "癃老入朝元是錯，期年决去已爲遲。", "天公賦予誰能測，只吝功名不吝詩。"]'),
('03ab8587-c3a6-485a-a8be-660098a2bff0','初歸雜詠七首  其六','陸游','宋','宋诗','song-poetry','','[]','小園五畝翦蓬蒿，便覺人間迹可逃。',64,'全唐诗/poet.song.133000.json','["小園五畝翦蓬蒿，便覺人間迹可逃。", "盡疏珍禽添爾雅，更書香草續離騷。", "藥苗可斸携長鑱，黍酒新成壓小槽。", "老入鵷行方徹悟，一官何處不徒勞。"]'),
('2e2bed9a-8211-44cf-9a34-51c683ade69f','初歸雜詠七首  其七','陸游','宋','宋诗','song-poetry','','[]','乞得身歸且浩歌，蕭然生世寄漁蓑。',64,'全唐诗/poet.song.133000.json','["乞得身歸且浩歌，蕭然生世寄漁蓑。", "茶甘半日如新啜，墨妙移時不再磨。", "山寺蹋雲頻獨往，鄰家穿竹自相過。", "棋枰勝負能多少，堪笑傍人說爛柯。"]'),
('ea414a3e-db9e-4d7f-bd1d-fb8083d2dd57','湖上急雨','陸游','宋','宋诗','song-poetry','','[]','溪烟一縷起前灘，急雨俄吞四面山。',32,'全唐诗/poet.song.133000.json','["溪烟一縷起前灘，急雨俄吞四面山。", "造化等閑成壯觀，月明却送釣船還。"]'),
('523d66b5-a6d7-43e1-8a23-d24fd1096d06','夏日獨居','陸游','宋','宋诗','song-poetry','','[]','平生本清凈，垂老更蕭然。',48,'全唐诗/poet.song.133000.json','["平生本清凈，垂老更蕭然。", "已罷客載酒，亦無僧說禪。", "空庭朝下鵲，密樹晚鳴蟬。", "長日君無厭，新秋近眼邊。"]'),
('ed5805ad-3cf5-4d7f-ab26-af59ba6f924a','溪上夜釣','陸游','宋','宋诗','song-poetry','','[]','少時妄意學金丹，八十溪頭把釣竿。',64,'全唐诗/poet.song.133000.json','["少時妄意學金丹，八十溪頭把釣竿。", "露溼茭叢姑惡哭，烟深沙渚鷺鷥寒。", "登臨每嘆乾坤大，强健猶應歲月寬。", "作意清吟未須厭，如山殘稿後人看。"]'),
('ac080687-0994-400d-87b7-108e19fdd384','幽事','陸游','宋','宋诗','song-poetry','','[]','曳杖驚林鵲，投竿罥澗花。',48,'全唐诗/poet.song.133000.json','["曳杖驚林鵲，投竿罥澗花。", "若非詩滿卷，只道夢還家。", "開士分朝飯，鄰翁喚午茶。", "悠然吾事足，歸路並山斜。"]'),
('b2e86ec0-ca51-409a-88b6-1a1f256f8f85','夙興','陸游','宋','宋诗','song-poetry','','[]','幽夢回千里，高城轉五更。',48,'全唐诗/poet.song.133000.json','["幽夢回千里，高城轉五更。", "窗虛送月落，竹動喜風生。", "自笑行安往，猶思坐待明。", "郊居少僮僕，手自闢柴荆。"]'),
('2704f405-d14d-4c8f-bffb-51e81a4b7ba5','文章','陸游','宋','宋诗','song-poetry','','[]','文章在眼每森然，力弱才疏挽不前。',32,'全唐诗/poet.song.133000.json','["文章在眼每森然，力弱才疏挽不前。", "前輩不生吾輩老，恐留遺恨又千年。"]'),
('945806d3-0b7c-4331-bd6f-4993925c0600','閑遊四首  其一','陸游','宋','宋诗','song-poetry','','[]','觸熱辭行在，扶衰返故丘。',48,'全唐诗/poet.song.133000.json','["觸熱辭行在，扶衰返故丘。", "亂蟬催落日，病葉報新秋。", "秣蹇投山驛，尋詩倚寺樓。", "不因行萬里，那信此生浮。"]'),
('cc977671-6313-4ee3-b6cc-9e66fc36abd9','閑遊四首  其二','陸游','宋','宋诗','song-poetry','','[]','剡縣有佳處，吾行無定期。',48,'全唐诗/poet.song.133000.json','["剡縣有佳處，吾行無定期。", "橫塘供晚釣，孤店具晨炊。", "約客同看竹，留僧與對棋。", "人生得自在，更老未爲遲。"]'),
('f6c18ffa-ee14-42d9-8363-934d68d749ce','閑遊四首  其三','陸游','宋','宋诗','song-poetry','','[]','我出亦何急，輟行還悵然。',48,'全唐诗/poet.song.133000.json','["我出亦何急，輟行還悵然。", "輕裝幸已具，老健更誰先。", "野飯聊支日，山蔬不直錢。", "此生終樂死，何以報皇天。"]'),
('07cd3847-964c-4c4e-b35f-e4a0ea267793','閑遊四首  其四','陸游','宋','宋诗','song-poetry','','[]','已破京塵夢，還尋剡曲遊。',48,'全唐诗/poet.song.133000.json','["已破京塵夢，還尋剡曲遊。", "戴星離古戍，衝雨憩山郵。", "壁認曾題字，門橫昔渡舟。", "經行固多感，隨處寄悠悠。"]'),
('9d9d7eb8-68da-4763-93de-6a5618196b0e','夏日','陸游','宋','宋诗','song-poetry','','[]','赫赫炎威日正中，冰紈笛簟欲無功。',64,'全唐诗/poet.song.133000.json','["赫赫炎威日正中，冰紈笛簟欲無功。", "一心願伴沙頭鷺，百計難呼木杪風。", "纖手削瓜刀似水，小罌分酒盞如空。", "洗心幸有高樓月，少待寒光出海東。"]'),
('8a16df4e-0a34-4427-9636-dfc08ed7001e','蜻蜓浦夜泊','陸游','宋','宋诗','song-poetry','','[]','風雨忽如秋已深，短篷今夜繫楓林。',64,'全唐诗/poet.song.133000.json','["風雨忽如秋已深，短篷今夜繫楓林。", "溪翁那問市朝事，蔬食不生杯炙心。", "橫截烟波飛健鶻，遠投沙渚落羈禽。", "斯遊誰道傷幽獨，猶有殘鐘伴苦吟。"]'),
('95cad950-e401-43e8-a4b9-3f337ca9ce2e','幽興','陸游','宋','宋诗','song-poetry','','[]','微官那得繫疏慵，幽興渾如社酒濃。',64,'全唐诗/poet.song.133000.json','["微官那得繫疏慵，幽興渾如社酒濃。", "掃盡塵埃無一點，洗空幻翳有千重。", "百年到處俱羈客，萬里從來付短筇。", "身在有餘真妙語，杯羹何地欠秋菘。"]'),
('79a1062d-5284-4f95-9277-a90f8f2e3ed7','避暑近村偶題','陸游','宋','宋诗','song-poetry','','[]','乞得身歸荷聖時，登臨筋力未全衰。',64,'全唐诗/poet.song.133000.json','["乞得身歸荷聖時，登臨筋力未全衰。", "楚祠草合三叉路，隋寺苔侵半折碑。", "孤店不妨乘月宿，扁舟頻爲看山移。", "紅塵冠蓋真堪怕，還我平生白接䍦。"]'),
('52ad28af-e887-4ed9-8bfb-f67735cb390e','南堂夜坐','陸游','宋','宋诗','song-poetry','','[]','老來日月駛，秋令俄更端。',96,'全唐诗/poet.song.133000.json','["老來日月駛，秋令俄更端。", "蟬號晚愈壯，螢火流空園。", "西風吹衣裳，蕭然謝炎官。", "飽食一事無，散髮坐前軒。", "河漢西南流，北斗何闌干。", "坐久光彩變，缺月涌金盆。", "欲睡復躊躇，草棘露已漙。", "徂歲何足道，死生付乾坤。"]'),
('ba297292-f8da-4596-aa39-87c0e66cc0f4','立秋前一夕作','陸游','宋','宋诗','song-poetry','','[]','螢度梧楸徑，鳥鳴蒲葦洲。',48,'全唐诗/poet.song.133000.json','["螢度梧楸徑，鳥鳴蒲葦洲。", "寧知八十老，又見一年秋。", "賀監稱狂客，劉伶贈醉侯。", "吾身會兼此，已矣尚何求。"]'),
('e8b8f2c9-0e0f-4273-91b1-00badd60c85b','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔西遊兩鬢青，即今鏡裏雪千莖。',64,'全唐诗/poet.song.133000.json','["憶昔西遊兩鬢青，即今鏡裏雪千莖。", "峨眉風月猶關念，濯錦鶯花已隔生。", "避暑有時移枕簟，畏人終日閉柴荆。", "此懷恨欠詩千首，且寄秋泉一再行。"]'),
('8a68d89d-d546-4566-a078-e87f72f41ddd','自嘲','陸游','宋','宋诗','song-poetry','','[]','外澤裏常粗，元知似瓠壺。',48,'全唐诗/poet.song.133000.json','["外澤裏常粗，元知似瓠壺。", "仕因無援困，學爲背時孤。", "軒蓋愁城市，風烟落道途。", "它年遊萬里，不必念歸吳。"]'),
('602ac2c5-93e7-4e43-a058-c8990f340d00','夜坐庭中','陸游','宋','宋诗','song-poetry','','[]','大澤秋初到，荒庭夜自明。',48,'全唐诗/poet.song.133000.json','["大澤秋初到，荒庭夜自明。", "風雲生有候，河漢落無聲。", "病得新凉減，詩因少睡成。", "高枝有烏鵲，栖穩若爲驚。"]'),
('2f290d36-a5ad-4aff-a0dc-f7917ac6ca85','養生','陸游','宋','宋诗','song-poetry','','[]','稟賦本不强，四十已遽衰。',168,'全唐诗/poet.song.133000.json','["稟賦本不强，四十已遽衰。", "藥裹不離手，對酒盤無梨。", "豈料今八十，白間猶黑絲。", "咀嚼雖小艱，幸未如牛呞。", "昔雖學養生，所遇少碩師。", "金丹既茫昧，鸞鶴安可期。", "惟有庖丁篇，可信端不疑。", "愛身過拱璧，奉以無缺虧。", "孽不患天作，戚惟憂自詒。", "攣躄豈不苦，害猶在四支。", "二豎伏膏肓，良醫所不治。", "衣巾視寒燠，飲食節飽饑。", "虎兕雖在傍，牙爪何由施。", "老人不妄語，聊賦養生詩。"]'),
('cda69f5e-b2a0-495c-bc37-999fedc3de21','飲酒近村','陸游','宋','宋诗','song-poetry','','[]','放翁睡多少行立，人扶往赴鄰里集。',64,'全唐诗/poet.song.133000.json','["放翁睡多少行立，人扶往赴鄰里集。", "痛飲山花插鬢紅，醉歸棘露霑衣溼。", "紗巾一幅何翩翩，庭中弄影不肯眠。", "莫欺此老今衰甚，曾見高皇狩越年。"]'),
('43d82239-5bf3-475c-af14-c7b1d397bf88','遊山四首  其一','陸游','宋','宋诗','song-poetry','','[]','蕭散湖山路，天教脫馽羈。',48,'全唐诗/poet.song.133000.json','["蕭散湖山路，天教脫馽羈。", "蟬聲入古寺，馬影度荒陂。", "樵唱時傾耳，僧談亦解頤。", "偏門燈火鬧，不敢恨歸遲。"]'),
('9b625ba2-f373-46ef-bc94-3833e708140e','遊山四首  其二','陸游','宋','宋诗','song-poetry','','[]','久客喜歸舍，况逢秋氣新。',48,'全唐诗/poet.song.133000.json','["久客喜歸舍，况逢秋氣新。", "聊乘行艓子，閑覓住庵人。", "道士青芒屨，高僧白氎巾。", "更須苔井水，一爲濯京塵。"]'),
('509eb267-4819-4278-b686-a9847b483725','遊山四首  其三','陸游','宋','宋诗','song-poetry','','[]','病退行猶倦，山坡每少休。',48,'全唐诗/poet.song.133000.json','["病退行猶倦，山坡每少休。", "高枝聞鵲語，淺瀨見魚遊。", "偶有堪乘興，元無可遣愁。", "悠然又終日，爭路有歸牛。"]'),
('0e6e2aab-603d-4822-90c1-1eccdc3f1e44','遊山四首  其四','陸游','宋','宋诗','song-poetry','','[]','古寺不來久，入門空嘆嗟。',48,'全唐诗/poet.song.133000.json','["古寺不來久，入門空嘆嗟。", "僧亡猶見塔，樹老已無花。", "世事雖難料，吾生固有涯。", "殷勤一梳月，十里伴還家。"]'),
('91d10b05-0116-4725-a371-e0279729d28f','聞蛩二首  其一','陸游','宋','宋诗','song-poetry','','[]','蟬聲未斷已蛩鳴，徂歲崢嶸得我驚。',32,'全唐诗/poet.song.133000.json','["蟬聲未斷已蛩鳴，徂歲崢嶸得我驚。", "八十光陰猶幾許，勉思忠敬盡餘生。"]'),
('2e88477c-b2dc-4238-8447-2a6850047ed6','聞蛩二首  其二','陸游','宋','宋诗','song-poetry','','[]','稽首周公萬世師，小儒命薄不同時。',32,'全唐诗/poet.song.133000.json','["稽首周公萬世師，小儒命薄不同時。", "秋蟲却是生無憾，名在豳人七月詩。"]'),
('ba3f4f27-2a54-4979-96e8-57e782502fee','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','束髮初學詩，妄意薄風雅。',72,'全唐诗/poet.song.133000.json','["束髮初學詩，妄意薄風雅。", "中年困憂患，聊欲希屈賈。", "寧知竟鹵莽，所得纔土苴。", "入海殊未深，珠璣不盈把。", "老來似少進，遇興頗傾瀉。", "猶能起後生，黄河吞鉅野。"]'),
('3008ac37-f600-49ce-b994-c3cac1362608','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','我昔西遊邊，萬里持一劍。',72,'全唐诗/poet.song.133000.json','["我昔西遊邊，萬里持一劍。", "風餐不自恤，露宿未嘗厭。", "棧危餘漢燒，山斷有秦塹。", "敢誇胡羊美，但懷巴酒釅。", "回首四十年，遠遊每關念。", "秋風跨蹇驢，尚喜道傍店。"]'),
('a6b43a5a-e074-4a2f-9fc7-ad0b2ed870cd','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','周南太史公，道家蓬萊山。',72,'全唐诗/poet.song.133000.json','["周南太史公，道家蓬萊山。", "塵凡不可料，亦復居其間。", "屢奏乞骸骨，寬恩許投閑。", "羽衣碧玉簡，尚綴僊官班。", "黄精掃白髮，面有孺子顔。", "簡寂吾家舊，飄然時往還。"]'),
('6a36962c-207d-47be-8ef7-52ff06ccc83b','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','我行剡中路，茆店連溪橋。',72,'全唐诗/poet.song.133000.json','["我行剡中路，茆店連溪橋。", "驢弱我亦饑，解鞍雨蕭蕭。", "投床得小憩，炊黍烹藥苗。", "舉手謝主人，去路盤山腰。", "沃洲在何許，秋葉紅未凋。", "遊僧不可逢，聊須問歸樵。"]'),
('980a9d9e-df92-4873-96bf-c84fb2db161c','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','怕事真駑痾，老作入都夢。',84,'全唐诗/poet.song.133000.json','["怕事真駑痾，老作入都夢。", "頭顱今何似，尚復堪自送。", "聯裾預登瀛，策馬從上雍。", "年衰當亟去，恩大容力控。", "雖言解朝籍，尚予侍祠俸。", "明年即八十，日月難把弄。", "著書則已矣，努力謀社甕。"]'),
('2f7ccd15-3ca0-419e-85ef-0004f61793f2','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','吾才如蹇人，何許逐奔馬。',72,'全唐诗/poet.song.133000.json','["吾才如蹇人，何許逐奔馬。", "吾文如醜女，惟藉粉黛假。", "向來已歸休，畢志向林下。", "塊然一愚公，初不繫用捨。", "國恩定難報，衰涕時一灑。", "人本不勝天，豈復論眾寡。"]'),
('b295d376-30a2-40ae-ba46-d63e7c23d814','入秋遊山賦詩略無闕日戲作五字七首識之以野店山橋送馬蹄爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','驢病比已損，秋風輕四蹄。',72,'全唐诗/poet.song.133000.json','["驢病比已損，秋風輕四蹄。", "朝遊支遁寺，暮涉干吉溪。", "青嶂環孤村，綠波溢橫堤。", "吾行本無定，所至窮攀躋。", "細推亦何樂，正類好鍛嵇。", "自今當務本，春蕪飽鉏犁。"]'),
('80a9a3bc-5a6d-4f0f-9932-db8fddf7d8a4','村居四首  其一','陸游','宋','宋诗','song-poetry','','[]','白首歸來亦灌畦，任教鄰里笑栖栖。',64,'全唐诗/poet.song.133000.json','["白首歸來亦灌畦，任教鄰里笑栖栖。", "道心寧感兩雌雉，生計惟存五母雞。", "不恨閑門可羅爵，本知窮巷自多泥。", "暮聞鼓角猶人境，更欲移家入剡溪。"]'),
('81d2dfd1-b16a-440b-ab66-e1bee1e021a6','村居四首  其二','陸游','宋','宋诗','song-poetry','','[]','游子從來念故鄉，我歸仍得值豐穰。',64,'全唐诗/poet.song.133000.json','["游子從來念故鄉，我歸仍得值豐穰。", "粗繒裁製襜褕暖，肥羜烹調餺飥香。", "對客不妨依几杖，呼兒時與話耕桑。", "却慚未解真齊物，猶揀山村靜處藏。"]'),
('64391630-01ed-474b-a9f1-ad54b2cd4775','村居四首  其三','陸游','宋','宋诗','song-poetry','','[]','青藜杖出氛埃外，白版扉開水竹邊。',64,'全唐诗/poet.song.133000.json','["青藜杖出氛埃外，白版扉開水竹邊。", "造物與閑仍與健，鄉人知老不知年。", "齋居每袖持螯手，妄想寧流見麴涎。", "昨夜小庭風露冷，菊花消息已先傳。"]'),
('ce1f922a-b43a-432c-bc27-067bea93271e','村居四首  其四','陸游','宋','宋诗','song-poetry','','[]','石帆山下樂誰如，八尺輕舠萬頃湖。',64,'全唐诗/poet.song.133000.json','["石帆山下樂誰如，八尺輕舠萬頃湖。", "能釀人家分小榼，愛棋道士寄新圖。", "條枚積地樹雞柵，溝港接筒澆芋區。", "父子還家更何事，斷編燈下講唐虞。"]'),
('10366fb4-be09-4c96-be56-5eb0e2cff84e','六藝示子聿','陸游','宋','宋诗','song-poetry','','[]','六藝江河萬古流，吾徒鉆仰死方休。',64,'全唐诗/poet.song.133000.json','["六藝江河萬古流，吾徒鉆仰死方休。", "沛然要似禹行水，卓爾孰如丁解牛。", "老憊簡編猶自力，夜凉膏火漸當謀。", "大門舊業微如線，賴有吾兒共此憂。"]'),
('555208ed-3a3a-48dd-85fb-e3a5d9f8108a','七月十七夜五更起坐至旦','陸游','宋','宋诗','song-poetry','','[]','秋容淡如水，昨暮到江城。',48,'全唐诗/poet.song.133000.json','["秋容淡如水，昨暮到江城。", "世事違高枕，年華入短檠。", "書中固多味，身外盡浮名。", "倚壁方清嘯，蓬窗已送明。"]'),
('4c663b62-6ee6-4de7-b4a5-43b6965b1613','書懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','不饑不寒萬事足，有山有水一生閑。',32,'全唐诗/poet.song.133000.json','["不饑不寒萬事足，有山有水一生閑。", "朱門莫管渠癡絕，自愛茅茨三兩間。"]'),
('bae88403-2c0f-4cac-8d04-a184f5c839cd','書懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','老人舉動須扶掖，跣婢椎奴少得閑。',32,'全唐诗/poet.song.133000.json','["老人舉動須扶掖，跣婢椎奴少得閑。", "從此漸須都畫斷，疋如避難在空山。"]'),
('c23b1133-dcf0-4207-bc6b-0d1704ab14df','書懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','蝸廬自稱野人居，三尺明窗已有餘。',32,'全唐诗/poet.song.133000.json','["蝸廬自稱野人居，三尺明窗已有餘。", "從此要當常省事，時時小葺欲何須。"]'),
('4a990c43-1140-4f23-9cd5-0e6957e94691','書懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','苜蓿堆盤莫笑貧，家園瓜瓠漸輪囷。',32,'全唐诗/poet.song.133000.json','["苜蓿堆盤莫笑貧，家園瓜瓠漸輪囷。", "但令爛熟如蒸鴨，不著鹽醯也自珍。"]'),
('815a0c4d-495b-4d70-bf41-44298f274b4d','湖上秋夜','陸游','宋','宋诗','song-poetry','','[]','湖上山銜落月明，釣筒收罷葉舟橫。',32,'全唐诗/poet.song.133000.json','["湖上山銜落月明，釣筒收罷葉舟橫。", "不知身世在何許，一夜蕭蕭蘆荻聲。"]'),
('a2958b5e-e610-4398-977d-4470dad801b1','書感','陸游','宋','宋诗','song-poetry','','[]','俗學方譁世，遺經寖已微。',48,'全唐诗/poet.song.133000.json','["俗學方譁世，遺經寖已微。", "斯文未云喪，吾道豈其非。", "拔本寧餘力，迷途幸識歸。", "新凉起衰疾，燈火耿郊扉。"]'),
('260a8c4d-12cf-443b-a307-061916cf93a2','示兒','陸游','宋','宋诗','song-poetry','','[]','得道如良賈，深藏要若無。',48,'全唐诗/poet.song.133000.json','["得道如良賈，深藏要若無。", "冶金寧輒躍，韞玉忌輕沽。", "儒術今方裂，吾家學本孤。", "汝曹能念此，努力共枝梧。"]'),
('63a22bc9-b8a1-4003-b655-ad7919f6b1d7','書適二首  其一','陸游','宋','宋诗','song-poetry','','[]','北崦千梢竹，東軒八尺床。',48,'全唐诗/poet.song.133000.json','["北崦千梢竹，東軒八尺床。", "徧行欣老健，熟睡領新凉。", "海石陳書几，陶詩貯藥囊。", "時時一到眼，亦足傲羲皇。"]'),
('4b352b4c-1ee5-42eb-87a8-afb967bd9146','書適二首  其二','陸游','宋','宋诗','song-poetry','','[]','心清絕慾早，才薄去官多。',48,'全唐诗/poet.song.133000.json','["心清絕慾早，才薄去官多。", "月下時閑釣，雲邊每浩歌。", "野堂青草覆，山市白驢過。", "也有成功處，新降百萬魔。"]'),
('3bb5c344-1822-4007-a1ae-be31d9cf46c6','放慵','陸游','宋','宋诗','song-poetry','','[]','往者耕仍養，中間仕易農。',48,'全唐诗/poet.song.133000.json','["往者耕仍養，中間仕易農。", "屢辭身老病，每荷上矜從。", "進愧門三戟，歸無畝一鍾。", "扶持得良藥，更放幾年慵。"]'),
('c28e42af-dc5d-483c-8909-3c5c4cf8ae68','登臨','陸游','宋','宋诗','song-poetry','','[]','儘道羈懷惡，登臨亦解顔。',48,'全唐诗/poet.song.133000.json','["儘道羈懷惡，登臨亦解顔。", "健嫌山路淺，狂恨酒尊慳。", "親友多疏索，漁樵自往還。", "有詩仍懶記，零落水雲間。"]'),
('123942ad-cc48-41a1-8a47-df74c166ad0d','寓嘆','陸游','宋','宋诗','song-poetry','','[]','有位方憂失，無家豈念歸。',48,'全唐诗/poet.song.133000.json','["有位方憂失，無家豈念歸。", "賢愚竟誰得，今昨兩皆非。", "世事無長算，人情忽駭機。", "細思如意處，惟有釣魚磯。"]'),
('a8cde7ce-8885-466a-bd25-c869affc98ae','居家','陸游','宋','宋诗','song-poetry','','[]','爲吏心雖懶，居家力尚餘。',48,'全唐诗/poet.song.133000.json','["爲吏心雖懶，居家力尚餘。", "刈茅支屋漏，裁棘補籬疏。", "就井磨樵斧，持錢鍛藥鉏。", "毋勞嘆徒步，野鶴豈堪車。"]'),
('debf2cb8-595b-4d20-9a9a-0c2c703a48df','舟中作','陸游','宋','宋诗','song-poetry','','[]','野老元無事，乘閑偶一來。',48,'全唐诗/poet.song.133000.json','["野老元無事，乘閑偶一來。", "微風市樓笛，落日寺街槐。", "梨大圍三寸，鱸肥疊四腮。", "鄰船不識面，呼與共銜杯。"]'),
('a144cd65-3626-48d2-889c-5dd3afabea58','筑舍','陸游','宋','宋诗','song-poetry','','[]','筑舍水雲鄉，蕭然似凈坊。',48,'全唐诗/poet.song.133000.json','["筑舍水雲鄉，蕭然似凈坊。", "粥鐺菰米滑，羹釜藥苗香。", "素壁圖嵩華，明窗讀老莊。", "與人元淡淡，不是故相忘。"]'),
('5326a71d-b17e-4346-bbe8-ee1211b59a10','雜感五首  其一','陸游','宋','宋诗','song-poetry','','[]','孔欲居九夷，老亦適流沙。',48,'全唐诗/poet.song.133000.json','["孔欲居九夷，老亦適流沙。", "忠信之所覃，豈間夷與華。", "况我州閭間，相視等一家。", "老稚各自力，勉蹈思無邪。"]'),
('92cfdddc-b7e5-4969-b2fe-cfef52255e07','雜感五首  其二','陸游','宋','宋诗','song-poetry','','[]','十月可釀酒，六月可作醬。',48,'全唐诗/poet.song.133000.json','["十月可釀酒，六月可作醬。", "兒曹念乃翁，左右日供養。", "比鄰有老疾，亦復致一餉。", "老老以及人，此義古所尚。"]'),
('f7f6eee6-602b-42e1-8f2e-ed7e5a8a9e96','雜感五首  其三','陸游','宋','宋诗','song-poetry','','[]','肉食養老人，古雖有是說。',48,'全唐诗/poet.song.133000.json','["肉食養老人，古雖有是說。", "修身以待終，何至陷饕餮。", "晨烹山蔬美，午漱石泉潔。", "豈役七尺軀，事此膚寸舌。"]'),
('3dcd6125-9188-4de7-a3dd-ba9b4e762e14','雜感五首  其四','陸游','宋','宋诗','song-poetry','','[]','一氣不遽變，雨霽皆有符。',48,'全唐诗/poet.song.133000.json','["一氣不遽變，雨霽皆有符。", "死非一旦至，小疾爲前驅。", "人能謹察之，豈有倉卒虞。", "哀哉不知此，雖悔良難圖。"]'),
('03d0ad4a-fc47-494b-89c2-84a316f1c3e4','雜感五首  其五','陸游','宋','宋诗','song-poetry','','[]','養生孰爲本，元氣不可虧。',48,'全唐诗/poet.song.133000.json','["養生孰爲本，元氣不可虧。", "秋毫失固守，金丹亦奚爲。", "所以古達人，一意堅自持。", "魔鬼雖百萬，敢犯堂堂師。"]'),
('2d2a9df4-61dd-4e1e-9d3c-f92f456038ef','送陳懷叔赴上皋酒官却還都下','陸游','宋','宋诗','song-poetry','','[]','奇才初試發硎刀，疋馬秋風到上皋。',64,'全唐诗/poet.song.133000.json','["奇才初試發硎刀，疋馬秋風到上皋。", "地近雖同三輔重，時平無復五陵豪。", "極知穩步烟霄路，却要微知郡縣勞。", "歸去平津開首燕，吐茵應復忤西曹。"]'),
('e43d37b4-9942-4d8d-9619-d8fed26d8b74','歸三山入秋益凉欣然有賦','陸游','宋','宋诗','song-poetry','','[]','藥物扶持美食眠，鏡湖仍遇素秋天。',64,'全唐诗/poet.song.133000.json','["藥物扶持美食眠，鏡湖仍遇素秋天。", "一年强起歸猶健，百口相看喜欲顛。", "碧瓦朱甍無傑屋，烏篷畫楫有新船。", "道山頂上雖清絕，萬頃烟波始是仙。"]'),
('69e41534-a139-4778-8bc9-26174cb132f2','子聿至湖上待其歸','陸游','宋','宋诗','song-poetry','','[]','舍北犬吠迎歸航，老翁待兒據胡床。',64,'全唐诗/poet.song.133000.json','["舍北犬吠迎歸航，老翁待兒據胡床。", "碧雲忽起欲吞日，黄葉自凋非霣霜。", "十風五雨歲則熟，左飧右粥身其康。", "豈無深谷結茅屋，父子讀易消年光。"]'),
('ea1343a7-c19d-435a-8fc8-8a502aaa1dcb','晚行舍後','陸游','宋','宋诗','song-poetry','','[]','略彴東邊一徑深，杖藜行飯當登臨。',64,'全唐诗/poet.song.133000.json','["略彴東邊一徑深，杖藜行飯當登臨。", "稷山並海出遥碧，禹穴生雲成暮陰。", "殘歲自興遊子感，少年誰解老人心。", "歸來燈火參差夜，倦倚胡床續短吟。"]'),
('2f314bc6-c9da-40ed-82e9-488650470c30','秋夜讀書有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','妄意斯文力弗勝，苦心猶欲付雲仍。',64,'全唐诗/poet.song.133000.json','["妄意斯文力弗勝，苦心猶欲付雲仍。", "數編魯壁家傳學，一盞吳僧夜講燈。", "南犬固應多吠雪，夏蟲那得解知冰。", "但令吾道常無墜，飲水何妨枕曲肱。"]'),
('65ebcf78-7ae0-4cdb-983d-825434bad8d1','秋夜讀書有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','齒髮凋殘志有餘，一編聊復遂吾初。',64,'全唐诗/poet.song.133000.json','["齒髮凋殘志有餘，一編聊復遂吾初。", "老來每恨無同學，夢裏猶曾得異書。", "家世偏憎慕青紫，兒童切莫話龍豬。", "正令世世皆農圃，廉讓何妨化里閭。"]'),
('0f5ff342-9f39-4d1b-8ac6-51a6a3943a58','治圃','陸游','宋','宋诗','song-poetry','','[]','小圃漫經營，栽培抵力耕。',48,'全唐诗/poet.song.133000.json','["小圃漫經營，栽培抵力耕。", "土鬆宜雨點，根稚怯鉏聲。", "紅果方當熟，清陰亦漸成。", "每來常竟日，聊得暢幽情。"]'),
('cc39aaa3-8cde-43c1-bb32-543d53d11c83','村醉','陸游','宋','宋诗','song-poetry','','[]','髮已凋零齒已疏，飽諳成敗更誰如。',64,'全唐诗/poet.song.133000.json','["髮已凋零齒已疏，飽諳成敗更誰如。", "貴人豈得常金屋，丞相那知起草廬。", "久泛江湖知釣術，晚歸壟畝授農書。", "一尊徑就村翁醉，未肯英雄許本初。"]'),
('f220b7e1-b944-4db4-acae-24e35355f25c','病卧','陸游','宋','宋诗','song-poetry','','[]','蕭條風雨又經旬，病卧真成不覿鄰。',64,'全唐诗/poet.song.133000.json','["蕭條風雨又經旬，病卧真成不覿鄰。", "跨馬難酬四方志，耽書空盡百年身。", "碧花引蔓緣疏竹，黄雀呼群啄破囷。", "君見此時風味否，肯辭人笑橐裝貧。"]'),
('0a416415-8b03-42d3-be0b-755d1d4d0cca','書悔','陸游','宋','宋诗','song-poetry','','[]','衣食須耕稼，無端浪出遊。',48,'全唐诗/poet.song.133000.json','["衣食須耕稼，無端浪出遊。", "客途南北雁，世事雨晴鳩。", "蓬轉何時已，灰寒善自謀。", "江湖千萬里，何處欠漁舟。"]'),
('db732179-7645-407e-8c4f-882d597552c1','航海','陸游','宋','宋诗','song-poetry','','[]','我老卧丘園，百事習慵惰。',144,'全唐诗/poet.song.133000.json','["我老卧丘園，百事習慵惰。", "惟有汗漫遊，未語意先可。", "或挂風半帆，或貯雲一舸。", "趁潮亂鳴櫓，過磧細扶柁。", "近輒凌烟海，自笑一何果。", "邂逅得奇觀，造物豈付我。", "古湫石蜿蜒，孤島松磊砢。", "湘竹閟娥祠，淮怪深禹鎖。", "鬼神駭犀炬，天地赫龍火。", "瑰奇窮萬變，鯤鵬尚么麽。", "紛紜旋或忘，追記今亦頗。", "作詩配齊諧，發子笑齒瑳。"]'),
('f6c4260c-5d33-427c-8396-c4e843886e34','黄犢','陸游','宋','宋诗','song-poetry','','[]','賣刀買黄犢，用以事耕稼。',72,'全唐诗/poet.song.133000.json','["賣刀買黄犢，用以事耕稼。", "凄風山北秋，缺月溪西夜。", "小童搢竹枝，相呼聊一跨。", "秋來作欄成，參差出林罅。", "青烟起草積，微火近茅舍。", "未言東作功，此景已可畫。"]'),
('9e41edba-c14d-4f1f-b016-ea392d0ab015','秋夜','陸游','宋','宋诗','song-poetry','','[]','老覺人間歲月遒，愔愔窗戶一燈幽。',64,'全唐诗/poet.song.133000.json','["老覺人間歲月遒，愔愔窗戶一燈幽。", "讀書已廢虛長夜，護塞無期負盛秋。", "病齒何堪食粱肉，殘軀惟念製衣裘。", "重陽卧看登高侶，滿地茱萸只自愁。"]'),
('c2dfeadb-79a5-45a4-ba75-0b4716725677','目昏頗廢觀書以詩記其始時年七十九矣','陸游','宋','宋诗','song-poetry','','[]','少時業詩書，慕古不自量。',144,'全唐诗/poet.song.133000.json','["少時業詩書，慕古不自量。", "晨暮間弦誦，左右紛朱黄。", "積書山崇崇，探義海茫茫。", "同志三四人，辯論略相當。", "落筆輒千言，氣欲吞名場。", "忽焉六十年，綠鬢久已霜。", "食必觀本草，不療病在床。", "今秋又病目，始覺閑味長。", "車馬既不至，亦無書在傍。", "一坐漏十刻，甚倦則倚牆。", "蝴蝶吾前身，華胥吾故鄉。", "童子亦聽睡，不復呼燒香。"]'),
('e49e4de4-5836-4de2-82e9-825fa7b7b641','假山擬宛陵先生體','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','疊石作小山，埋甕成小潭。',48,'全唐诗/poet.song.133000.json','["疊石作小山，埋甕成小潭。", "旁爲負薪徑，中開釣魚庵。", "谷聲應鐘鼓，波影倒松楠。", "借問此何許，恐是廬山南。"]'),
('6ea906bf-cdb0-46d6-8063-e3e7b524f607','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','拒霜慘淡數枝紅，石竹凋零不滿叢。',32,'全唐诗/poet.song.133000.json','["拒霜慘淡數枝紅，石竹凋零不滿叢。", "小蝶一雙來又去，與人都在寂寥中。"]'),
('d7f393e7-46aa-4b3a-87f6-422dbb451e91','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','足力蹣跚少迎客，目視昏短常廢書。',32,'全唐诗/poet.song.133000.json','["足力蹣跚少迎客，目視昏短常廢書。", "賴是門前秋水長，沙鷗未遽與人疏。"]'),
('59739647-d302-4a11-814e-3e1fb3ca9edf','湖上夜歸','陸游','宋','宋诗','song-poetry','','[]','滿鏡新霜奈老何，扁舟日日醉顔酡。',64,'全唐诗/poet.song.133000.json','["滿鏡新霜奈老何，扁舟日日醉顔酡。", "樂如逐兔牽黄犬，快似麾兵卷白波。", "霜近菊花猶未見，雨餘橙子已堪搓。", "湖桑小市人無數，爭看山翁擊檝歌。"]'),
('eb1f0cf2-e6ac-4a32-ba8d-4c997b7b2168','晨起','陸游','宋','宋诗','song-poetry','','[]','戒婢篝衣徹扊扅，呼兒滌硯作隃麋。',32,'全唐诗/poet.song.133000.json','["戒婢篝衣徹扊扅，呼兒滌硯作隃麋。", "須臾開卷東窗下，即是先生無病時。"]'),
('8a4e3eac-4ec2-4b1d-8689-7c834ae3dd0e','飯飽晝卧戲作短歌','陸游','宋','宋诗','song-poetry','','[]','爲農得飯常半菽，出仕固應甘脫粟。',96,'全唐诗/poet.song.133000.json','["爲農得飯常半菽，出仕固應甘脫粟。", "藜羹自美何待糝，况復畏人嘲苜蓿。", "今年還東已八十，視聽雖存鬢先禿。", "安能賣藥謀助道，但有知分堪養福。", "水車轆轆鄰餽魚，社鼓鼕鼕眾分肉。", "可憐老子暫膨脝，午睡窗邊自捫腹。"]'),
('1abafba1-71e2-4592-961b-ce9d839a4151','孤學','陸游','宋','宋诗','song-poetry','','[]','孤學雖違俗，猶爲一腐儒。',48,'全唐诗/poet.song.133000.json','["孤學雖違俗，猶爲一腐儒。", "家貧占力量，夜夢驗工夫。", "正復安三徑，寧忘奏六符。", "殘年知有幾，自怪尚區區。"]'),
('2566912f-bd36-4bd9-b3ac-b530e4ec1ff4','自嘲','陸游','宋','宋诗','song-poetry','','[]','儒生窮事業，老去轉荒唐。',48,'全唐诗/poet.song.133000.json','["儒生窮事業，老去轉荒唐。", "長日中分睡，殘年有底忙。", "書常懶終卷，詩亦少成章。", "忽棄蓬窗去，花前又一觴。"]'),
('78ce0e4e-2194-48d0-8086-af9da42612bb','試筆','陸游','宋','宋诗','song-poetry','','[]','清談數語猶疑過，平地徐行亦慮危。',32,'全唐诗/poet.song.133000.json','["清談數語猶疑過，平地徐行亦慮危。", "酌酒淺深須在我，更衣單複要隨時。"]'),
('c0b670c5-d477-4722-983c-4a18166607c7','秋思三首  其一','陸游','宋','宋诗','song-poetry','','[]','烏柏微丹菊漸開，天高風送雁聲哀。',32,'全唐诗/poet.song.133000.json','["烏柏微丹菊漸開，天高風送雁聲哀。", "詩情也似并刀快，翦得秋光入卷來。"]'),
('c64f5b98-469f-428c-95a7-9b67151aeae2','秋思三首  其二','陸游','宋','宋诗','song-poetry','','[]','水際柴門一扇開，白頭羸病亦堪哀。',32,'全唐诗/poet.song.133000.json','["水際柴門一扇開，白頭羸病亦堪哀。", "阿誰得似桄榔杖，肯爲閑人萬里來。"]'),
('e268dfbe-d7c6-48ef-b1a4-f5bee0dce3ea','秋思三首  其三','陸游','宋','宋诗','song-poetry','','[]','蒼顔莫怪少曾開，觸目人情但可哀。',32,'全唐诗/poet.song.133000.json','["蒼顔莫怪少曾開，觸目人情但可哀。", "死去肯爲浮世戀，此身元自不應來。"]'),
('11422039-6551-4e25-8455-7bff3bc813b3','晨起偶得五字戲題稿後','陸游','宋','宋诗','song-poetry','','[]','推枕悠然起，吾詩忽欲成。',48,'全唐诗/poet.song.133000.json','["推枕悠然起，吾詩忽欲成。", "雖云無義語，猶異不平鳴。", "有得忌輕出，微瑕須細評。", "平生五字句，垂老愧長城。"]'),
('e07a5e6a-f57f-4519-8df9-2660b1144a61','野步','陸游','宋','宋诗','song-poetry','','[]','場圃農功畢，村鄰醉叟多。',48,'全唐诗/poet.song.133000.json','["場圃農功畢，村鄰醉叟多。", "野風吹慘澹，海氣起嵯峨。", "婦女窺籬看，兒童拾穗歌。", "身閑不自樂，如此暮年何。"]'),
('2ebf45e3-49e3-46d1-a78c-6c4f1cd2a49f','喜晴','陸游','宋','宋诗','song-poetry','','[]','一夜霜風掃積陰，簷間喚起有鳴禽。',64,'全唐诗/poet.song.133000.json','["一夜霜風掃積陰，簷間喚起有鳴禽。", "滿窗零亂梧楸影，鄰巷蕭條雞犬音。", "文史漸宜精討閱，湖山仍得飽登臨。", "園丁也解娛翁意，藝果移花已滿林。"]'),
('f415604a-0820-42a5-aedc-49121cda3982','自箴','陸游','宋','宋诗','song-poetry','','[]','带寬非復昔年腰，頰上餘丹日日消。',32,'全唐诗/poet.song.133000.json','["带寬非復昔年腰，頰上餘丹日日消。", "切勿更爲兒戲事，解猿放鶴各消摇。"]'),
('cef7d5f7-41de-49e5-83d0-254e489d3e5a','自喜','陸游','宋','宋诗','song-poetry','','[]','身閑僊不遠，食足富何加。',48,'全唐诗/poet.song.133000.json','["身閑僊不遠，食足富何加。", "庭卧長生犢，園開手種花。", "狂歌聲跌宕，醉草筆橫斜。", "八十明年是，衰殘豈復嗟。"]'),
('85d01413-3d6c-4817-9e08-7bb26181400a','自詒二首  其一','陸游','宋','宋诗','song-poetry','','[]','病中看周易，醉後讀離騷。',48,'全唐诗/poet.song.133000.json','["病中看周易，醉後讀離騷。", "不解書驢券，安能問馬曹。", "身隨遊宦困，氣爲屏居豪。", "清旦南堂坐，稽山秋更高。"]'),
('0e31291f-6add-4d6f-8f4e-ba1d0022dc18','自詒二首  其二','陸游','宋','宋诗','song-poetry','','[]','莊語畏如俳，端居要若齋。',48,'全唐诗/poet.song.133000.json','["莊語畏如俳，端居要若齋。", "清虛集心腑，枯槁見形骸。", "自計愚無用，何傷老不諧。", "人生須廣大，勿作井中蛙。"]'),
('4a962c07-7d32-4205-aa56-835c14876fe0','對酒示坐中','陸游','宋','宋诗','song-poetry','','[]','綠橙丹柿鬭時新，一笑聊誇老健身。',64,'全唐诗/poet.song.133000.json','["綠橙丹柿鬭時新，一笑聊誇老健身。", "大度乾坤容縱酒，多情風月伴垂綸。", "初生京洛逢時泰，幼度江淮避虜塵。", "八十年間窮不死，猶能澗底束荆薪。"]'),
('1f60ab11-103e-40fa-acec-e1a345376f49','秋晚衰疾稍平聊識喜懷','陸游','宋','宋诗','song-poetry','','[]','世事紛紛博局中，豈知造物貸衰翁。',64,'全唐诗/poet.song.133000.json','["世事紛紛博局中，豈知造物貸衰翁。", "短筇倚壁知身健，小甑炊粳喜歲豐。", "霜近平郊多雁落，雨頻斷港有船通。", "更餘一事生詩興，烏桕新添數葉紅。"]'),
('89463717-e774-409f-92e5-837084539376','偶出至近村','陸游','宋','宋诗','song-poetry','','[]','神爽無酣寢，身閑有劇棋。',48,'全唐诗/poet.song.133000.json','["神爽無酣寢，身閑有劇棋。", "說詩橫楖栗，賒酒挈鴟夷。", "寺古殘香冷，溪深獨木危。", "往來元信步，不是赴幽期。"]'),
('8f44c182-5677-475a-b099-e4ad208ba112','書宛陵集後','陸游','宋','宋诗','song-poetry','','[]','突過元和作，巍然獨主盟。',48,'全唐诗/poet.song.133000.json','["突過元和作，巍然獨主盟。", "諸家義皆墮，此老話方行。", "趙璧連城價，隋珠照乘明。", "粗能窺梗概，亦足慰平生。"]'),
('ba6cae63-051a-4dd3-82ab-c61891538021','鄉居','陸游','宋','宋诗','song-poetry','','[]','客問鄉居事，久居君自知。',48,'全唐诗/poet.song.133000.json','["客問鄉居事，久居君自知。", "度橋徵士悔，過社旅人悲。", "社散家分肉，農閑眾筑陂。", "牆東新洗竹，我亦補藩籬。"]'),
('4ad50681-ac56-4325-b014-a3d0964928a1','重九無菊有感','陸游','宋','宋诗','song-poetry','','[]','重陽未見一枝菊，它日菊開生我愁。',32,'全唐诗/poet.song.133000.json','["重陽未見一枝菊，它日菊開生我愁。", "高興亭中香滿把，令人北望憶梁州。"]'),
('e0ef3036-b885-4345-bd5e-1e5a3e01fb25','記東村父老言','陸游','宋','宋诗','song-poetry','','[]','原上一縷雲，水面數點雨。',120,'全唐诗/poet.song.133000.json','["原上一縷雲，水面數點雨。", "夾衣己覺冷，秋令遽如許。", "行行適東村，父老可共語。", "披衣出迎客，芋栗旋烹煮。", "自言家近郊，生不識官府。", "甚愛問孝書，請學公勿拒。", "我亦爲欣然，開卷發端緒。", "講說雖淺近，於子或有補。", "耕荒兩黄犢，庇身一茅宇。", "勉讀庶人章，淳風可還古。"]'),
('c1a6dbfa-4f21-4a67-a83e-201451d99052','試筆','陸游','宋','宋诗','song-poetry','','[]','用筆如用人，利鈍烏可常。',96,'全唐诗/poet.song.133000.json','["用筆如用人，利鈍烏可常。", "必欲責其全，無乃廢所長。", "宣城與晉陵，聲價略相當。", "不知今何年，森然集龜堂。", "和墨若瑿黑，搗紙如銀光。", "心手適調一，運此紫毫鋩。", "前却俱稱意，六驥馳康莊。", "聊復取一快，詎必師鍾張。"]'),
('ab4a9775-aa0d-44cf-9ac3-b5446ff20bf5','曠懷','陸游','宋','宋诗','song-poetry','','[]','曠懷何啻等沙鷗，外物相挻劇火牛。',64,'全唐诗/poet.song.133000.json','["曠懷何啻等沙鷗，外物相挻劇火牛。", "若信本心無一事，始知平地起閑愁。", "每逢達士惟長嘯，欲棄浮生尚小留。", "今旦微霜好風日，短筇且領鏡湖秋。"]'),
('3cba1f28-fcdd-4ff1-91ae-87da4c62c84c','夢行小益道中二首  其一','陸游','宋','宋诗','song-poetry','','[]','棧雲零亂馱鈴聲，驛樹輪囷樺燭明。',32,'全唐诗/poet.song.133000.json','["棧雲零亂馱鈴聲，驛樹輪囷樺燭明。", "清夢不知身萬里，只言今夜宿葭萌。"]'),
('3d4dc5d6-226e-4f27-81ef-e7f86153feba','夢行小益道中二首  其二','陸游','宋','宋诗','song-poetry','','[]','櫸柳林邊候吏迎，血塗草棘虎縱橫。',32,'全唐诗/poet.song.133000.json','["櫸柳林邊候吏迎，血塗草棘虎縱橫。", "分明身在朝天驛，惟欠嘉陵江水聲。"]'),
('dd4ef358-28f6-420f-b27b-1dfdeb71813f','秋樹','陸游','宋','宋诗','song-poetry','','[]','秋風一夜吹橋樹，明日來看已非故。',64,'全唐诗/poet.song.133000.json','["秋風一夜吹橋樹，明日來看已非故。", "吳中九月霜尚薄，落葉半隨飛鳥去。", "老人心事感凋零，只欲逢秋醉不醒。", "范寬用意真難解，偏寫丹楓作畫屏。"]'),
('368c461d-bf85-4b35-9180-3211b76ef299','雜感六首  其一','陸游','宋','宋诗','song-poetry','','[]','鶴乘軒車已堪嘆，狐戴髑髏何可親。',32,'全唐诗/poet.song.133000.json','["鶴乘軒車已堪嘆，狐戴髑髏何可親。", "勸君一笑掃除盡，來作人間百歲人。"]'),
('f77f85e7-ddf1-4065-9b4f-54a929ceb907','雜感六首  其二','陸游','宋','宋诗','song-poetry','','[]','讒口安能作禍基，吾曹興廢豈無時。',32,'全唐诗/poet.song.133000.json','["讒口安能作禍基，吾曹興廢豈無時。", "向來何事令公怒，問著渠儂自不知。"]'),
('0e1582f3-0796-4965-b45f-5f964744fd16','雜感六首  其三','陸游','宋','宋诗','song-poetry','','[]','艱危寧度瘦驢嶺，奔走莫隨肥馬塵。',32,'全唐诗/poet.song.133000.json','["艱危寧度瘦驢嶺，奔走莫隨肥馬塵。", "困阨終身元自好，可憐癡子恨無津。"]'),
('c683ce4b-0de6-4c07-9b12-ab3307b9c4e5','雜感六首  其四','陸游','宋','宋诗','song-poetry','','[]','一尊易致蒲萄酒，萬里難逢鸛鵲樓。',32,'全唐诗/poet.song.133000.json','["一尊易致蒲萄酒，萬里難逢鸛鵲樓。", "何日群胡遺種盡，關河形勝得重遊。"]'),
('82d50958-10b3-4b56-a129-597893e38935','雜感六首  其五','陸游','宋','宋诗','song-poetry','','[]','老境睡多行立少，浮生會少別離多。',32,'全唐诗/poet.song.133000.json','["老境睡多行立少，浮生會少別離多。", "安得此身重壯健，一杯朋舊共高歌。"]'),
('eaa0d306-a159-4042-85b5-2bf4a9c55c6e','雜感六首  其六','陸游','宋','宋诗','song-poetry','','[]','苦熱惟憂不復凉，轉頭忽已見清霜。',32,'全唐诗/poet.song.133000.json','["苦熱惟憂不復凉，轉頭忽已見清霜。", "道人若悟無寒暑，墮指流金總道場。"]'),
('e6c6bf1e-e3dd-4241-8abb-65f05526e38e','柳橋秋夜','陸游','宋','宋诗','song-poetry','','[]','帝青萬里月輪孤，掃盡浮雲一點無。',32,'全唐诗/poet.song.133000.json','["帝青萬里月輪孤，掃盡浮雲一點無。", "正是吾廬秋好夜，上橋渾不要人扶。"]'),
('fb4d1a5f-a7d2-4b6e-9e0e-733ba8ecb926','訪隱者不遇','陸游','宋','宋诗','song-poetry','','[]','秋高山色青如染，寒雨霏微時數點。',96,'全唐诗/poet.song.133000.json','["秋高山色青如染，寒雨霏微時數點。", "蘭亭在眼久不到，每對湖山輒懷歉。", "雅聞其下有隱士，漠漠孤烟起松崦。", "獨携拄杖行造之，枳籬數曲柴門掩。", "笛聲尚近人已遯，日啜薄糜終不貶。", "何如小住共一尊，山藜野芋分猿嗛。"]'),
('c651599a-e834-45db-b97a-1ac3abf39a29','蒼檜','陸游','宋','宋诗','song-poetry','','[]','北風捲野天晝晦，雨如弩鏃穿屋背。',64,'全唐诗/poet.song.133000.json','["北風捲野天晝晦，雨如弩鏃穿屋背。", "老夫下床行躡屐，稚子抱書坐持蓋。", "豈無長楸與巨竹，幹折枝摧共顛沛。", "孰能不動安如山，屹立庭前獨蒼檜。"]'),
('5094be8b-1347-4ef5-94b0-8db51aeec0ac','農家歌','陸游','宋','宋诗','song-poetry','','[]','村東買牛犢，舍北作牛屋。',129,'全唐诗/poet.song.133000.json','["村東買牛犢，舍北作牛屋。", "飯牛三更起，夜寐不敢熟。", "茫茫陂水白，纖纖稻秧綠。", "二月鳴搏黍，三月號布穀。", "爲農但力作，瘠鹵變衍沃。", "腰鐮卷黄雲，踏碓舂白玉。", "八月租稅畢，社甕醲如粥。", "老稚相扶携，閭里迭追逐。", "坐令百世後，復睹可封俗。", "君不見朱門玉食烹萬羊，不如農家小甑吳粳香。"]'),
('4980fff4-49d2-4f56-8422-34663cd6a179','君子非好異','陸游','宋','宋诗','song-poetry','','[]','君子非好異，本意亦從眾。',72,'全唐诗/poet.song.133000.json','["君子非好異，本意亦從眾。", "居然迫所愧，難復趨一鬨。", "孟軻遇齊王，夫豈不欲用。", "萬鍾養弟子，乃似以利動。", "惟其有辭受，百世尊道統。", "豈惟聖賢哉，學者固所共。"]'),
('36b8c776-6eb4-4dae-aefa-05161e866ac9','獨登東巖','陸游','宋','宋诗','song-poetry','','[]','早慕功名已絕癡，晚耽筆墨愈無奇。',64,'全唐诗/poet.song.133000.json','["早慕功名已絕癡，晚耽筆墨愈無奇。", "牧羝未乳身先老，化鶴重歸語更悲。", "朋舊在亡成斷夢，山河興廢入孤吹。", "悠然獨倚闌干笑，又過簪萸泛菊時。"]'),
('677a40d3-1a73-41a3-8e9f-9d143cfe404e','灌園','陸游','宋','宋诗','song-poetry','','[]','八十身猶健，生涯學灌園。',48,'全唐诗/poet.song.133000.json','["八十身猶健，生涯學灌園。", "溪風吹短褐，村雨暗衡門。", "眼正魔軍怖，心安疾豎奔。", "午窗無一事，梨棗弄諸孫。"]'),
('a9e05e59-00c1-401f-b3f1-8bf59b28c0bf','晨起','陸游','宋','宋诗','song-poetry','','[]','老尚貪書課，黎明即下床。',48,'全唐诗/poet.song.133000.json','["老尚貪書課，黎明即下床。", "不驚天乍冷，更覺意差强。", "蟾滴初添水，螭爐旋炷香。", "浮生又一日，開卷就窗光。"]'),
('d0c3e4df-27f3-44fb-8328-68ba88829f1b','龜堂','陸游','宋','宋诗','song-poetry','','[]','莫笑龜堂老，殘年所得多。',48,'全唐诗/poet.song.133000.json','["莫笑龜堂老，殘年所得多。", "賦詩傳海估，說法度天魔。", "夭矯竹如意，鱗皴松養和。", "拈來示諸子，無事數相過。"]'),
('0a196211-a2b1-4995-873c-b16385da2812','蜀漢','陸游','宋','宋诗','song-poetry','','[]','蜀漢崎嶇外，江湖莽蒼中。',48,'全唐诗/poet.song.133000.json','["蜀漢崎嶇外，江湖莽蒼中。", "冷官家世事，獨立古人風。", "已老學猶力，久窮詩未工。", "悠悠千載後，此意與誰同。"]'),
('3bcfa235-3d32-4eed-bec8-4671737a98bf','客有言泰山者因思青城舊遊有作','陸游','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','我登青城山，雲雨顧在下。',120,'全唐诗/poet.song.133000.json','["我登青城山，雲雨顧在下。", "月色縞巖谷，欲睡不忍捨。", "明朝下半嶺，頗怪哀湍瀉。", "山麓雲未歸，平地泥沒踝。", "乃知宿處高，所恨到者寡。", "有客談泰山，昔嘗宿石室。", "夜分林采變，暘谷看浴日。", "九州皆片塵，盛夏猶慘栗。", "我聞思一往，安得飛僊術。", "但願齊魯平，東封扈清蹕。"]'),
('bec7a581-5b68-428a-98c3-6229b2078985','遊近村','陸游','宋','宋诗','song-poetry','','[]','度塹穿林脚愈輕，憑高望遠眼猶明。',64,'全唐诗/poet.song.133000.json','["度塹穿林脚愈輕，憑高望遠眼猶明。", "霜凋老樹寒無色，風掠枯荷颯有聲。", "泥淺不侵雙草屨，身閑常對一棋枰。", "茆簷蔬飯歸來晚，已發城頭長短更。"]'),
('e32fdb92-26fc-4fab-b6a8-32e2898dfff7','疏雨','陸游','宋','宋诗','song-poetry','','[]','簷間秋雨時一滴，絕似漢嘉方響泉。',32,'全唐诗/poet.song.133000.json','["簷間秋雨時一滴，絕似漢嘉方響泉。", "不聽此聲三十載，夢回搔首一凄然。"]'),
('0c4cb530-4e27-49e5-96bd-6824707609d5','秋曉','陸游','宋','宋诗','song-poetry','','[]','菅席多年敗見經，布衾木枕伴殘更。',64,'全唐诗/poet.song.133000.json','["菅席多年敗見經，布衾木枕伴殘更。", "嗈嗈天際雁初度，喔喔舍傍雞亂鳴。", "貸米未回愁竈冷，讀書有課待窗明。", "一秋最恨空階雨，滴破羈懷是此聲。"]'),
('331fdde6-a626-45ce-9369-404b95cead89','癸亥初冬作','陸游','宋','宋诗','song-poetry','','[]','開歲忽八十，古來應更稀。',48,'全唐诗/poet.song.133000.json','["開歲忽八十，古來應更稀。", "我存人盡死，今是昨皆非。", "愛酒陶元亮，還鄉丁令威。", "目前尋故物，惟有釣魚磯。"]'),
('2067092a-068f-4cc5-9338-fa4338d08d6e','兀坐久散步野舍','陸游','宋','宋诗','song-poetry','','[]','澒洞風號木，蕭條雨滴階。',48,'全唐诗/poet.song.133000.json','["澒洞風號木，蕭條雨滴階。", "忽思穿兩屐，聊用散孤懷。", "赤脚舂畬粟，平頭拾澗柴。", "先師有遺訓，萬事忌安排。"]'),
('2ae9399e-6285-4f50-958c-ca611f0303c4','法雲寺','陸游','宋','宋诗','song-poetry','','[]','不到法雲久，秋高初一來。',48,'全唐诗/poet.song.133000.json','["不到法雲久，秋高初一來。", "厨供菰白美，池蘸水紅開。", "橋畔逢遊衲，雲邊數過桅。", "同遊恨歸早，珍重約尋梅。"]'),
('cf92a26b-258a-4ac1-a72f-7f85a54c6808','小徑登東山繚行自西北至溪上','陸游','宋','宋诗','song-poetry','','[]','行穿犖确度谽谺，小立風中客袖斜。',64,'全唐诗/poet.song.133000.json','["行穿犖确度谽谺，小立風中客袖斜。", "衰草雙雙點飛蝶，長空一一送栖鴉。", "荻洲薄暮收魚網，茆舍初寒響緯車。", "誰道老人多感慨，未妨尊酒樂年華。"]'),
('2cb83604-66a1-453f-be9f-d2a1de28a566','美睡','陸游','宋','宋诗','song-poetry','','[]','老來胸次掃崢嶸，投枕神安氣亦平。',64,'全唐诗/poet.song.133000.json','["老來胸次掃崢嶸，投枕神安氣亦平。", "漫道布衾如鐵冷，未妨鼻息自雷鳴。", "天高斗柄闌干曉，露下雞塒腷膊聲。", "俗念絕知無起處，夢爲孤鶴過青城。"]'),
('9431ed37-d7cb-4fcb-9a35-9b653ddae214','逆旅','陸游','宋','宋诗','song-poetry','','[]','秋晚南山行，小蹇就店秣。',96,'全唐诗/poet.song.133000.json','["秋晚南山行，小蹇就店秣。", "我亦念少休，無奈市兒聒。", "嗟爾亦坐饑，錙銖苦爭奪。", "其心計亦厭，陷溺無自脫。", "我欲救其本，汝勿謂迂闊。", "要傾江海大，一洗錐刀末。", "人生顧須幾，卒歲惟一褐。", "有地即可耕，何山不堪活。"]'),
('db1c8b27-5edb-4e54-8c6b-6c6be5aab8c0','東園','陸游','宋','宋诗','song-poetry','','[]','今日天霣霜，又見一日晴。',72,'全唐诗/poet.song.133000.json','["今日天霣霜，又見一日晴。", "晴寒病良已，扶杖東園行。", "瓦鼓息我倦，靜聽幽鳥鳴。", "花果四十株，手自培養成。", "疏密無行列，東園蓋强名。", "人看不滿笑，聊用適我情。"]'),
('2c052c3a-bac6-40a6-b4fb-4d51ef5b89b9','雜感四首  其一','陸游','宋','宋诗','song-poetry','','[]','買薪貸粟不曾知，一事無營盡日嬉。',32,'全唐诗/poet.song.133000.json','["買薪貸粟不曾知，一事無營盡日嬉。", "耋老却如童稚日，早眠晏起食無時。"]'),
('2f64edf9-c506-4dcc-a960-43ff3c120725','雜感四首  其二','陸游','宋','宋诗','song-poetry','','[]','古言忍字似而非，獨有癡頑二字奇。',32,'全唐诗/poet.song.133000.json','["古言忍字似而非，獨有癡頑二字奇。", "此是龜堂安樂法，大書銘座更何疑。"]'),
('dd67048a-fe30-4995-b7cb-99a96406000c','雜感四首  其三','陸游','宋','宋诗','song-poetry','','[]','平生所聞宋華子，病忘乃與知道鄰。',32,'全唐诗/poet.song.133000.json','["平生所聞宋華子，病忘乃與知道鄰。", "老夫歷盡世間事，始覺此公真可人。"]'),
('c6e2b8ca-295c-40c3-abc6-3dafe5c10d77','雜感四首  其四','陸游','宋','宋诗','song-poetry','','[]','羲皇一畫開百聖，學者即今誰造微。',32,'全唐诗/poet.song.133000.json','["羲皇一畫開百聖，學者即今誰造微。", "文詞害道第一事，子能去之其庶幾。"]'),
('17a6c667-5d75-4553-9d37-6ca813cc34ab','渡頭','陸游','宋','宋诗','song-poetry','','[]','蒼檜丹楓古渡頭，小橋橫處繫孤舟。',32,'全唐诗/poet.song.133000.json','["蒼檜丹楓古渡頭，小橋橫處繫孤舟。", "范寬只恐今猶在，寫出山陰一片秋。"]'),
('00c16084-aef8-45a2-8bc0-e77d1b3ee9d4','小飲賞菊','陸游','宋','宋诗','song-poetry','','[]','菊得霜乃榮，性與凡草殊。',72,'全唐诗/poet.song.133000.json','["菊得霜乃榮，性與凡草殊。", "我病得霜健，每却稚子扶。", "豈與菊同性，故能老不枯。", "今朝喚父老，采菊陳酒壺。", "舉袖舞翩僊，擊缶歌烏烏。", "秋晚遇佳日，一醉詎可無。"]'),
('b7955d11-88ee-45a7-ad16-a41228c72d3d','與兒輩小集','陸游','宋','宋诗','song-poetry','','[]','老子秋來樂事稠，吳秔新擣酒新篘。',64,'全唐诗/poet.song.133000.json','["老子秋來樂事稠，吳秔新擣酒新篘。", "矮黄不待園官送，小白每煩溪女留。", "頓飽可憐頻夢與，半酣自喜有兒酬。", "不如意事何窮已，且放團欒一笑休。"]'),
('10586cf1-34c6-4056-92af-4f270c8e3b80','舍北晚眺','陸游','宋','宋诗','song-poetry','','[]','平野沉寒日，遠村生暮烟。',48,'全唐诗/poet.song.133000.json','["平野沉寒日，遠村生暮烟。", "離離立紅樹，點點散烏犍。", "暫出不逾歲，告歸仍一廛。", "江湖初見雁，著眼送雲邊。"]'),
('f320aa05-2b23-4176-8726-1875f1184f91','書室獨處欣然有詠','陸游','宋','宋诗','song-poetry','','[]','鑿空學道本無師，歇盡狂心頗自奇。',64,'全唐诗/poet.song.133000.json','["鑿空學道本無師，歇盡狂心頗自奇。", "閑坐始知冬日永，高談未覺耄年衰。", "治棺準備膏肓日，釀酒枝梧雨雪時。", "常笑祖龍癡到底，一生辛苦覓安期。"]'),
('227f2838-74f6-4f6c-8ecf-4067ba80fc41','冬初至法雲','陸游','宋','宋诗','song-poetry','','[]','曉日曈曨露未乾，東中十月始微寒。',64,'全唐诗/poet.song.133000.json','["曉日曈曨露未乾，東中十月始微寒。", "牛閑處處農功畢，米賤家家酒盞寬。", "烟浦白鷗迎鼓枻，漁村紅樹入憑闌。", "歸舟莫恨無人語，手把陶詩側卧看。"]'),
('bbada3a6-5e62-45fb-867f-13d3933eba8c','感憤','陸游','宋','宋诗','song-poetry','','[]','形勝崤潼在，英豪趙魏多。',48,'全唐诗/poet.song.133000.json','["形勝崤潼在，英豪趙魏多。", "精兵連六郡，要地控三河。", "慷慨鴻門會，悲傷易水歌。", "幾人懷此志，送老一漁蓑。"]'),
('91f02e16-baf4-4a37-97f3-6cec2f1adc9a','記老農語','陸游','宋','宋诗','song-poetry','','[]','霜清楓葉照溪赤，風起寒鴉半天黑。',96,'全唐诗/poet.song.133000.json','["霜清楓葉照溪赤，風起寒鴉半天黑。", "魚陂車水人竭作，麥壟翻泥牛盡力。", "碓舂玉粒恰輸租，籃挈黄雞還作貸。", "歸來糠粞常不饜，終歲辛勤亦何得。", "雖然君恩烏可忘，爲農力耕自其職。", "百錢布被可過冬，但願時清無盜賊。"]'),
('a91bfbdc-7ada-4f12-852e-4b47a637a43b','村舍','陸游','宋','宋诗','song-poetry','','[]','剝啄敲村舍，丫叉揖主人。',48,'全唐诗/poet.song.133000.json','["剝啄敲村舍，丫叉揖主人。", "新牆拆龜兆，疏瓦斷魚鱗。", "紅粒炊畬粟，青烟鬰澗薪。", "得床思熟睡，寒犬苦狺狺。"]'),
('b7474b40-9597-4d90-8ea4-6c76992294bb','自述','陸游','宋','宋诗','song-poetry','','[]','偶策青驢出，還將白鶴隨。',48,'全唐诗/poet.song.133000.json','["偶策青驢出，還將白鶴隨。", "鍊丹留日觀，采藥上天池。", "送客清秋棹，留僧靜夜棋。", "從來閑姓字，不遣世人知。"]'),
('54743097-4d24-440e-817f-bd5ec568c4bb','泊舟湖橋酒樓下','陸游','宋','宋诗','song-poetry','','[]','縹緲雲邊罨畫樓，空濛雨外木蘭舟。',32,'全唐诗/poet.song.133000.json','["縹緲雲邊罨畫樓，空濛雨外木蘭舟。", "誰知老子清狂甚，獨占城南十里秋。"]'),
('012b3a7b-1f4a-4e10-963c-7a194b57a8d5','庵中雜書四首  其一','陸游','宋','宋诗','song-poetry','','[]','蒲龕坐久暖如春，紙被無聲白似雲。',32,'全唐诗/poet.song.133000.json','["蒲龕坐久暖如春，紙被無聲白似雲。", "除却放生并施藥，更無一事累天君。"]'),
('a76b0ee0-ece9-4f2a-841f-ac4bb2197bcd','庵中雜書四首  其二','陸游','宋','宋诗','song-poetry','','[]','謀生安用苦區區，豆飯藜羹未遽無。',32,'全唐诗/poet.song.133000.json','["謀生安用苦區區，豆飯藜羹未遽無。", "若使天年猶合活，不妨自有穀於菟。"]'),
('8ccc3fc5-8ae5-48ea-91fb-1c6c8586a43b','庵中雜書四首  其三','陸游','宋','宋诗','song-poetry','','[]','萬物並作吾觀復，眾人皆醉我獨醒。',32,'全唐诗/poet.song.133000.json','["萬物並作吾觀復，眾人皆醉我獨醒。", "走遍世間無著處，閉門鋤菜伴園丁。"]'),
('f9457c25-94cb-4b38-899e-09d928187b93','庵中雜書四首  其四','陸游','宋','宋诗','song-poetry','','[]','茅茨一室有餘樂，轍環四海誰知心。',32,'全唐诗/poet.song.133000.json','["茅茨一室有餘樂，轍環四海誰知心。", "輟耕垅上鴻鵠志，長嘯山中鸞鳳音。"]'),
('daa607dd-5ca1-4d51-83db-5d1531aa5088','連日暴下薾然不支戲作','陸游','宋','宋诗','song-poetry','','[]','老子心如行脚僧，秋風久已辦行縢。',32,'全唐诗/poet.song.133000.json','["老子心如行脚僧，秋風久已辦行縢。", "紙衾夜夜江湖夢，小復遲留待判懲。"]'),
('58015fd1-3009-413b-8284-330d9e0a23da','大風','陸游','宋','宋诗','song-poetry','','[]','風大連三夕，衰翁不出門。',48,'全唐诗/poet.song.133000.json','["風大連三夕，衰翁不出門。", "兒言卷茅屋，奴報徹蘆藩。", "狼藉鴉擠壑，縱橫葉滿園。", "乘除有今旦，紅日上車軒。"]'),
('1f823a76-3628-45b3-8b72-b25c1b2b296f','野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','掃盡紅塵閉是非，舍傍好在舊苔磯。',64,'全唐诗/poet.song.133000.json','["掃盡紅塵閉是非，舍傍好在舊苔磯。", "壺中春色松肪酒，江上秋風槲葉衣。", "一片共知雲偶出，千年誰識鶴重歸。", "勿言野外無供給，雪後連山藥草肥。"]'),
('5227b347-a43b-46df-be97-cf33d804ead4','野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','樓蘭勛業竟悠悠，聊作人間汗漫遊。',64,'全唐诗/poet.song.133000.json','["樓蘭勛業竟悠悠，聊作人間汗漫遊。", "半谷雲霞丹竈熟，一天雷雨劍池秋。", "徜徉藥市經旬醉，問訊巢仙數夕留。", "却過故廬應一嘆，岸邊猶繫采菱舟。"]'),
('6beaa9cd-82a6-4f35-a397-539dc736982c','若耶村老人','陸游','宋','宋诗','song-poetry','','[]','昔聞若耶村，意象乃物外。',168,'全唐诗/poet.song.133000.json','["昔聞若耶村，意象乃物外。", "皤然阡陌間，來往幾鮐背。", "無論百歲翁，甲子數至再。", "我來親見之，殊未輟耕耒。", "曩事一一言，多聞雜諄誨。", "回頭指丁壯，此是曾玄輩。", "有翁又過我，家有孫五代。", "指呼取斗酒，山果雜細碎。", "顧我使云年，慚縮不能對。", "恭惟大父行，不覺投杖拜。", "養生惟一嗇，此在吾術內。", "翁能信踐之，成就乃爾大。", "我今纔耄及，耳目已憒憒。", "長庚雖餘輝，敢與明月配。"]'),
('9126838d-2d56-42d7-ad0d-873c8709ef4e','霜曉','陸游','宋','宋诗','song-poetry','','[]','霜有連甍白，林無一葉青。',48,'全唐诗/poet.song.133000.json','["霜有連甍白，林無一葉青。", "紙衾圍栗烈，風響送東丁。", "酒盡尊餘滴，灰深火撥星。", "蓬窗了無事，默坐養黄庭。"]'),
('20c6d0b2-7fca-4ff1-a6f9-f4c0215262e3','山澤','陸游','宋','宋诗','song-poetry','','[]','我本山澤人，散誕傲簪裳。',120,'全唐诗/poet.song.133000.json','["我本山澤人，散誕傲簪裳。", "宦遊五十年，天遣還農桑。", "東阡南陌間，吾亦愛吾鄉。", "楚祠坐秋社，隋寺觀夜場。", "醉迷采蒼耳，旅飯炊黄粱。", "自疑太古民，百年樂未央。", "有時閑暇時，頗復誦老莊。", "亦嘗遊岷峨，略聞度世方。", "氣爲東道主，主安客自長。", "却後五百年，見我灞城旁。"]'),
('e768c4f6-86d9-462d-a66d-6c5fce34cb1c','遠遊','陸游','宋','宋诗','song-poetry','','[]','姓字不須通，從來號放翁。',48,'全唐诗/poet.song.133000.json','["姓字不須通，從來號放翁。", "月明登暑雪，木落過秋風。", "處處題僧壁，時時卧釣篷。", "始知侯萬里，未必是英雄。"]'),
('bf4dd6d1-5155-44cd-a2d5-b22199c94141','北窗','陸游','宋','宋诗','song-poetry','','[]','破屋頹垣嘯且歌，一窗隨處寄婆娑。',64,'全唐诗/poet.song.133000.json','["破屋頹垣嘯且歌，一窗隨處寄婆娑。", "閱人每嘆同儕少，遇事方知去日多。", "雲溼沙洲秋下雁，雨來荻浦夜鳴鼉。", "何時更續扁舟興，剩載郫筒醉綠蘿。"]'),
('15b86a13-0216-4072-9032-0050763919d2','醉題','陸游','宋','宋诗','song-poetry','','[]','目光炯炯射車牛，何至隨人作浪愁。',64,'全唐诗/poet.song.133000.json','["目光炯炯射車牛，何至隨人作浪愁。", "身處江湖如富貴，心親魚鳥等朋儔。", "孤帆滅沒三湘曉，野店荒寒二華秋。", "醉墨不容塵土汙，憑君試訪寺家樓。"]'),
('7e51a9e1-bd75-45b6-990a-25948aa86d51','幽居','陸游','宋','宋诗','song-poetry','','[]','練褐藤冠物外裝，下簾留住欲殘香。',64,'全唐诗/poet.song.133000.json','["練褐藤冠物外裝，下簾留住欲殘香。", "瀟湘客過誇漁具，灊皖僧來說藥方。", "詩未遽衰猶跌宕，書雖小退亦軒昂。", "不緣厭靜尋幽事，老去無如白日長。"]'),
('a53ad05c-d82d-4ae9-a1ce-79bf72cf9cd2','連陰欲雪排悶','陸游','宋','宋诗','song-poetry','','[]','先生經旬甑生塵，藜羹不污白氎巾。',64,'全唐诗/poet.song.133000.json','["先生經旬甑生塵，藜羹不污白氎巾。", "魯連敢謂天下士，摩詰要是山中人。", "溪從灘瘦愈刻厲，山自木落增嶙峋。", "雲重惟愁雪欲作，梅花忽報一枝春。"]'),
('81e48437-61f5-4e38-a30e-d665befc25b4','示子聿','陸游','宋','宋诗','song-poetry','','[]','古學尊皇極，淫辭斥異端。',48,'全唐诗/poet.song.133000.json','["古學尊皇極，淫辭斥異端。", "人才如爾少，老健及吾難。", "身退桑榆暖，家貧菽水歡。", "人生粗足耳，衣食不須寬。"]'),
('96757e2a-bd92-401a-a082-2aa45b02a086','項里溪上見珍禽曰溪鵲相隨數十步不去','陸游','宋','宋诗','song-poetry','','[]','涉溪來過東溪老，斷枝槁葉紛如掃。',96,'全唐诗/poet.song.133000.json','["涉溪來過東溪老，斷枝槁葉紛如掃。", "忽逢溪鵲昔未識，言語惺憁羽毛好。", "異哉馴狎若可呼，迹雖甚疏情有餘。", "上穿蒼烟立高樹，下踏白石窺遊魚。", "老夫日日溪頭行，見此不妨雙眼明。", "定交物外從今始，豈獨沙鷗可與盟。"]'),
('8d6ef52c-62d2-44c6-abf6-a8cd8ef43fca','冬夜對書卷有感','陸游','宋','宋诗','song-poetry','','[]','人生如夢終當覺，世事非天孰可憑。',64,'全唐诗/poet.song.133000.json','["人生如夢終當覺，世事非天孰可憑。", "萬卷雖多當具眼，一言惟恕可銘膺。", "所聞要足敵憂患，吾道豈其無廢興。", "白髮蕭蕭年八十，依然父子短檠燈。"]'),
('6e87b299-f085-47ef-8b16-ba008ca55d38','項王祠','陸游','宋','宋诗','song-poetry','','[]','項里溪水聲潺湲，溪上青山峨髻鬟。',128,'全唐诗/poet.song.133000.json','["項里溪水聲潺湲，溪上青山峨髻鬟。", "烟村人語虛市合，石橋日落漁樵還。", "堂上君王凜八尺，大冠如箕熊豹顔。", "筑祠不知始何代，典祀千載誰敢刪。", "肅清亭障息剽奪，掃蕩螟螣囚神奸。", "范增玉斗久已碎，虞姬粧面留餘潸。", "小人平生仰遺烈，近廟欲結茅三間。", "時時長歌拔山曲，醉倒聊慰窮途艱。"]'),
('a49c4e64-727f-4815-9291-f2a629d8c833','入城','陸游','宋','宋诗','song-poetry','','[]','宿凍迷車轍，晨霜縞瓦溝。',48,'全唐诗/poet.song.133000.json','["宿凍迷車轍，晨霜縞瓦溝。", "路長休小驛，風勁透重裘。", "貿貿殘軀健，芒芒去日遒。", "親交喜握手，隨處小遲留。"]'),
('7432ad6e-186e-412a-be2c-5dac92db0239','出城','陸游','宋','宋诗','song-poetry','','[]','病鶴寒彌瘦，孤松老不枯。',48,'全唐诗/poet.song.133000.json','["病鶴寒彌瘦，孤松老不枯。", "非關畏軒冕，本自樂江湖。", "古錦添詩句，羸驂入畫圖。", "兒孫候門久，喚取倒殘壺。"]'),
('372b7651-d951-4866-bc20-8d2d5596bb11','不入城半年矣作短歌遣興','陸游','宋','宋诗','song-poetry','','[]','我居城西南，渺渺水雲鄉。',144,'全唐诗/poet.song.133000.json','["我居城西南，渺渺水雲鄉。", "舟車皆十里，來往道豈長。", "今夏我來時，天風吹荷香。", "再來已孟冬，慘然天霣霜。", "市南兩株柳，葉盡萌已黄。", "乃知多事人，歲晚虛悲傷。", "名藍墮劫火，鞠爲瓦礫場。", "河橋比一新，華表照康莊。", "成壞莽相尋，推理海芒芒。", "疾豎造物兒，吾手扼其吭。", "砥柱天下險，一葦乃可杭。", "養氣倘能全，斯言豈荒唐。"]'),
('2714a66a-39a5-4d2a-a177-a4b1ec9aba03','先大父以元祐乙亥寓居妙明僧舍後百餘年當嘉泰癸亥游復假榻一夕感嘆成詠','陸游','宋','宋诗','song-poetry','','[]','楚公仙去幾秋風，巷陌蕭條舊隱空。',32,'全唐诗/poet.song.133000.json','["楚公仙去幾秋風，巷陌蕭條舊隱空。", "遺老即今無處覓，斷香殘照泪痕中。"]'),
('efe1f1c7-8674-4af2-a9a4-3e91dad11af8','志學','陸游','宋','宋诗','song-poetry','','[]','聖門志學豈能差，山立方當斥百家。',64,'全唐诗/poet.song.133000.json','["聖門志學豈能差，山立方當斥百家。", "早忝授經聞博約，晚羞同俗陷浮華。", "風剺槁面寒無褐，雷轉饑腸飯有沙。", "漫道衰慵貪睡美，五更和夢聽城笳。"]'),
('993058ba-e550-44b0-9eac-afa6991a014a','晚行舍北','陸游','宋','宋诗','song-poetry','','[]','逆旅將歸客，扶衰取次行。',48,'全唐诗/poet.song.133000.json','["逆旅將歸客，扶衰取次行。", "霜濃木葉盡，水落岸痕生。", "鳧雁浮寒浦，牛羊滿晚晴。", "東村隔烟寺，杳杳送鐘聲。"]'),
('ddc7a275-86f5-4147-b316-f4041f0868ef','幽居述事四首  其一','陸游','宋','宋诗','song-poetry','','[]','曾會蘭亭醉墮簪，後身依舊住山陰。',64,'全唐诗/poet.song.133000.json','["曾會蘭亭醉墮簪，後身依舊住山陰。", "琴傳數世漆文斷，鶴養多年丹頂深。", "滌硯灘頭無漬墨，吹簫月下有遺音。", "小詩戲述幽居事，後有高人識此心。"]'),
('cf546c3f-bf30-4d24-9a69-2a46e6e82f1e','幽居述事四首  其二','陸游','宋','宋诗','song-poetry','','[]','頹然掩戶不妨奇，又賦幽居第二詩。',64,'全唐诗/poet.song.133000.json','["頹然掩戶不妨奇，又賦幽居第二詩。", "大藥鼎成令虎守，精思床穩用龜搘。", "壺中自喜乾坤別，局上元知日月遲。", "更就群童閑鬭草，人間何處不兒嬉。"]'),
('a0ecb086-41e3-49f5-8022-56021a50feae','幽居述事四首  其三','陸游','宋','宋诗','song-poetry','','[]','落葉平溝日滿廊，幽居又賦第三章。',64,'全唐诗/poet.song.133000.json','["落葉平溝日滿廊，幽居又賦第三章。", "喜無俗事干靈府，恨不終年住醉鄉。", "上樹榜船雖老健，疏泉移竹亦窮忙。", "山僧欲去還留話，更盡西齋一炷香。"]'),
('faac2e6b-eda8-4973-999f-57a0a2194973','幽居述事四首  其四','陸游','宋','宋诗','song-poetry','','[]','舴艋東歸喜遂初，頻拈枯筆賦幽居。',64,'全唐诗/poet.song.133000.json','["舴艋東歸喜遂初，頻拈枯筆賦幽居。", "細燒柏子供清坐，明點松肪讀道書。", "蒼爪嫩芽開露茗，紅根小把瀹烟蔬。", "年來自許機心盡，頗怪飛鷗自作疏。"]'),
('62ad517a-af40-4165-b1b8-e3d4b40035e8','十一月五夜風雪寒甚燃薪取暖戲作五字','陸游','宋','宋诗','song-poetry','','[]','束薪從澗底，及此不時求。',48,'全唐诗/poet.song.133000.json','["束薪從澗底，及此不時求。", "力比鵝黄酒，功如狐白裘。", "分才具糜粥，餘事暖衾稠。", "復恐成驕惰，三更起飯牛。"]'),
('160268cc-6b3a-4532-b146-17f46f50cce7','魯墟','陸游','宋','宋诗','song-poetry','','[]','魯墟無復壞垣存，偶榜舟來入亂雲。',64,'全唐诗/poet.song.133000.json','["魯墟無復壞垣存，偶榜舟來入亂雲。", "杜曲桑麻猶鬰鬰，桃源雞犬亦欣欣。", "青圍舊墅千峰立，綠引官河一脈分。", "我卜數椽差不遠，得歸何以報吾君。"]'),
('c79ebb97-c245-4023-a770-01a5707c09cb','曉雪二首  其一','陸游','宋','宋诗','song-poetry','','[]','繞湖誰琢玉爲屏，換却南堂萬疊青。',32,'全唐诗/poet.song.133000.json','["繞湖誰琢玉爲屏，換却南堂萬疊青。", "老子醉狂還自笑，持竿畫字滿中庭。"]'),
('42345ab7-d4c4-42bf-b384-4f50029ffaa2','曉雪二首  其二','陸游','宋','宋诗','song-poetry','','[]','觀雪剡溪天下勝，題詩常恨不能奇。',32,'全唐诗/poet.song.133000.json','["觀雪剡溪天下勝，題詩常恨不能奇。", "未應便許凝之語，此興何曾有盡時。"]'),
('06acf718-3937-444c-8366-edd7c5d3a9ed','養生','陸游','宋','宋诗','song-poetry','','[]','西遊曾受養生書，晚愛烟波結草廬。',64,'全唐诗/poet.song.133000.json','["西遊曾受養生書，晚愛烟波結草廬。", "兩眥神光穿夜戶，一頭胎髮入晨梳。", "邀雲作伴遠忘返，與鶴分窠寬有餘。", "占盡世間閑事業，任渠千載笑迂疏。"]'),
('062f52e1-ef18-4600-875e-7c711ec5e13b','夜讀鞏仲至閩中詩有懷其人','陸游','宋','宋诗','song-poetry','','[]','詩思尋常有，偏於客路新。',48,'全唐诗/poet.song.133000.json','["詩思尋常有，偏於客路新。", "能追無盡景，始見不凡人。", "細讀公奇作，都忘我病身。", "蘭亭盡名士，逸少獨清真。"]'),
('7b8e9c2a-9c4b-4c0f-b964-b2c46a795297','獨意','陸游','宋','宋诗','song-poetry','','[]','酒似交情薄，愁隨夜漏長。',48,'全唐诗/poet.song.133000.json','["酒似交情薄，愁隨夜漏長。", "常貧且撐拄，多病不禁當。", "偶讀書終卷，閑臨帖數行。", "翻憐市朝客，擾擾爲誰忙。"]'),
('43008961-f9bf-43f0-bb16-9bc1a66f7291','十一月十三日夜作','陸游','宋','宋诗','song-poetry','','[]','風雪正相乘，蕭然一點燈。',48,'全唐诗/poet.song.133000.json','["風雪正相乘，蕭然一點燈。", "擁爐蒙衲被，就壁倚枯藤。", "火降神方王，河潮腦自凝。", "鄰雞太多事，三唱請晨興。"]'),
('046e0907-d127-48f2-9f17-a9592fa08def','故人趙昌甫久不相聞寄三詩皆傑作也輒以長句奉酬','陸游','宋','宋诗','song-poetry','','[]','海內文章有阿昌，數能著句寄龜堂。',64,'全唐诗/poet.song.133000.json','["海內文章有阿昌，數能著句寄龜堂。", "就令覿面成三倒，未若冥心付兩忘。", "道義極知當負荷，風波那得易禁當。", "相思命駕應無日，且約陶然寓醉鄉。"]'),
('a0a59cb7-0357-4935-bc44-2ceb3f6ff6e0','夢中賦早行','陸游','宋','宋诗','song-poetry','','[]','夜分秉炬治裝赍，千里霜風入馬蹄。',64,'全唐诗/poet.song.133000.json','["夜分秉炬治裝赍，千里霜風入馬蹄。", "擁褐却尋孤驛夢，垂鞭時聽近村雞。", "荒烟漫漫沉殘月，宿莽離離上古堤。", "天色漸分寒更力，道傍沽酒坼官泥。"]'),
('cb66ae56-7ed5-4737-89a6-1699f3527868','兀兀','陸游','宋','宋诗','song-poetry','','[]','兀兀初何有，倀倀不自知。',48,'全唐诗/poet.song.133000.json','["兀兀初何有，倀倀不自知。", "偶然登耄及，便欲數期頤。", "把釣秋風夕，騎驢晚雪時。", "江湖遊已徧，更作灞城期。"]'),
('f89d2c57-5c33-4c28-bbef-681b055c96c2','哺猿','陸游','宋','宋诗','song-poetry','','[]','有書常懶讀，有酒常懶醉。',72,'全唐诗/poet.song.133000.json','["有書常懶讀，有酒常懶醉。", "惟有默坐佳，又以睡爲祟。", "不如捨之起，扶杖來東園。", "摘此幽澗果，哺我高枝猿。", "食果飲清泉，猿計亦何闕。", "但恐夜霜時，腸斷巴山月。"]'),
('ca3e5db9-776d-4e40-9ca1-f2b3693c1be0','與子坦子聿元敏犯寒至東園尋梅','陸游','宋','宋诗','song-poetry','','[]','北風吹人身欲僵，老翁畏冷晝閉房。',96,'全唐诗/poet.song.133000.json','["北風吹人身欲僵，老翁畏冷晝閉房。", "梅花忽報消息動，意氣山立非復常。", "二兒一孫奉此老，瘦藤夭矯凌風霜。", "幽禽白頰忽滿樹，似與我輩爭翱翔。", "溝絕無聲凍地裂，耿耿寒日青無光。", "歸來相視不得語，小榼一寫鵝兒黄。"]'),
('ff0a5352-ec76-4560-ad15-e08785e08a4c','示諸孫','陸游','宋','宋诗','song-poetry','','[]','蝸舍鶉衣老可哀，衰顔時爲汝曹開。',64,'全唐诗/poet.song.133000.json','["蝸舍鶉衣老可哀，衰顔時爲汝曹開。", "朱門莫羨煮羊脚，糲食且安羹芋魁。", "家塾讀書須十紙，山園上樹莫千回。", "但令學業無中絕，秀出安知有後來。"]'),
('323e963d-25b4-4e0e-adc6-620c6dcd61ad','題齋壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','皞皞太平民，堂堂大耋身。',48,'全唐诗/poet.song.133000.json','["皞皞太平民，堂堂大耋身。", "乾坤一旅舍，日月兩車輪。", "蓑貴超三品，蔬甘敵八珍。", "明年真耄矣，爛醉海山春。"]'),
('129859c8-baf8-477c-8d57-0d1caa9afbf5','題齋壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','力穡輸公上，藏書教子孫。',48,'全唐诗/poet.song.133000.json','["力穡輸公上，藏書教子孫。", "追遊屏裘馬，宴集止雞豚。", "寒士邀同學，單門與議婚。", "定知千載後，猶以陸名村。"]'),
('17ab4f7b-a6c3-4d4b-88bf-6718595049fb','雜言示子聿','陸游','宋','宋诗','song-poetry','','[]','福莫大於不材之木，禍莫慘於自躍之金。',118,'全唐诗/poet.song.133000.json','["福莫大於不材之木，禍莫慘於自躍之金。", "鶴生於野兮何有於軒，桐爨則已兮豈慕爲琴。", "古今共戒玉自獻，卷舒要似雲無心。", "廬室但取蔽風雨，衣食過足豈所欽。", "我今餘年忽八十，歸耕幸得安山林。", "逢人雖嘆種種髮，入塾尚憶青青衿。", "吾兒殆可守孤學，相與竭力窮幽深。"]'),
('7e37f661-398a-44e8-8e10-7499d9bc41fd','夜坐聞大風','陸游','宋','宋诗','song-poetry','','[]','天曠穹廬覆，風豪野戰酣。',48,'全唐诗/poet.song.133000.json','["天曠穹廬覆，風豪野戰酣。", "詩成非醉墨，棋罷縱高談。", "奇怪空堪笑，低摧亦未甘。", "東浮雲海去，會載酒千甔。"]'),
('117efdaf-db2b-42b4-9e0c-409944042082','歸老','陸游','宋','宋诗','song-poetry','','[]','歸老何妨駕鹿車，平生風雪慣騎驢。',64,'全唐诗/poet.song.133000.json','["歸老何妨駕鹿車，平生風雪慣騎驢。", "鬢毛白盡猶耽酒，目力衰來轉愛書。", "止足極知于道近，癡頑更喜與人疏。", "著身莫怪無閑處，地肺天台儘有餘。"]'),
('4715baa2-8aee-4b69-85a7-5156d2a45243','懷舊三首  其一','陸游','宋','宋诗','song-poetry','','[]','扇子峽中有隱士，清江一曲照柴荆。',32,'全唐诗/poet.song.133000.json','["扇子峽中有隱士，清江一曲照柴荆。", "當時船急失一見，至今空憶暮猿聲。"]'),
('784a7fbc-4e4a-4de9-b80d-ca806f6ed1b3','懷舊三首  其二','陸游','宋','宋诗','song-poetry','','[]','青城之西溪谷深，道翁巢居獨鼓琴。',32,'全唐诗/poet.song.133000.json','["青城之西溪谷深，道翁巢居獨鼓琴。", "一盃松麨留我宿，夜半虎嘯風生林。"]'),
('6c9010ce-2ab2-4872-8af4-345ba1c184fa','懷舊三首  其三','陸游','宋','宋诗','song-poetry','','[]','剡溪百里徹底清，石闌干裏真人行。',32,'全唐诗/poet.song.133000.json','["剡溪百里徹底清，石闌干裏真人行。", "大丹一粒擲溪水，禽魚草木皆長生。"]'),
('1c1c9475-2394-4434-a27f-0248f587da9c','道室雜詠三首  其一','陸游','宋','宋诗','song-poetry','','[]','舄化雙鳧杖化龍，雲山回首不知重。',64,'全唐诗/poet.song.133000.json','["舄化雙鳧杖化龍，雲山回首不知重。", "藥園夜嘯丹臺月，酒市秋聽紫閣鐘。", "豈但烟霄隨步武，故應冰雪換形容。", "小童開戶驚奇事，野鶴來巢砌下松。"]'),
('1e1653b2-761b-47b1-8867-ca7fe36bd420','道室雜詠三首  其二','陸游','宋','宋诗','song-poetry','','[]','莫怪先生閱事多，人間何處不經過。',64,'全唐诗/poet.song.133000.json','["莫怪先生閱事多，人間何處不經過。", "天山八月霜枯草，暘谷三更日浴波。", "酒熟春風歸掌握，丹成神物共誰何。", "散人本带江湖號，四百年來一釣蓑。"]'),
('a2ba416b-52c7-4800-a906-e2b8fcf99aad','道室雜詠三首  其三','陸游','宋','宋诗','song-poetry','','[]','身是秋風一斷蓬，何曾住處限西東。',64,'全唐诗/poet.song.133000.json','["身是秋風一斷蓬，何曾住處限西東。", "棋枰窗下時聞雹，丹竈巖間夜吐虹。", "采藥不辭千里去，釣魚曾破十年功。", "白頭始悟頤生妙，盡在黄庭兩卷中。"]'),
('4126376e-8798-4149-b9a8-05a8f96fa248','偶與客飲客去戲作','陸游','宋','宋诗','song-poetry','','[]','多泥窮巷破茆屋，人不堪憂心自足。',98,'全唐诗/poet.song.133000.json','["多泥窮巷破茆屋，人不堪憂心自足。", "有時負日向門前，手把南華日中讀。", "若教開門與客游，擾擾依前懷百憂。", "平生自計亦已熟，惟有釣魚湖水頭。", "舊聞仲長子光可與友，瘖不能言但耽酒。", "安得此友常過門，一語不交傾數斗。"]'),
('1f4ac27c-f3db-4083-aa4a-38fbbc3e26ee','故里','陸游','宋','宋诗','song-poetry','','[]','故里淳風比結繩，歸耕况遇歲豐登。',64,'全唐诗/poet.song.133000.json','["故里淳風比結繩，歸耕况遇歲豐登。", "已侵鐘漏行安往，略有園廬退可憑。", "萬事寧容愧天地，一心常若蹈淵冰。", "區區僻見君無怪，人固終身有不能。"]'),
('875e6504-dfee-4990-a5b0-89ce3901d128','齲齒','陸游','宋','宋诗','song-poetry','','[]','人生天地間，本非金石堅。',96,'全唐诗/poet.song.133000.json','["人生天地間，本非金石堅。", "况復歷歲久，蠹壞無復全。", "齲齒雖小疾，頗解妨食眠。", "昨暮作尤劇，頰輔相鈎聯。", "欲起懶衣裳，欲睡目瞭然。", "恨不棄殘骸，蛻去如蛇蟬。", "或當學金丹，揮手凌雲烟。", "逢師定悠悠，丹成在何年。"]'),
('54d76782-c0c4-4f90-9563-7e6e5b2fad2f','冬夜','陸游','宋','宋诗','song-poetry','','[]','悠悠孤夢伴餘酲，窗下寒燈黮闇明。',64,'全唐诗/poet.song.133000.json','["悠悠孤夢伴餘酲，窗下寒燈黮闇明。", "雪意欲成風正惡，漁舟忽過雁群鳴。", "志衰但有徂年感，身沒應無後世名。", "猶幸耄期身粗健，天公元不負書生。"]'),
('d422812d-c0e5-4b96-a29a-4e8235f624e3','枕上','陸游','宋','宋诗','song-poetry','','[]','鐘鼎初何有，山林亦足雄。',48,'全唐诗/poet.song.133000.json','["鐘鼎初何有，山林亦足雄。", "行思絕大幕，歸但醉新豐。", "雁過荒寒外，燈殘寂寞中。", "蒼顔無鏡對，那覺是衰翁。"]'),
('352313b1-b276-4777-814a-38dc0c5c2dd7','寒暑','陸游','宋','宋诗','song-poetry','','[]','寒暑侵陵日夜衰，坐令齒髮不支持。',64,'全唐诗/poet.song.133000.json','["寒暑侵陵日夜衰，坐令齒髮不支持。", "愛憎徇物去忘反，神氣養形誰復知。", "布帔九條晨入靜，柏床五尺夜精思。", "舊交勿恨江湖別，雲海神山會有期。"]'),
('8f177daa-c880-4e51-bd19-03b0dc0180b5','長溪東山容老索月谷幽賞詩二首 月谷','陸游','宋','宋诗','song-poetry','','[]','人間底處無明月，只看青山爲發揮。',32,'全唐诗/poet.song.133000.json','["人間底處無明月，只看青山爲發揮。", "林裏枝寒無鵲立，水邊路白有僧歸。"]'),
('a10b0a83-e856-4172-898c-6b1a6f807d8a','長溪東山容老索月谷幽賞詩二首 幽賞','陸游','宋','宋诗','song-poetry','','[]','清泉白石君家物，美竹名花可旋移。',32,'全唐诗/poet.song.133000.json','["清泉白石君家物，美竹名花可旋移。", "幽賞定知隨處榜，更須時展放翁詩。"]'),
('9a53d962-23da-481a-9229-21aee9a1b90b','梅','陸游','宋','宋诗','song-poetry','','[]','若耶溪頭春意慳，梅花獨秀愁空山。',64,'全唐诗/poet.song.133000.json','["若耶溪頭春意慳，梅花獨秀愁空山。", "逢時决非桃李輩，得道自保冰雪顔。", "僊去要令天下惜，折來聊伴放翁閑。", "人中商略誰堪比，千載夷齊伯仲間。"]'),
('84ee4e4b-732a-4652-ac6d-bc2393e42bfc','歲晚幽興四首  其一','陸游','宋','宋诗','song-poetry','','[]','梅出疏籬柳拂池，流年已迫早春時。',64,'全唐诗/poet.song.133000.json','["梅出疏籬柳拂池，流年已迫早春時。", "壯心卓犖猶欺酒，老業呻吟未廢詩。", "眼暗觀書如棘瀝，齒疏嘬飯似牛呞。", "風爐欲試蒼鷹爪，自向林間拾墮枝。"]'),
('077718dc-2413-44cd-a47b-328612a68747','歲晚幽興四首  其二','陸游','宋','宋诗','song-poetry','','[]','殘年欲遂迫期頤，追數朋儔死已遲。',64,'全唐诗/poet.song.133000.json','["殘年欲遂迫期頤，追數朋儔死已遲。", "卜冢治棺輸我快，染鬚種齒笑人癡。", "野梅墮地草生後，街柳拂鞍冰泮時。", "滿眼雲山不須買，剩傾新釀賦新詩。"]'),
('64aa7442-e778-4d04-a3ad-41a74c524084','歲晚幽興四首  其三','陸游','宋','宋诗','song-poetry','','[]','萬里風波行路難，君恩尚許綴祠官。',64,'全唐诗/poet.song.133000.json','["萬里風波行路難，君恩尚許綴祠官。", "中庭鬰鬰藥苗長，絕壁颼颼松吹寒。", "泥巷有人尋杜甫，雪廬無吏問袁安。", "清晨對鏡增幽致，龜屋新裁二寸冠。"]'),
('c4509767-9635-4cf2-afd5-52204b703842','歲晚幽興四首  其四','陸游','宋','宋诗','song-poetry','','[]','短鬢元知不久青，况開九帙數餘齡。',64,'全唐诗/poet.song.133000.json','["短鬢元知不久青，况開九帙數餘齡。", "全家共保一忍字，累世相傳三住銘。", "時泛孤舟過梅市，却穿雙屩上蘭亭。", "擁爐莫恨無僧在，滿院松風要細聽。"]'),
('9cada7a7-7332-478c-a030-ce6ed8204cbb','寄題胡基仲故居','陸游','宋','宋诗','song-poetry','','[]','憶昔公來一束書，蕭然不復畜僮奴。',64,'全唐诗/poet.song.133000.json','["憶昔公來一束書，蕭然不復畜僮奴。", "浮雲每嘆成蒼狗，空谷誰能縶白駒。", "才氣沙塵埋巨闕，文章林壑吼於菟。", "旅墳三尺雲門寺，又見離離長綠蕪。"]'),
('ce50773f-425c-4c47-af69-94eb0941801d','雪夜','陸游','宋','宋诗','song-poetry','','[]','雪聲如飛沙，風聲如翻濤。',120,'全唐诗/poet.song.133000.json','["雪聲如飛沙，風聲如翻濤。", "三更天地闇，雪急風愈豪。", "頗疑虛空中，鬼神戰方鏖。", "勝負要一决，利兵未肯櫜。", "我如墮重圍，百計無由逃。", "僵縮不能寐，坐起擁故袍。", "自嘆老益貧，庭草常不薅。", "惟酒不憚費，貸券如山高。", "園蔬甘且柔，味不減豚羔。", "醉此風雪夕，聊慰抱甕勞。"]'),
('89384d2a-2a6f-45e1-936e-c179b887c7dc','聽雪爲客置茶果','陸游','宋','宋诗','song-poetry','','[]','病齒已兩旬，日夜事醫藥。',72,'全唐诗/poet.song.133000.json','["病齒已兩旬，日夜事醫藥。", "對食不能舉，况復議杯酌。", "平生外形骸，常恐墮貪著。", "時時鄰曲來，尚不廢笑謔。", "青燈耿窗戶，設茗聽雪落。", "不飣栗與梨，猶能烹鴨脚。"]'),
('c25a6f88-4a6e-4f60-bd08-7f972a2c6051','獨夜','陸游','宋','宋诗','song-poetry','','[]','燈花寒自結，雪片夜方深。',48,'全唐诗/poet.song.133000.json','["燈花寒自結，雪片夜方深。", "瘦影參危坐，清愁入苦吟。", "江湖身汗漫，藥石病侵尋。", "朋舊凋零盡，何人識此心。"]'),
('f70122a4-5034-48c1-8dcd-0469c6111a23','寄題王才臣山居','陸游','宋','宋诗','song-poetry','','[]','王子自少無他娛，求佳山林結草廬。',64,'全唐诗/poet.song.133000.json','["王子自少無他娛，求佳山林結草廬。", "頭童齒豁已衰矣，衣弊屢空常晏如。", "出遊耻懷禰衡刺，歸卧盡讀倚相書。", "它日叩門傾白墮，要看著句到黄初。"]'),
('27d92595-41e8-468d-a5cc-509bc1e76974','夜賦','陸游','宋','宋诗','song-poetry','','[]','練色亭皋月，江聲木杪風。',48,'全唐诗/poet.song.133000.json','["練色亭皋月，江聲木杪風。", "開書燈煜煜，傳漏鼓鼕鼕。", "流落諸生老，呻吟四壁空。", "生涯君勿笑，淡話有兒同。"]'),
('e6ab2a17-53ab-4f95-8fed-9b89d29ee66c','雪後二首  其一','陸游','宋','宋诗','song-poetry','','[]','雪後晴初快，春前日漸長。',48,'全唐诗/poet.song.133000.json','["雪後晴初快，春前日漸長。", "菊根萌已動，梅藟意先香。", "禽語驚幽枕，冰消漲野塘。", "衰殘難出戶，不是懶衣裳。"]'),
('8fd66ff5-d148-478c-8839-e3d91ef6d71e','雪後二首  其二','陸游','宋','宋诗','song-poetry','','[]','冰開地沮洳，雲破日曈曨。',48,'全唐诗/poet.song.133000.json','["冰開地沮洳，雲破日曈曨。", "鴻入青冥際，草生殘燒中。", "方欣畢公稅，已復始農功。", "稻壟牛行處，泥翻夕照紅。"]'),
('9497e6a0-62bf-4b2d-9c01-9fa75f413dea','寒夜讀書','陸游','宋','宋诗','song-poetry','','[]','老去無他嗜，書中有獨欣。',48,'全唐诗/poet.song.133000.json','["老去無他嗜，書中有獨欣。", "月窗雞喔喔，霜野犬狺狺。", "雖嘆吾何適，猶尊昔所聞。", "從今倘未死，一日亦當勤。"]'),
('01169790-e790-4a20-977d-e81fe74069f5','對食戲作六首  其一','陸游','宋','宋诗','song-poetry','','[]','霜餘蔬甲淡中甜，春近靈苗嫩不蘞。',32,'全唐诗/poet.song.133000.json','["霜餘蔬甲淡中甜，春近靈苗嫩不蘞。", "采掇歸來便堪煮，半銖鹽酪不須添。"]'),
('2958a7a5-54f9-4c78-9952-18e9b81a1c8c','對食戲作六首  其二','陸游','宋','宋诗','song-poetry','','[]','白鹽赤米了朝餔，拗項何妨煮瓠壺。',32,'全唐诗/poet.song.133000.json','["白鹽赤米了朝餔，拗項何妨煮瓠壺。", "一種是貧吾尚可，鄰家稗飯亦常無。"]'),
('552687d1-5976-4d30-afaf-e497a370ec18','對食戲作六首  其三','陸游','宋','宋诗','song-poetry','','[]','春前臘後物華催，時伴兒曹把酒杯。',32,'全唐诗/poet.song.133000.json','["春前臘後物華催，時伴兒曹把酒杯。", "蒸餅猶能十字裂，餛飩那得五般來。"]'),
('214a114d-2e33-426f-bb82-032f31d543ff','對食戲作六首  其四','陸游','宋','宋诗','song-poetry','','[]','栟櫚子嫩供香飯，皂莢芽新簇冷淘。',32,'全唐诗/poet.song.133000.json','["栟櫚子嫩供香飯，皂莢芽新簇冷淘。", "常使先生飽捫腹，其餘萬事一秋毫。"]'),
('bb271d98-056d-4e9e-a54a-709277951211','對食戲作六首  其五','陸游','宋','宋诗','song-poetry','','[]','冰壺欲著先生傳，髯簿卑凡豈得書。',32,'全唐诗/poet.song.133000.json','["冰壺欲著先生傳，髯簿卑凡豈得書。", "常恨當年定交晚，枉教渴死老相如。"]'),
('74db0643-b4b9-45b5-a36b-1bf5c459ad61','對食戲作六首  其六','陸游','宋','宋诗','song-poetry','','[]','黄昏來扣野人扉，笑語欣欣意不遲。',32,'全唐诗/poet.song.133000.json','["黄昏來扣野人扉，笑語欣欣意不遲。", "葑火正紅煨芋美，不妨秉炬雪中歸。"]'),
('633b8367-b574-4279-9c48-273e0b9e530b','甲子立春前二日作','陸游','宋','宋诗','song-poetry','','[]','頭風初愈喜身輕，書卷時開覺眼明。',64,'全唐诗/poet.song.133000.json','["頭風初愈喜身輕，書卷時開覺眼明。", "養熟犬雞隨坐起，性靈烏鵲報陰晴。", "韭菘飣餖春盤好，芝朮簁和臘藥成。", "自笑衰殘殺風景，燈時不擬入重城。"]'),
('a7b19d6f-3cbb-480b-b7a0-395a99d3d112','家居自戒六首  其一','陸游','宋','宋诗','song-poetry','','[]','曩得京口俸，始卜湖邊居。',48,'全唐诗/poet.song.133000.json','["曩得京口俸，始卜湖邊居。", "屋財十許間，歲久亦倍初。", "藝花過百本，嘯詠已有餘。", "猶愧先楚公，終身無屋廬。"]'),
('ca143b29-4194-41f0-9b33-240e52e44f55','家居自戒六首  其二','陸游','宋','宋诗','song-poetry','','[]','平居少愧怍，動以直自遂。',48,'全唐诗/poet.song.133000.json','["平居少愧怍，動以直自遂。", "雖墮虎兕群，我已無死地。", "神仙果可學，吾輩恐差易。", "勿言聞道晚，努力補黥劓。"]'),
('c338d8fb-cd0a-494e-b568-a16abe0300f6','家居自戒六首  其三','陸游','宋','宋诗','song-poetry','','[]','世人無奈愁，沃以杯中酒。',48,'全唐诗/poet.song.133000.json','["世人無奈愁，沃以杯中酒。", "未能平磊塊，已復生堆阜。", "治水不治源，九載亦何有。", "不如讀周易，一卷常在手。"]'),
('5572b196-a1ce-4098-bc36-f9b83d33ed8c','家居自戒六首  其四','陸游','宋','宋诗','song-poetry','','[]','疾病當治本，神醫古難遭。',48,'全唐诗/poet.song.133000.json','["疾病當治本，神醫古難遭。", "哀哉有限身，日與利欲鏖。", "大嚼徒爲貪，劇飲豈足豪。", "淡薄以養壽，亦非慕名高。"]'),
('41790fd7-35a5-48fa-90ee-929a61918955','家居自戒六首  其五','陸游','宋','宋诗','song-poetry','','[]','饑寒陷侵暴，其實可憐傷。',48,'全唐诗/poet.song.133000.json','["饑寒陷侵暴，其實可憐傷。", "一事百自反，忿心冷如霜。", "恕物學者心，省事慮亦長。", "吾過固多矣，責彼何暇詳。"]'),
('a38cd3a4-9e8d-4f08-9f6f-09e3e83290a7','家居自戒六首  其六','陸游','宋','宋诗','song-poetry','','[]','霜嚴雞報晨，月落犬警盜。',48,'全唐诗/poet.song.133000.json','["霜嚴雞報晨，月落犬警盜。", "遺粒與棄糠，每愧不足報。", "椎奴事樵汲，跣婢勤爨竈。", "有過姑教之，箠楚置勿道。"]'),
('30c13a8c-2d4b-46a6-ba15-31f6a3fa1779','感貧','陸游','宋','宋诗','song-poetry','','[]','經歲無兼味，窮冬止破裘。',48,'全唐诗/poet.song.133000.json','["經歲無兼味，窮冬止破裘。", "翁將貧博健，兒以學忘憂。", "士固安天命，吾寧爲食謀。", "八荒如可望，時亦上高樓。"]'),
('5790459d-5fc1-4457-b48d-246b1d3f316c','鄰曲','陸游','宋','宋诗','song-poetry','','[]','濁酒聚鄰曲，偶來非宿期。',48,'全唐诗/poet.song.133000.json','["濁酒聚鄰曲，偶來非宿期。", "拭盤堆連展，洗鬴煮黎祁。", "烏㹀將新犢，青桑長嫩枝。", "豐年多樂事，相勸且伸眉。"]'),
('07e966ac-6436-4c76-af89-a8d7665ba503','送客','陸游','宋','宋诗','song-poetry','','[]','有客相與飲，酒盡惟清言。',72,'全唐诗/poet.song.133000.json','["有客相與飲，酒盡惟清言。", "坐久饑腸鳴，殷如車輪翻。", "烹栗煨芋魁，味美敵熊蹯。", "一飽失百憂，抵掌談羲軒。", "意倦客辭去，秉炬送柴門。", "林間鳥驚起，落月傾金盆。"]'),
('7d0e6edf-2830-4442-a66d-03434232195e','夜寒起坐待旦','陸游','宋','宋诗','song-poetry','','[]','戃怳不成寐，攬衣寒夜中。',48,'全唐诗/poet.song.133000.json','["戃怳不成寐，攬衣寒夜中。", "青熒煨芋火，鞺鞳鼓簾風。", "巷犬聲如豹，山童首似蓬。", "悠然束書坐，徐待日生東。"]'),
('7ae08e6b-6111-4821-b31d-446015e70fbb','信手翻古人詩隨所得次韵二首 夜坐','陸游','宋','宋诗','song-poetry','','[]','病起瘦可驚，崚嶒夜窗影。',72,'全唐诗/poet.song.133000.json','["病起瘦可驚，崚嶒夜窗影。", "八十遂當至，何止踐衰境。", "食簞幸能盡，藥裹亦已屏。", "汲泉煮日鑄，舌本味方永。", "士苦不自晦，常若錐見穎。", "叔度獨何人，長陂渺千頃。"]'),
('5eb68dff-584d-4202-b862-bcfe8b5452ed','信手翻古人詩隨所得次韵二首 除夜沐浴','陸游','宋','宋诗','song-poetry','','[]','孔門春服成，弟子從沂浴。',96,'全唐诗/poet.song.133000.json','["孔門春服成，弟子從沂浴。", "老氏坐中庭，莊生記新沐。", "古聖自潔清，如日浴暘谷。", "豈比流俗人，蟣蝨生桎梏。", "老人喜時節，良夕當爆竹。", "未濯三生垢，湯沐意亦足。", "豈惟寓蕭散，亦以洗榮辱。", "悠然獨酌罷，投枕睡已熟。"]'),
('a88c98c1-3463-4c4b-8df7-d583baa529a5','甲子歲元日','陸游','宋','宋诗','song-poetry','','[]','飲罷屠蘇酒，真爲八十翁。',48,'全唐诗/poet.song.133000.json','["飲罷屠蘇酒，真爲八十翁。", "本憂緣直死，却喜坐詩窮。", "米賤知無盜，雲霒又主豐。", "一簞那復慮，嬉笑伴兒童。"]'),
('b6cb4f38-2174-4df4-a322-938d2c255b61','初春書懷七首  其一','陸游','宋','宋诗','song-poetry','','[]','六十餘年慕古人，即今方近葛天民。',64,'全唐诗/poet.song.133000.json','["六十餘年慕古人，即今方近葛天民。", "見人各是元非恕，遇事皆安豈怨貧。", "小圃鉏耰聊過日，扁舟烟雨尚關身。", "出門未覺龍鍾在，禹廟蘭亭又見春。"]'),
('9ef0af38-cd73-4535-885c-5af1c989a6cb','初春書懷七首  其二','陸游','宋','宋诗','song-poetry','','[]','耄及光陰古更稀，自今惟有數期頤。',64,'全唐诗/poet.song.133000.json','["耄及光陰古更稀，自今惟有數期頤。", "食觀本草雖多事，醉讀離騷自一奇。", "物外有人閑始見，山中可樂老方知。", "武陵好在桃千樹，短櫂相尋亦未遲。"]'),
('c6b176f9-97f5-4399-8413-c0cbb95e0813','初春書懷七首  其三','陸游','宋','宋诗','song-poetry','','[]','數掩蘆藩並水居，一家全似業樵漁。',64,'全唐诗/poet.song.133000.json','["數掩蘆藩並水居，一家全似業樵漁。", "春寒例謝常來客，老病猶貪未見書。", "馴雀正緣拋食慣，芳蘭肯爲礙門鋤。", "藥苗滿鉢無人共，賴有溪僧爲破除。"]'),
('5f649a0d-faed-409c-86b9-8ab99d62b2d5','初春書懷七首  其四','陸游','宋','宋诗','song-poetry','','[]','甫及初春日已長，偶同鄰曲集山房。',64,'全唐诗/poet.song.133000.json','["甫及初春日已長，偶同鄰曲集山房。", "囊盛古墨靴紋皺，箬護新茶带胯方。", "老境不嫌來冉冉，流年直恐去堂堂。", "清泉冷浸疏梅蕊，共領人間第一香。"]'),
('96cd5858-d82e-47a5-bc77-5ea80215a198','初春書懷七首  其五','陸游','宋','宋诗','song-poetry','','[]','底處人間無駭機，超遥且喜謝招麾。',64,'全唐诗/poet.song.133000.json','["底處人間無駭機，超遥且喜謝招麾。", "千年澗底孤松秀，萬里天邊獨雁歸。", "服氣昔常憎火食，遊山近已製荷衣。", "青城况有幽人約，會守丹爐隱翠微。"]'),
('5ef948e2-6088-4a5c-a2ab-bdb831ea4a6c','初春書懷七首  其六','陸游','宋','宋诗','song-poetry','','[]','納祿貧如筮仕初，歸來依舊卧蝸廬。',64,'全唐诗/poet.song.133000.json','["納祿貧如筮仕初，歸來依舊卧蝸廬。", "半池墨瀋臨章草，一碗松肪讀隱書。", "長鑱僅供饑子美，清江不療渴相如。", "耄期自許詩情在，雪裏猶能跨蹇驢。"]'),
('290dcc15-d4d3-425b-8bc4-1bc9ba4cb303','初春書懷七首  其七','陸游','宋','宋诗','song-poetry','','[]','愚公不解計安危，行盡人間惡路岐。',64,'全唐诗/poet.song.133000.json','["愚公不解計安危，行盡人間惡路岐。", "難似車登蛇退嶺，險如舟過馬當祠。", "平生憂患常難測，送老安閑敢自期。", "一事不成應有命，惟將知止報明時。"]'),
('79811001-eff2-42bc-9bd3-8a9534068e40','初春紀事二首  其一','陸游','宋','宋诗','song-poetry','','[]','窗欞無日影，庭樹無風聲。',72,'全唐诗/poet.song.133000.json','["窗欞無日影，庭樹無風聲。", "微雲淡天宇，非陰亦非晴。", "美哉豐年祥，入我屠蘇觥。", "父老亦共喜，歡言叩柴荆。", "一飽已有期，惟當力春耕。", "遣兒牧雞豚，作社賽西成。"]'),
('1d447a55-c75b-4c51-a71c-810b4541c1b9','初春紀事二首  其二','陸游','宋','宋诗','song-poetry','','[]','經冬少雨雪，所至苦水涸。',60,'全唐诗/poet.song.133000.json','["經冬少雨雪，所至苦水涸。", "園蔬葉多蠹，山步船半閣。", "入春一再雨，喜氣滿墟落。", "又聞湖邊路，已破小桃萼。", "一尊儻可携，父子自酬酢。"]'),
('0a31d6ce-12ee-4127-91b6-15187061feda','送子虡吳門之行','陸游','宋','宋诗','song-poetry','','[]','相送何由插羽翰，淡烟微雨暗江干。',64,'全唐诗/poet.song.133000.json','["相送何由插羽翰，淡烟微雨暗江干。", "孤懷最怯新春別，病骨難禁昨夜寒。", "尊酒汝寧嫌魯薄，釜羹翁自絮吳酸。", "此詩字字俱愁絕，忍泪成篇却怕看。"]'),
('734f536e-0798-4d14-8eff-381e0e28d255','法雲僧房','陸游','宋','宋诗','song-poetry','','[]','八十衰翁有底忙，水邊山際亦倀倀。',64,'全唐诗/poet.song.133000.json','["八十衰翁有底忙，水邊山際亦倀倀。", "清溪橋斷舟橫岸，小塢梅殘雨漬香。", "數點青燈經野市，一爐軟火宿僧房。", "自嫌尚有人間念，却爲春寒怯夜長。"]'),
('9149660a-b5f7-44e6-b1ca-2da99685c468','陌上','陸游','宋','宋诗','song-poetry','','[]','陌上長歌任笑狂，此生得喪略相當。',64,'全唐诗/poet.song.133000.json','["陌上長歌任笑狂，此生得喪略相當。", "天將耄齒償貧悴，身坐虛名掇謗傷。", "溪水漸生朱舫活，野梅半落綠苔香。", "新晴快上蘭亭路，莫待春殘始一觴。"]'),
('9805c0c5-41bc-4aad-906c-f00b586e4cf2','獨立','陸游','宋','宋诗','song-poetry','','[]','白髯蕭颯一愚公，獨立濛濛細雨中。',64,'全唐诗/poet.song.133000.json','["白髯蕭颯一愚公，獨立濛濛細雨中。", "羊踏寒蔬新少夢，魚生空釜久諳窮。", "殘編幸有聖賢對，閑話豈無鄰曲同。", "衒鬻才名非老事，小詩信筆不能工。"]'),
('0b7d96db-5cd7-447d-ab4e-085aee5d70ae','春陰','陸游','宋','宋诗','song-poetry','','[]','數間茅屋傍楓林，常負平生萬里心。',64,'全唐诗/poet.song.133000.json','["數間茅屋傍楓林，常負平生萬里心。", "老去逐年增老病，春來無日不春陰。", "麴塵蘸岸波初漲，猩血團枝色已深。", "欲到東園還懶起，却和殘睡聽鳴禽。"]'),
('39b1e82f-a3a7-4644-8794-8a104248257d','閑味','陸游','宋','宋诗','song-poetry','','[]','身似枯禪謝世塵，豈容收斂强冠巾。',64,'全唐诗/poet.song.133000.json','["身似枯禪謝世塵，豈容收斂强冠巾。", "庾郎三韭不妨飽，晏子一裘何恨貧。", "栖冷每憐雞唱早，雲開初見月痕新。", "閑中有味君知否，熊掌駝峰未是珍。"]'),
('8d314cbe-e9e5-40b3-84ac-5cb64faf86e5','聞虜亂代華山隱者作','陸游','宋','宋诗','song-poetry','','[]','滿谷松風枕石眠，中元戰血又成川。',64,'全唐诗/poet.song.133000.json','["滿谷松風枕石眠，中元戰血又成川。", "但思秦鑄銅人日，不記齊成柏寢年。", "大藥一爐暾晚日，孤桐三尺寫秋泉。", "何妨狂舞旗亭下，乞與人間畫醉僊。"]'),
('62681639-5483-4d6d-aa1e-cfb5059875d4','春日','陸游','宋','宋诗','song-poetry','','[]','車馬閑中絕，衣襦病後寬。',48,'全唐诗/poet.song.133000.json','["車馬閑中絕，衣襦病後寬。", "改詩消晝永，賒酒敵春寒。", "柳細搓難似，花新染未乾。", "歸鴻與來燕，各自管悲歡。"]'),
('ddd58459-d70c-40da-969b-740c18b4a8ab','寄子虡','陸游','宋','宋诗','song-poetry','','[]','十里城南路，蕭然一禿翁。',48,'全唐诗/poet.song.133000.json','["十里城南路，蕭然一禿翁。", "舊書衰易忘，新句懶難工。", "山色春寒淡，溪流宿雨通。", "街頭有良醞，思汝一尊同。"]'),
('48129d58-14e6-41e7-ab30-8b71e9f6774c','送子坦','陸游','宋','宋诗','song-poetry','','[]','老境寧容別，諸兒仕爲貧。',48,'全唐诗/poet.song.133000.json','["老境寧容別，諸兒仕爲貧。", "一春多卧病，幾度送行人。", "五斗方須祿，千金且愛身。", "長安雖可樂，憐汝正思親。"]'),
('303c0217-86e4-408c-903c-4b2c723c44a0','送子遹','陸游','宋','宋诗','song-poetry','','[]','隔一濤江路豈遥，躊躇不覺欲魂銷。',64,'全唐诗/poet.song.133000.json','["隔一濤江路豈遥，躊躇不覺欲魂銷。", "寄書勿遣過三日，發渡何曾無兩潮。", "睡少不關茶作祟，愁多却賴酒時澆。", "柯橋西畔斜陽岸，誰爲離人惜柳條。"]'),
('c7f37e90-b8c9-4250-8233-dc2110dc0ee9','醉眠初起書事','陸游','宋','宋诗','song-poetry','','[]','身世元知似斷蓬，流年分付酒杯中。',64,'全唐诗/poet.song.133000.json','["身世元知似斷蓬，流年分付酒杯中。", "饑寒未解士先老，風雨欲收花已空。", "泥補舊巢梁燕喜，水生支港釣船通。", "睡魔正費驅除力，隔竹敲茶賴小童。"]'),
('cd4dd268-dca2-44b9-8562-9e21670b30bd','見蜂采檜花偶作','陸游','宋','宋诗','song-poetry','','[]','來禽海棠相續開，輕狂蛺蝶去還來。',32,'全唐诗/poet.song.133000.json','["來禽海棠相續開，輕狂蛺蝶去還來。", "山蜂却是有風味，偏采檜花供蜜材。"]'),
('f38ee568-f870-4d32-8581-df5ba96ac632','對酒戲詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','不管詩人大瘦生，但念酒徒稀醉眠。',32,'全唐诗/poet.song.133000.json','["不管詩人大瘦生，但念酒徒稀醉眠。", "憑誰爲畫畢吏部，縛著鄰家春甕邊。"]'),
('c832395a-13e6-4547-bcb5-19cdf9661c3c','對酒戲詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','長安市中多美酒，一斗財當三百錢。',32,'全唐诗/poet.song.133000.json','["長安市中多美酒，一斗財當三百錢。", "堪笑書生消幾許，有錢十萬醉經年。"]'),
('100cc591-2427-4934-b245-b7bd1489292e','夜興','陸游','宋','宋诗','song-poetry','','[]','梟呼作人聲，月出如野燒。',72,'全唐诗/poet.song.133000.json','["梟呼作人聲，月出如野燒。", "推枕中夜起，殘燈尚餘照。", "難從公榮飲，獨效孫登嘯。", "八十推不僵，平昔豈所料。", "空廊病馬卧，枯草老牛噍。", "明朝語俗人，與汝不同調。"]'),
('c1f42773-d9c2-47fb-8e1a-5d33f91981d2','老甚自詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘年真欲數期頤，一事無營飽即嬉。',64,'全唐诗/poet.song.133000.json','["殘年真欲數期頤，一事無營飽即嬉。", "身入兒童鬭草社，心如太古結繩時。", "騰騰不許諸人會，兀兀從嘲老子癡。", "亦莫城中買鹽酪，菜羹有味淡方知。"]'),
('24c355c9-f23e-45b0-912b-1da713b369da','老甚自詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','羨生常笑古人癡，俯仰那知迫耄期。',64,'全唐诗/poet.song.133000.json','["羨生常笑古人癡，俯仰那知迫耄期。", "鏡裏鬢無添白處，尊前顔有暫丹時。", "客瞋終歲常稱疾，兒訝經旬懶賦詩。", "枉却愁過强健日，身閑何往不熙熙。"]'),
('0e2216fa-91ca-4fc3-9ace-370fb49655dc','夜過魯墟','陸游','宋','宋诗','song-poetry','','[]','晡時發柯橋，申夜過魯墟。',72,'全唐诗/poet.song.133000.json','["晡時發柯橋，申夜過魯墟。", "燈出籬落間，七世有故廬。", "門低不容駟，壁壞亡遺書。", "高樹宿羈鳥，廢沼跳驚魚。", "移船過古埭，水面涵星疏。", "安得病良已，畢世澆春蔬。"]'),
('82cd99f3-8a44-43f2-88da-fa03b7029908','園中小飲','陸游','宋','宋诗','song-poetry','','[]','造物佚我老，畀以江湖寬。',120,'全唐诗/poet.song.133000.json','["造物佚我老，畀以江湖寬。", "俯仰六年間，得請兩挂冠。", "鬢毛雖蕭颯，脚力未蹣跚。", "記書過十張，噉飯空一簞。", "開歲忽兩月，感此春事殘。", "杏靨笑牆頭，鶯聲入雲端。", "掃地設菅席，相與勸加餐。", "村酒瀉濁清，野果嘗甘酸。", "鄰里語蟬聯，兒孫話團欒。", "雖無萬錢筯，浩歌有餘歡。"]'),
('3d6b2495-33e8-498c-96b5-d0447c624129','幽居春晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','雲歸禹穴賞新晴，酒買蘭亭散宿酲。',64,'全唐诗/poet.song.133000.json','["雲歸禹穴賞新晴，酒買蘭亭散宿酲。", "竹带鞭移俄盛出，鶴全窠買已長鳴。", "故山雖愧收身晚，外物元如脫髮輕。", "只恐村鄰成間闊，杖藜隨處叩柴荆。"]'),
('b2bb218b-a439-4f7f-8a67-4df095ebda27','幽居春晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','老廢讎書病廢詩，晝閑惟與睡相宜。',64,'全唐诗/poet.song.133000.json','["老廢讎書病廢詩，晝閑惟與睡相宜。", "未尋內史流觴地，又近龐公上冢時。", "花發遊蜂喧院落，筍長馴鹿入藩籬。", "石帆山下春如許，野老來招不用辭。"]'),
('c7032f40-09e3-4793-a012-3b17023be9c5','梅花過後遊西山諸庵','陸游','宋','宋诗','song-poetry','','[]','乞得身歸喜滿顔，柴門雖設不曾關。',64,'全唐诗/poet.song.133000.json','["乞得身歸喜滿顔，柴門雖設不曾關。", "無如梅作經年別，且就僧分半日閑。", "樵斧曉穿雲外去，釣船夜向月中還。", "君看老子無窮樂，一笑知非造物慳。"]'),
('56a1e50b-cff5-495b-b361-940c13fd1328','梅僊塢花涇觀桃李','陸游','宋','宋诗','song-poetry','','[]','妖妍天遣占年華，嘆息人間有許花。',64,'全唐诗/poet.song.133000.json','["妖妍天遣占年華，嘆息人間有許花。", "十里織成無罅錦，半天留得未殘霞。", "欲題直恐無才稱，不見何由信客誇。", "醉後又驚春事晚，湖堤烟柳已藏鴉。"]'),
('20712b04-6793-4693-a175-6fa84a8f051a','家園賞花','陸游','宋','宋诗','song-poetry','','[]','白首扁舟返舊邦，逢春直欲倒千缸。',64,'全唐诗/poet.song.133000.json','["白首扁舟返舊邦，逢春直欲倒千缸。", "紅雲夾路薔薇障，翠羽成層薜荔幢。", "鶯語枝頭常盡日，蝶迷葉底不成雙。", "閑人爛醉尋常事，中聖先判卧北窗。"]'),
('59cfed3d-c6a7-47a0-b5a4-92fb31315a7d','聞金溪陸伯政下世','陸游','宋','宋诗','song-poetry','','[]','久矣望來使，潸然開訃書。',48,'全唐诗/poet.song.133000.json','["久矣望來使，潸然開訃書。", "兩家通絕譜，千里泣靈車。", "亦悟古皆死，所悲天祝余。", "泉扃生氣在，故不羨曹蜍。"]'),
('d9bf403a-61c8-4541-86de-0dadd2d87a1b','一春風雨太半有感','陸游','宋','宋诗','song-poetry','','[]','忽忽春將老，寒暄尚未齊。',48,'全唐诗/poet.song.133000.json','["忽忽春將老，寒暄尚未齊。", "雨昏雞唱晚，風惡鵲巢低。", "寫物才殊退，尋芳思欲迷。", "餘年不須較，只是死秦稽。"]'),
('62566eab-df13-4242-8cfc-2663808d66e6','山行贈野叟二首  其一','陸游','宋','宋诗','song-poetry','','[]','垂白衰翁住道邊，突間猶喜續炊烟。',64,'全唐诗/poet.song.133000.json','["垂白衰翁住道邊，突間猶喜續炊烟。", "壁如龜筴難占卜，瓦似魚鱗不接連。", "幼學及時兒識字，官租先眾吏無權。", "與君俱長宣和日，握手相看一悵然。"]'),
('eb46c429-7096-4f0b-a2e0-a85abbae3d57','山行贈野叟二首  其二','陸游','宋','宋诗','song-poetry','','[]','莫笑孤村生理微，茅茨烟火自相依。',64,'全唐诗/poet.song.133000.json','["莫笑孤村生理微，茅茨烟火自相依。", "客來旋掃青苔榻，日在先關白版扉。", "婦女憂蠶租葉去，兒童耘麥荷鉏歸。", "散人世襲江湖號，剩欲溪頭借釣磯。"]'),
('aedf1764-76ec-4fa7-9d1a-ea3901c84627','雲門道中','陸游','宋','宋诗','song-poetry','','[]','川靄林霏翠欲浮，散人心事寄沙鷗。',64,'全唐诗/poet.song.133000.json','["川靄林霏翠欲浮，散人心事寄沙鷗。", "暮投野店孤烟起，曉涉清溪小蹇愁。", "嶺路窮時縈細棧，山形缺處起重樓。", "釣游陳迹渾如昨，一念凄然不自由。"]'),
('f3c031d4-05e0-4131-8d5e-5382b9aa7eef','讀書有感','陸游','宋','宋诗','song-poetry','','[]','洙泗諸生尊所聞，豈容兀者亦中分。',64,'全唐诗/poet.song.133000.json','["洙泗諸生尊所聞，豈容兀者亦中分。", "焚經競欲愚黔首，亡史誰能及闕文。", "吾道固應千古在，幾人虛用一生勤。", "世間倚相何曾乏，會與明時誦典墳。"]'),
('f94a7515-1ef9-4e1d-bf19-d36b3beb5757','六言雜興九首  其一','陸游','宋','宋诗','song-poetry','','[]','世界庵摩勒果，聖賢優鉢曇華。',28,'全唐诗/poet.song.133000.json','["世界庵摩勒果，聖賢優鉢曇華。", "但解折衷六藝，何須和會三家。"]'),
('a0d99c20-49d3-4f3f-bc99-0f421198c18e','六言雜興九首  其二','陸游','宋','宋诗','song-poetry','','[]','夢裏明明周孔，胸中歷歷唐虞。',28,'全唐诗/poet.song.133000.json','["夢裏明明周孔，胸中歷歷唐虞。", "欲盡致君事業，先求養氣工夫。"]'),
('9687562b-707a-4272-a65b-74f11e18f15c','六言雜興九首  其三','陸游','宋','宋诗','song-poetry','','[]','語道無如孔孟，佛莊雖似非同。',28,'全唐诗/poet.song.133000.json','["語道無如孔孟，佛莊雖似非同。", "倘有一人領會，何須客滿坐中。"]'),
('9203ebfb-b255-41c5-9c46-6c77dc61fdd4','六言雜興九首  其四','陸游','宋','宋诗','song-poetry','','[]','失馬詎知非福，亡羊不妨補牢。',28,'全唐诗/poet.song.133000.json','["失馬詎知非福，亡羊不妨補牢。", "病裏正須周易，醉中却要離騷。"]'),
('ae395674-8aec-4ef2-b632-286a77f9b5df','六言雜興九首  其五','陸游','宋','宋诗','song-poetry','','[]','舉足加劉公腹，引手捋孫郎鬚。',28,'全唐诗/poet.song.133000.json','["舉足加劉公腹，引手捋孫郎鬚。", "士氣日趨委靡，賴有二君掃除。"]'),
('10c5c17e-da11-4beb-86f4-8e6173340b67','六言雜興九首  其六','陸游','宋','宋诗','song-poetry','','[]','廣平作梅花賦，少陵無海棠詩。',28,'全唐诗/poet.song.133000.json','["廣平作梅花賦，少陵無海棠詩。", "正自一時偶爾，俗人平地生疑。"]'),
('c8455017-fd70-4d86-9410-c99b199fe001','六言雜興九首  其七','陸游','宋','宋诗','song-poetry','','[]','瘦馬羸僮道路，清泉白石山林。',28,'全唐诗/poet.song.133000.json','["瘦馬羸僮道路，清泉白石山林。", "常得有衣換酒，不愁無法燒金。"]'),
('00a8ef2c-4085-4a42-95ee-caa1e12d94aa','六言雜興九首  其八','陸游','宋','宋诗','song-poetry','','[]','一夜雨來可怖，五更雲散無餘。',28,'全唐诗/poet.song.133000.json','["一夜雨來可怖，五更雲散無餘。", "傳舍僧窗雖異，不妨隨處觀書。"]'),
('1e2ef1ee-e940-4f1a-b1e7-c6d691028396','六言雜興九首  其九','陸游','宋','宋诗','song-poetry','','[]','熟讀大小止觀，精思內外黄庭。',28,'全唐诗/poet.song.133000.json','["熟讀大小止觀，精思內外黄庭。", "直使超然有得，豈若淵源六經。"]'),
('7b74e66c-1eff-42fd-9b53-1102151f2ecc','春晚出遊六首  其一','陸游','宋','宋诗','song-poetry','','[]','風急名花紛絳雪，土鬆香草出瑶簪。',32,'全唐诗/poet.song.133000.json','["風急名花紛絳雪，土鬆香草出瑶簪。", "且呼野艇西村去，未必微雲便作陰。"]'),
('806566df-9400-4467-8822-b6b5f2092b06','春晚出遊六首  其二','陸游','宋','宋诗','song-poetry','','[]','王孫草生與階齊，女郎花發乳鶯啼。',32,'全唐诗/poet.song.133000.json','["王孫草生與階齊，女郎花發乳鶯啼。", "街頭賣酒處處賤，信脚覓醉無東西。"]'),
('4c293d86-d6e3-496f-a038-883787c7823c','春晚出遊六首  其三','陸游','宋','宋诗','song-poetry','','[]','柳暗人家水滿陂，放翁隨處曳筇枝。',32,'全唐诗/poet.song.133000.json','["柳暗人家水滿陂，放翁隨處曳筇枝。", "村深麥秀蠶眠後，日暖鳩鳴鵲乳時。"]'),
('d90f5287-4c06-48db-86c8-4c687646339c','春晚出遊六首  其四','陸游','宋','宋诗','song-poetry','','[]','禹吾無間聖所嘆，治水殆與天同功。',32,'全唐诗/poet.song.133000.json','["禹吾無間聖所嘆，治水殆與天同功。", "三千年事一炊頃，窆石嵯峨烟靄中。"]'),
('5eedee81-165f-4fc9-beb5-841e27bce332','春晚出遊六首  其五','陸游','宋','宋诗','song-poetry','','[]','岌岌高丘近道邊，寂寥翁仲卧荒烟。',32,'全唐诗/poet.song.133000.json','["岌岌高丘近道邊，寂寥翁仲卧荒烟。", "生前意氣今何在，寒食無人挂紙錢。"]'),
('da6f340d-958c-4346-98f3-a539c9dea475','春晚出遊六首  其六','陸游','宋','宋诗','song-poetry','','[]','鳴機裂素製春衣，煮酒香清雁鶩肥。',32,'全唐诗/poet.song.133000.json','["鳴機裂素製春衣，煮酒香清雁鶩肥。", "倒社相呼共行樂，三撾鼓近是船歸。"]'),
('f90c6fd5-62ff-47ac-a77b-a59dc5bc875a','北窗','陸游','宋','宋诗','song-poetry','','[]','老人日夜衰，卧起常在背。',120,'全唐诗/poet.song.133000.json','["老人日夜衰，卧起常在背。", "窗間一編書，終日聖賢對。", "東皋客輸米，粲粲珠出碓。", "南山僧餉茶，細細雪落磑。", "吾兒亦解事，稀甲自鉏菜。", "一饑既退舍，百念皆卷旆。", "閑身去俗遠，澄念與道會。", "宿痾走二豎，美睡造三昧。", "挂冠反布韋，上印謝銀艾。", "庭中石蒼然，此客真度外。"]'),
('c352f344-a0e7-4aa3-b675-65481b091a29','幽居雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','開歲頻風雨，清明氣始和。',48,'全唐诗/poet.song.133000.json','["開歲頻風雨，清明氣始和。", "遊山書半廢，耽酒睡常多。", "客去孫登嘯，牛疲甯戚歌。", "餘生猶有幾，盡底付漁蓑。"]'),
('5f57f086-bdad-4ea8-b417-379c13b928e3','幽居雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','雅意元知止，遄歸喜遂初。',48,'全唐诗/poet.song.133000.json','["雅意元知止，遄歸喜遂初。", "久閑棋格長，多病釣徒疏。", "漬藥三升酒，支頭一束書。", "兒曹看翁懶，切勿厭蝸廬。"]'),
('03e5cacb-e233-41d6-877c-a4f45a408e46','幽居雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','忽忽年光逝，悠悠世事非。',48,'全唐诗/poet.song.133000.json','["忽忽年光逝，悠悠世事非。", "曉猶明績火，晝永啟漁扉。", "施食禽魚熟，疏溝杞菊肥。", "寂寥何所嘆，父子自相依。"]'),
('23c4d2db-9d96-4672-925e-0464d6405d75','幽居雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','獨往成初志，安居謝世紛。',48,'全唐诗/poet.song.133000.json','["獨往成初志，安居謝世紛。", "名書硬黄紙，古硯熨焦紋。", "雨作占琴薦，風來散鷺群。", "豈無朝市事，塞耳未曾聞。"]'),
('b09011e5-7b3a-4a60-a2e7-04feb337e310','題旅舍壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','泥淖停牛屋，風埃坐簀床。',48,'全唐诗/poet.song.133000.json','["泥淖停牛屋，風埃坐簀床。", "絳人難諱老，楚客自嫌狂。", "浪迹江湖大，回頭日月長。", "村村有餅餌，正可不赍糧。"]'),
('c4170537-d48b-43eb-881d-4a832a800816','題旅舍壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','地曠風號木，天高日脫雲。',48,'全唐诗/poet.song.133000.json','["地曠風號木，天高日脫雲。", "村名步頭換，縣界驛前分。", "蒿艾春侵路，雞豚暮識群。", "敲門就炊爨，一飯敢忘君。"]'),
('c3c5f7df-e607-420e-919c-677c0e8b67a3','出行湖山間雜賦四首  其一','陸游','宋','宋诗','song-poetry','','[]','老入新年健，春逢小雨晴。',48,'全唐诗/poet.song.133000.json','["老入新年健，春逢小雨晴。", "偶因尋酒去，又作繞村行。", "塘水蒼鵝戲，郊原黄犢鳴。", "閑身有樂事，倚杖看農耕。"]'),
('22b4a736-49a6-474c-9f70-50cee9ab810a','出行湖山間雜賦四首  其二','陸游','宋','宋诗','song-poetry','','[]','新釀學鵝黄，幽花作蜜香。',48,'全唐诗/poet.song.133000.json','["新釀學鵝黄，幽花作蜜香。", "客邀閑即去，病起醉何傷。", "野寺無晨粥，村伶有夜場。", "吾心靜如水，隨事答年光。"]'),
('7df6cecd-c26e-4e5d-81c2-4cf5ca326d73','出行湖山間雜賦四首  其三','陸游','宋','宋诗','song-poetry','','[]','徑繞茶岡北，橋連芡浦東。',48,'全唐诗/poet.song.133000.json','["徑繞茶岡北，橋連芡浦東。", "蟲鎪烏桕葉，露溼豨薟叢。", "燒地春蕪綠，漁扉夕照紅。", "君恩那可報，惟是祝年豐。"]'),
('b7fe3b8a-403c-4965-8b3f-b25806da0432','出行湖山間雜賦四首  其四','陸游','宋','宋诗','song-poetry','','[]','魚市樵風口，茶村穀雨前。',48,'全唐诗/poet.song.133000.json','["魚市樵風口，茶村穀雨前。", "柳邊烟掩苒，堤上草芊眠。", "墓掃鴉銜肉，人歸鷺導船。", "東風吹短髮，得句爲誰妍。"]'),
('fe9e8f23-46d2-4ee5-a2e4-99d84f37329d','上巳','陸游','宋','宋诗','song-poetry','','[]','殘年登八十，佳日遇重三。',48,'全唐诗/poet.song.133000.json','["殘年登八十，佳日遇重三。", "簾幕低新燕，房櫳起晚蠶。", "名花紅滿舫，美醞綠盈甔。", "春事還如昨，衰懷自不堪。"]'),
('38866c2b-91e4-4139-9130-129002f65a9e','筍絕句','陸游','宋','宋诗','song-poetry','','[]','列仙閱世獨清癯，雪谷冰溪老不枯。',32,'全唐诗/poet.song.133000.json','["列仙閱世獨清癯，雪谷冰溪老不枯。", "輸與錦棚孩子輩，千金一束入天厨。"]'),
('91353824-cb9c-4d7e-b5c8-51a0d29df355','贈蘇召叟','陸游','宋','宋诗','song-poetry','','[]','蘇子出儔輩，翩如天際鴻。',48,'全唐诗/poet.song.133000.json','["蘇子出儔輩，翩如天際鴻。", "才華刮眼瞙，文字愈頭風。", "豈止千人見，真當四海空。", "老夫雖耄矣，此論不妨公。"]'),
('9143ed91-bca2-4790-98ae-377018500318','贈趙去華','陸游','宋','宋诗','song-poetry','','[]','趙子毫端萬斛珠，眼前百輩不枝梧。',64,'全唐诗/poet.song.133000.json','["趙子毫端萬斛珠，眼前百輩不枝梧。", "盛名豈待它年見，公論何曾一日無。", "我老杜門惟足睡，君豪折簡固難呼。", "此詩强欲相題目，堪笑衰翁膽滿軀。"]'),
('ca284bdd-bbca-45dc-b43f-c172a53749a4','道室述懷','陸游','宋','宋诗','song-poetry','','[]','養心功用在還嬰，肯使秋毫有妄情。',64,'全唐诗/poet.song.133000.json','["養心功用在還嬰，肯使秋毫有妄情。", "二寸藤冠狂道士，一編蠹簡老書生。", "狐妖從汝作人立，金價在吾如土輕。", "地肺終嫌近朝市，明年泝峽上青城。"]'),
('42b9f377-1691-4266-899c-36861c8ee395','春晚雨中作','陸游','宋','宋诗','song-poetry','','[]','冉冉流年不貸人，東園青杏又嘗新。',64,'全唐诗/poet.song.133000.json','["冉冉流年不貸人，東園青杏又嘗新。", "方書無藥醫治老，風雨何心斷送春。", "樂事久歸孤枕夢，酒痕空伴素衣塵。", "畏途回首濤瀾惡，賴有雲山著此身。"]'),
('ebe2fce9-f974-4432-b4e5-699afc774f43','晚行湖上','陸游','宋','宋诗','song-poetry','','[]','飽來捫腹繞村嬉，北陌東阡信所之。',64,'全唐诗/poet.song.133000.json','["飽來捫腹繞村嬉，北陌東阡信所之。", "女手采餘桑鬰鬰，烟蕪生遍冢纍纍。", "高林日暮無鶯語，深巷人歸有犬隨。", "東走郡城逾十里，好風勞送角聲悲。"]'),
('2b8e726b-42ee-43c0-8fea-39248ac586cf','欲卜庵居未有勝地作詩識之','陸游','宋','宋诗','song-poetry','','[]','破裘百結鬢垂蓬，旋過流年旋已空。',64,'全唐诗/poet.song.133000.json','["破裘百結鬢垂蓬，旋過流年旋已空。", "魔眷屬如雲盡散，性光明似日方中。", "極知萬事不勞問，欲住一庵誰與同。", "會向巢居明月夜，五弦橫膝寫松風。"]'),
('21c653aa-bdc6-44ce-abc4-5daa9d91504b','東窗遣興','陸游','宋','宋诗','song-poetry','','[]','東窗徙倚當閑遊，水長池魚自滿溝。',64,'全唐诗/poet.song.133000.json','["東窗徙倚當閑遊，水長池魚自滿溝。", "花氣襲人渾欲醉，鳥聲喚客又成愁。", "百年光景輸欹枕，萬里風烟入倚樓。", "欲寫烏絲還懶去，詩名老去判悠悠。"]'),
('0b99a30a-9b6d-4808-b2dc-b1c853bbde55','獨酌','陸游','宋','宋诗','song-poetry','','[]','一榼芳醪手自斟，從來戶小怯杯深。',64,'全唐诗/poet.song.133000.json','["一榼芳醪手自斟，從來戶小怯杯深。", "已於醉醒知狂聖，又向淳漓見古今。", "濡首固非吾輩事，達生猶得昔人心。", "酴醿欲過香差減，且據胡床坐綠陰。"]'),
('f65f0121-ba19-4918-8532-8b1a392eafbd','舟中作','陸游','宋','宋诗','song-poetry','','[]','誤長僊蓬不滿年，恩容歸老白雲邊。',64,'全唐诗/poet.song.133000.json','["誤長僊蓬不滿年，恩容歸老白雲邊。", "草枯病馬停朝秣，水冷鰥魚廢夜眠。", "混俗豈須名赫赫，耐嘲唯可腹便便。", "柯橋梅市花俱好，且典春衣醉放顛。"]'),
('bcefd645-3f42-4cc8-9d67-98424bd7b07b','衰疾','陸游','宋','宋诗','song-poetry','','[]','衰疾憐新鬼，狂豪尚故吾。',48,'全唐诗/poet.song.133000.json','["衰疾憐新鬼，狂豪尚故吾。", "棋常先客著，行不許兒扶。", "硯潤閑蟾滴，香殘冷鴨爐。", "自憐風味在，尚欲泛江湖。"]'),
('8e3019fa-99e4-4222-8d01-37ef40b4bc63','示兒','陸游','宋','宋诗','song-poetry','','[]','聞義貴能徙，見賢思與齊。',48,'全唐诗/poet.song.133000.json','["聞義貴能徙，見賢思與齊。", "食嘗甘脫粟，起不待鳴雞。", "蕭索園官菜，酸寒太學齏。", "時時語兒子，未用厭鉏犁。"]'),
('620ab1ee-47a4-4154-a450-baa1bafdf527','野興','陸游','宋','宋诗','song-poetry','','[]','溪漲侵庵路，山光壓釣磯。',48,'全唐诗/poet.song.133000.json','["溪漲侵庵路，山光壓釣磯。", "荒畦荷鉏去，小艇載犁歸。", "世態那堪看，吾言可自違。", "從今謝人事，終日掩荆扉。"]'),
('379cda42-9a72-4643-8555-cb29815e807a','閑遊四首  其一','陸游','宋','宋诗','song-poetry','','[]','遊徧名山日月長，結廬歸占水雲鄉。',64,'全唐诗/poet.song.133000.json','["遊徧名山日月長，結廬歸占水雲鄉。", "醉中即是逃名地，閑外應無度世方。", "檜蜜滿脾餘小苦，朮苗浥露有奇香。", "肺腸自與人間別，堪笑醅缸與飯囊。"]'),
('a5db16df-2dde-4427-88d2-40f8f1bc7e11','閑遊四首  其二','陸游','宋','宋诗','song-poetry','','[]','高會揮金愧二疏，食貧只似布衣初。',64,'全唐诗/poet.song.133000.json','["高會揮金愧二疏，食貧只似布衣初。", "終年老健緣儲藥，隨分窮忙爲著書。", "弔古何時過梁宋，題詩且欲徧衡廬。", "不須更擬乘風去，水有烟帆陸筍輿。"]'),
('75f1e289-7b78-450f-86ae-dc70884d8014','閑遊四首  其三','陸游','宋','宋诗','song-poetry','','[]','過盡僧家到店家，山形四合路三叉。',64,'全唐诗/poet.song.133000.json','["過盡僧家到店家，山形四合路三叉。", "清明漿美村村賣，穀雨茶香院院誇。", "困卧幽窗身化蝶，醉題素壁字棲鴉。", "夕陽不盡青鞋興，小立風前鬢脚斜。"]'),
('661b2791-85a9-401a-a69e-64bc426b8f87','閑遊四首  其四','陸游','宋','宋诗','song-poetry','','[]','夙興蓐食戒山行，策蹇迢迢過故城。',64,'全唐诗/poet.song.133000.json','["夙興蓐食戒山行，策蹇迢迢過故城。", "露葉未乾明曉日，風蒲初勁借秋聲。", "綠陰渡口孤鶯語，白水陂頭兩犢耕。", "遥望炊烟疑可憩，試從行路問村名。"]'),
('c36569d6-f5cf-45ac-bd92-8625521f3465','炊米不繼戲作','陸游','宋','宋诗','song-poetry','','[]','敢羨晨興費萬錢，口邊縱理信前緣。',64,'全唐诗/poet.song.133000.json','["敢羨晨興費萬錢，口邊縱理信前緣。", "高年雖獲殿諸老，一飽常如登九天。", "架上有書吾已矣，甑中無飯亦陶然。", "蓬門一閉還旬日，實怕閑人攪晝眠。"]'),
('1a4719d6-81e7-4920-87ef-6601232248f6','暮行','陸游','宋','宋诗','song-poetry','','[]','志士能輕萬戶封，野人自愛一枝筇。',64,'全唐诗/poet.song.133000.json','["志士能輕萬戶封，野人自愛一枝筇。", "行窮綠岸呼船渡，糴得黄粱就碓舂。", "林外人家明遠火，月邊僧閣下疏鐘。", "江村不用愁孤絕，小店茅簷儘見容。"]'),
('7cd9023e-f31f-44fd-be3a-9ddd93614361','小雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','小雨過巖扃，殘雲傍野亭。',48,'全唐诗/poet.song.133000.json','["小雨過巖扃，殘雲傍野亭。", "花光相映發，鶯語苦叮嚀。", "舉酒和神氣，彈琴悅性靈。", "索居朋友絕，得句遣誰聽。"]'),
('3a7554fd-811a-4b43-9f73-3dc2461719e3','小雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','急雨方侵幔，斜暉忽滿廊。',48,'全唐诗/poet.song.133000.json','["急雨方侵幔，斜暉忽滿廊。", "塵清添草色，衣潤省篝香。", "婦織將收繭，農功已下秧。", "諸孫入家塾，親爲授三蒼。"]'),
('33d1ee53-db28-4f07-864c-975fd3d5e795','送辛幼安殿撰造朝','陸游','宋','宋诗','song-poetry','','[]','稼軒落筆凌鮑謝，退避聲名稱學稼。',192,'全唐诗/poet.song.133000.json','["稼軒落筆凌鮑謝，退避聲名稱學稼。", "十年高卧不出門，參透南宗牧牛話。", "功名固是券內事，且葺園廬了婚嫁。", "千篇昌谷詩滿囊，萬卷鄴侯書插架。", "忽然起冠東諸侯，黄旗皂纛從天下。", "聖朝仄席意未快，尺一東來煩促駕。", "大材小用古所嘆，管仲蕭何實流亞。", "天山挂旆或少須，先挽銀河洗嵩華。", "中原麟鳳爭自奮，殘虜犬羊何足嚇。", "但令小試出緒餘，青史英豪可雄跨。", "古來立事戒輕發，往往讒夫出乘罅。", "深仇積憤在逆胡，不用追思灞亭夜。"]'),
('92c4df6e-96bb-4421-97ec-fafd04b38f5f','初夏','陸游','宋','宋诗','song-poetry','','[]','白白飺筒美，青青米果新。',48,'全唐诗/poet.song.133000.json','["白白飺筒美，青青米果新。", "衰遲重時節，薄少遍鄉鄰。", "梅市花成幄，蘭亭草作茵。", "極知歡意盡，强起伴遊人。"]'),
('3c227491-5eea-48af-b2db-1ca0ac16e9e1','自警','陸游','宋','宋诗','song-poetry','','[]','放翁原憒憒，徂歲復駸駸。',48,'全唐诗/poet.song.133000.json','["放翁原憒憒，徂歲復駸駸。", "社櫟終無用，秋蟲漫苦吟。", "拍蚊違殺戒，引水動機心。", "老耄誰規我，忠言抵萬金。"]'),
('de7364ce-e14a-42a1-905a-4d5004d22d1b','枕上','陸游','宋','宋诗','song-poetry','','[]','病叟少安枕，驚禽無穩棲。',48,'全唐诗/poet.song.133000.json','["病叟少安枕，驚禽無穩棲。", "慵占賈誼鵩，空感祖生雞。", "野勢風號北，窗痕月過西。", "元非破賊手，只合架牛犁。"]'),
('96855601-bb37-482f-b857-825922e7261c','野步至近村','陸游','宋','宋诗','song-poetry','','[]','耳目康寧手足輕，村墟草市徧經行。',64,'全唐诗/poet.song.133000.json','["耳目康寧手足輕，村墟草市徧經行。", "孝經章裏觀初學，麥飯香中喜太平。", "婦女相呼同夜績，比鄰竭作事春耕。", "勿言野饁無鹽酪，筍蕨何妨淡煮羹。"]'),
('9f53d2c8-0bc1-40a0-9ee6-3027a9218c26','書懷示子遹','陸游','宋','宋诗','song-poetry','','[]','平生山林幾緉屐，何意隨人戴朝幘。',192,'全唐诗/poet.song.133000.json','["平生山林幾緉屐，何意隨人戴朝幘。", "口言報國直妄耳，斷簡圍坐晨至夕。", "道山堂東直廬冷，手種疏篁半窗碧。", "但虞風波起平地，豈有毫髮能補益。", "成書朝奏暮請老，入耳幸免煩言嘖。", "東望故山百餘里，父老歡忻來接迹。", "白羊綠酒爭下擔，長笛腰鼓紛如織。", "迢迢梅市過魯墟，觀者所至空巷陌。", "爾來呻吟又春盡，周視室中惟四壁。", "但令糲飯粗撐拄，猶勝朱門常踧踖。", "小兒助我理孤學，終歲伏几心如石。", "問看飲酒詠離騷，何似焚香對周易。"]'),
('63d456e1-eb3f-4792-a355-2c3f4f48248e','三月三十夜聞杜宇','陸游','宋','宋诗','song-poetry','','[]','斗轉春歸不自由，韶華已逐水東流。',32,'全唐诗/poet.song.133000.json','["斗轉春歸不自由，韶華已逐水東流。", "子規獨抱區區意，血泪交零曉未休。"]'),
('4eb17329-d5aa-4ff8-b8df-e1420c169ff6','夜大雨連明晨起乃知之','陸游','宋','宋诗','song-poetry','','[]','黄紬被穩枕慵移，夜雨淋浪了不知。',64,'全唐诗/poet.song.133000.json','["黄紬被穩枕慵移，夜雨淋浪了不知。", "水長壞陂初復後，鳩鳴去婦却還時。", "芳蹊入夏多青子，白髮今年有黑絲。", "剩欲披衣湖上去，滿村芳草正離離。"]'),
('69cefb61-c8bb-4651-a012-87403c1f87d0','聞虜亂次前輩韵','陸游','宋','宋诗','song-poetry','','[]','中原昔喪亂，豺虎厭人肉。',72,'全唐诗/poet.song.133000.json','["中原昔喪亂，豺虎厭人肉。", "輦金輸虜庭，耳目久習熟。", "不知貪殘性，搏噬何日足。", "至今磊落人，泪盡以血續。", "後生志撫薄，誰辦新亭哭。", "藝祖有聖謨，嗚呼寧忍讀。"]'),
('9bc69af7-15a8-45ba-bae8-e1f8723ebe20','壯士吟次唐人韵','陸游','宋','宋诗','song-poetry','','[]','士厭貧賤思起家，富貴何在髮已華。',96,'全唐诗/poet.song.133000.json','["士厭貧賤思起家，富貴何在髮已華。", "不如爲國戍萬里，大寒破肉風卷沙。", "誓捐一死報天子，兜鍪如箕鎧如水。", "男兒墮地射四方，安能山棲效園綺。", "塞雲漠漠黄河深，凉州新城高十尋。", "風餐露宿寧非苦，且試平生鐵石心。"]'),
('9cefa6fb-4fc8-45a7-9ea9-71ea07a907e4','衰疾','陸游','宋','宋诗','song-poetry','','[]','衰疾猶能飯一簞，蓴絲菰首亦加餐。',64,'全唐诗/poet.song.133000.json','["衰疾猶能飯一簞，蓴絲菰首亦加餐。", "舊叨刻印俄銷印，老愧彈冠亟挂冠。", "自怪嵇康如許懶，人憐范叔不勝寒。", "得錢剩買青芒屨，采藥名山興未闌。"]'),
('81e0d103-c513-41b0-ba60-5f984fe98c33','書日用事二首  其一','陸游','宋','宋诗','song-poetry','','[]','左右數書冊，朝夕一草堂。',48,'全唐诗/poet.song.133000.json','["左右數書冊，朝夕一草堂。", "家貧自能儉，病愈不求方。", "盛饌豚肩美，常庖筍茁香。", "園丁報花坼，亦復命壺觴。"]'),
('c977a22e-56cf-4136-b6ce-11f308893a94','書日用事二首  其二','陸游','宋','宋诗','song-poetry','','[]','一裘良已暖，半菽可無饑。',48,'全唐诗/poet.song.133000.json','["一裘良已暖，半菽可無饑。", "養氣戒多語，端居如有思。", "私心須自勝，己過遣誰知。", "耄齒尤當勉，常憂寸晷移。"]'),
('7a3f0df1-f0b5-4398-8909-b1b5e07bf23e','初夏出遊','陸游','宋','宋诗','song-poetry','','[]','去去衝朝霧，行行弄夕霏。',72,'全唐诗/poet.song.133000.json','["去去衝朝霧，行行弄夕霏。", "移秧晴竭作，坐社醉扶歸。", "細草迷行徑，殘花點釣磯。", "牸牛將犢過，雄雉挾雌飛。", "野寺烟鐘遠，村墟績火微。", "諸孫殊可念，相喚候柴扉。"]'),
('27031cab-71be-44b4-ab27-0290fc4e1233','初夏晝眠','陸游','宋','宋诗','song-poetry','','[]','好景逢初夏，閑身得晝眠。',72,'全唐诗/poet.song.133000.json','["好景逢初夏，閑身得晝眠。", "書橫竹架上，冠墮素屏前。", "葱蒨小山桂，潺湲幽竇泉。", "危巢出乳燕，高樹集新蟬。", "强健關天命，逍遥近地仙。", "晚窗思茗飲，自取雪芽煎。"]'),
('65902719-1c0b-4a53-a8f7-f7699e2eaf8a','農事稍間有作','陸游','宋','宋诗','song-poetry','','[]','架犁架犁喚春農，布穀布穀督歲功。',120,'全唐诗/poet.song.133000.json','["架犁架犁喚春農，布穀布穀督歲功。", "黄雲壓簷風日美，綠針插水霧雨濛。", "年豐遠近笑語樂，浦漲縱橫舟楫通。", "東家筑室窗戶綠，西舍迎婦花扇紅。", "我方祭竈徹豚酒，盤箸亦復呼鄰翁。", "客歸我起何所作，孝經論語教兒童。", "教兒童，莫匆匆，願汝日夜勤磨礱，烏巾白紵待至公。"]'),
('e49aaf06-71f3-4e77-8f36-0b05f84d4a07','夜雨','陸游','宋','宋诗','song-poetry','','[]','暮雨蕭蕭集瓦溝，空階點滴送清愁。',32,'全唐诗/poet.song.133000.json','["暮雨蕭蕭集瓦溝，空階點滴送清愁。", "何由乞得須臾睡，直到窗明滴未休。"]'),
('74bdcb5d-ffcc-4004-9467-ef2e239e12eb','朝晴','陸游','宋','宋诗','song-poetry','','[]','宿雨初收雲四歸，小山草木麗朝暉。',32,'全唐诗/poet.song.133000.json','["宿雨初收雲四歸，小山草木麗朝暉。", "翩然雙鵲從簷下，言語分明訴溼衣。"]'),
('3c9e9681-6fa3-4fc8-9a07-d27c7e5aca80','北窗','陸游','宋','宋诗','song-poetry','','[]','簾影參差午漏前，盆山綠潤雨餘天。',64,'全唐诗/poet.song.133000.json','["簾影參差午漏前，盆山綠潤雨餘天。", "詩無傑句真衰矣，酒借朱顔却悵然。", "海燕理巢知再乳，吳蠶放食過三眠。", "名泉不負吾兒意，一掬丁坑手自煎。"]'),
('7041f491-e723-443a-aee5-aa7181ca46c8','遊山戲作','陸游','宋','宋诗','song-poetry','','[]','晚境頻辭祿，窮居旋學耕。',48,'全唐诗/poet.song.133000.json','["晚境頻辭祿，窮居旋學耕。", "量衰添酒敵，才盡減詩名。", "風月成交友，溪山管送迎。", "登車雨先止，天豈相吾行。"]'),
('7ea66a4a-4df3-45f3-929e-18febf9d0776','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','聒聒鳴鳩莫笑渠，百年我亦旋枝梧。',64,'全唐诗/poet.song.133000.json','["聒聒鳴鳩莫笑渠，百年我亦旋枝梧。", "病知藥物難爲驗，老覺人間不足娛。", "茆屋何妨度寒暑，蔬餐且可遣朝晡。", "釣船一出無尋處，千頃江邊雪色蘆。"]'),
('446528ee-d57b-4cfa-9f30-907f67e471c8','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','老荷君恩許醉眠，散人名號愧妨賢。',64,'全唐诗/poet.song.133000.json','["老荷君恩許醉眠，散人名號愧妨賢。", "久叨物外清閑福，粗識詩中造化權。", "風月四時隨指顧，乾坤一氣入陶甄。", "新秋更欲浮滄海，卧看雲帆萬里天。"]'),
('5a886bce-1dc0-4dbe-8784-16c15150cbdf','細雨','陸游','宋','宋诗','song-poetry','','[]','細雨重雲漸入梅，陰陰門巷長新槐。',64,'全唐诗/poet.song.133000.json','["細雨重雲漸入梅，陰陰門巷長新槐。", "壯心已與年俱逝，脫髮應無術可栽。", "美睡常嫌鶯喚起，清愁却要酒闌回。", "年來百事非平昔，信手題詩懶剪裁。"]'),
('6f706c96-6d2e-4ab0-8030-6792614e7191','初暑','陸游','宋','宋诗','song-poetry','','[]','槐陰清潤麥風凉，一枕閑眠晝漏長。',64,'全唐诗/poet.song.133000.json','["槐陰清潤麥風凉，一枕閑眠晝漏長。", "山鵲喜晴當戶語，海桐带露入簾香。", "酒緣久病常辭酌，茶爲前銜偶得嘗。", "雲北雲南動遊興，速呼小豎治輕裝。"]'),
('b573d500-22e2-4e82-8796-c9e36f6644c4','夙興','陸游','宋','宋诗','song-poetry','','[]','夙興短蓬髮，幽步豁煩襟。',48,'全唐诗/poet.song.133000.json','["夙興短蓬髮，幽步豁煩襟。", "翠碧停闌角，黧黄語柳陰。", "書殘頻補緝，琴廢細追尋。", "未是全無事，猶堪養道心。"]'),
('998b836e-251c-481b-9a5c-512a17ad6a12','新堂','陸游','宋','宋诗','song-poetry','','[]','湖上新堂氣疏豁，三面嵐光翠如潑。',64,'全唐诗/poet.song.133000.json','["湖上新堂氣疏豁，三面嵐光翠如潑。", "都門歸來病相屬，鄰里怪我間何闊。", "蓴絲作羹飯雕胡，厨人斫鱠藝絕殊。", "何由喚得左元放，銀盤釣出松江鱸。"]'),
('3e51e5ad-cfb6-4824-92e2-27efe81c8876','即席四首  其一','陸游','宋','宋诗','song-poetry','','[]','稚荷出水榴花開，長笛圜鼙送舉杯。',32,'全唐诗/poet.song.133000.json','["稚荷出水榴花開，長笛圜鼙送舉杯。", "村鄰相樂君勿笑，要是安健無兇災。"]'),
('780d78ff-67fe-4f18-8d68-fa87ba5c084c','即席四首  其二','陸游','宋','宋诗','song-poetry','','[]','醉中起舞遞相屬，坐上戴花常作先。',32,'全唐诗/poet.song.133000.json','["醉中起舞遞相屬，坐上戴花常作先。", "要知吾輩不凡處，一吸已乾雙玉船。"]'),
('d2e9ac41-bf1d-42bc-8ca6-0891b8652aeb','即席四首  其三','陸游','宋','宋诗','song-poetry','','[]','長魚腹腴羊臂臑，饞想久矣無秋毫。',32,'全唐诗/poet.song.133000.json','["長魚腹腴羊臂臑，饞想久矣無秋毫。", "今朝林下煨苦筍，更覺此君風味高。"]'),
('4e02e2eb-42e5-44c2-848f-9b90a83305f2','即席四首  其四','陸游','宋','宋诗','song-poetry','','[]','小山榴花照眼明，青梅自墮時有聲。',32,'全唐诗/poet.song.133000.json','["小山榴花照眼明，青梅自墮時有聲。", "柳橋東岸倚筇立，聊借水風吹宿酲。"]'),
('fb6521e9-fb2d-4e0b-8c22-ffde8b97be15','生涯','陸游','宋','宋诗','song-poetry','','[]','久矣冥行墮嶮巇，樂哉偶得謝招麾。',64,'全唐诗/poet.song.133000.json','["久矣冥行墮嶮巇，樂哉偶得謝招麾。", "放懷身世相忘地，夙駕山林獨往時。", "縱老豈容妨痛飲，更慵亦未廢新詩。", "超然自喜生涯別，始嘆龜堂見事遲。"]'),
('209bdc39-4bd0-41ae-b922-0a2ebbfd7647','落花','陸游','宋','宋诗','song-poetry','','[]','桃李擅春事，酴醿爲之殿。',96,'全唐诗/poet.song.133000.json','["桃李擅春事，酴醿爲之殿。", "豈不欲周旋，過日如掣電。", "大風連三日，吹盡無餘片。", "留之豈有策，佇立情眷眷。", "空令腸九回，竟欠語一轉。", "流年付芳草，樽酒孤勝踐。", "鶯聲入碧雲，簾影滿深院。", "消摇綠陰間，風流屬團扇。"]'),
('441e63d2-f0d1-42c5-aa45-5728b269614c','四月廿二日微雨中次前輩韵','陸游','宋','宋诗','song-poetry','','[]','語訛覺齒疏，冠倒感髮稀。',72,'全唐诗/poet.song.133000.json','["語訛覺齒疏，冠倒感髮稀。", "屢爲曼容免，遂賦淵明歸。", "今日天氣佳，雨絲弄斜暉。", "起居惟所適，單複時易衣。", "出遊叩僧廬，歸卧掩漁扉。", "一笑顧兒子，正爾良未非。"]'),
('7eb0e1ac-1d72-4844-89b6-d6537514fd05','夜雨','陸游','宋','宋诗','song-poetry','','[]','點滴茅簷雨，長宵不肯晴。',48,'全唐诗/poet.song.133000.json','["點滴茅簷雨，長宵不肯晴。", "殘缸待雞唱，倦枕厭梟鳴。", "已踐衰殘境，况兼羈旅情。", "晨興亦何事，椎髻繞廊行。"]'),
('92bc51dc-1bca-4e59-89aa-c4ab48b723dc','夏日','陸游','宋','宋诗','song-poetry','','[]','入戶桐陰漸覆床，乍敷笛簟北窗凉。',64,'全唐诗/poet.song.133000.json','["入戶桐陰漸覆床，乍敷笛簟北窗凉。", "筇枝倚壁知身健，衣焙殘香覺日長。", "雨霽斷雲時聚散，風來纖草久低昂。", "蝶衣粉溼猶飛懶，小駐闌干就夕陽。"]'),
('df5c21a1-71df-4166-838a-2b6b5bbcf6c2','久雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','梅子青青苦未黄，經旬積雨欲頹牆。',64,'全唐诗/poet.song.133000.json','["梅子青青苦未黄，經旬積雨欲頹牆。", "蠹生書帙時須火，潤入衣篝剩得香。", "鄰舍相逢驚間闊，通宵不寐聽淋浪。", "定知又發韓公笑，有底鳴蛙兩股長。"]'),
('a10cccda-6fe7-4a6a-a580-668fe0926ce1','久雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','梅天一日幾陰晴，對酒無聊醉不成。',64,'全唐诗/poet.song.133000.json','["梅天一日幾陰晴，對酒無聊醉不成。", "巧曆莫能知雨點，孤桐那解寫溪聲。", "林深鳥爵來無數，草茂鋤耰去即生。", "明日雲開天萬里，御風吾欲過青城。"]'),
('aa3464bb-825d-4ee4-8e9d-31aa88645d2d','舟中','陸游','宋','宋诗','song-poetry','','[]','青楓湖上村，綠蓑舟中客。',72,'全唐诗/poet.song.133000.json','["青楓湖上村，綠蓑舟中客。", "雲興山疊見，海近地勢坼。", "悠然滄洲趣，宛與塵世隔。", "雖云食不足，粗免婚嫁責。", "渥丹未辭鏡，衰白幸滿幘。", "明當鼓枻行，放浪窮七澤。"]'),
('c4db02e8-18d7-4272-9e5b-be079acfe36b','繫船','陸游','宋','宋诗','song-poetry','','[]','高樹滴殘雨，叢蘆生夕風。',48,'全唐诗/poet.song.133000.json','["高樹滴殘雨，叢蘆生夕風。", "惰遊貧有自，老鈍學無功。", "歲月詩編裏，江湖旅色中。", "烟村繫船處，邂逅得漁翁。"]'),
('e8e72178-15fe-4eff-88e7-641ff24a1e7a','復雨','陸游','宋','宋诗','song-poetry','','[]','催喚兒童掃綠苔，長歌清嘯興悠哉。',64,'全唐诗/poet.song.133000.json','["催喚兒童掃綠苔，長歌清嘯興悠哉。", "林間子墮知梅熟，水面痕生驗雨來。", "往事已成孤枕夢，故人誰共一樽開。", "自憐未負年華在，素扇團團月樣裁。"]'),
('22942e7c-d19d-4597-bd81-31ad9ce3ee32','書適','陸游','宋','宋诗','song-poetry','','[]','清和巷陌單衣後，綠潤軒窗午餉餘。',64,'全唐诗/poet.song.133000.json','["清和巷陌單衣後，綠潤軒窗午餉餘。", "曲曲素屏圍倦枕，斜斜筠架閣殘書。", "松陰坐石閑看鶴，山寺尋僧晚跨驢。", "此段家風君試看，京塵撲帽獨何歟。"]'),
('0a1d4a5c-ddfd-4f97-8b51-1d43cbab1b1f','村社禱晴有應','陸游','宋','宋诗','song-poetry','','[]','叢祠牲酒走村村，賴是龍歸爲解紛。',64,'全唐诗/poet.song.133000.json','["叢祠牲酒走村村，賴是龍歸爲解紛。", "爽氣收回騎月雨，快風散盡滿天雲。", "數峰縹緲如屏面，一浦漣漪作簟紋。", "猶勝楚人簫鼓裏，九歌哀怨下湘君。"]'),
('8833bf95-3acf-4151-b83c-ca76900cb4ea','題北窗二首  其一','陸游','宋','宋诗','song-poetry','','[]','束擔還山讀舊書，斷編終日見唐虞。',64,'全唐诗/poet.song.133000.json','["束擔還山讀舊書，斷編終日見唐虞。", "千莖白髮年華速，一點青燈夜漏徂。", "厚價異時空市骨，大呼從昔不成盧。", "細思天賦原非薄，跬步門前萬頃湖。"]'),
('d8a9c65b-4494-4c95-bbe0-07977e308a0b','題北窗二首  其二','陸游','宋','宋诗','song-poetry','','[]','不嗔人作腐儒看，斷簡堆中興未闌。',64,'全唐诗/poet.song.133000.json','["不嗔人作腐儒看，斷簡堆中興未闌。", "更事愈懷憂國切，苦心始覺著書難。", "流泉激激人聲遠，修竹蕭蕭暑令寒。", "四海諸公常共處，北窗何地著身寬。"]'),
('02b71a79-4b08-489f-a218-74739e0e343f','晝坐聞牆外人聲殊敗幽思戲作','陸游','宋','宋诗','song-poetry','','[]','老人氣衰凋髮齒，歲月翩翩來有幾。',96,'全唐诗/poet.song.133000.json','["老人氣衰凋髮齒，歲月翩翩來有幾。", "晨興食米不一溢，日課讀書猶十紙。", "雖云喧寂無二觀，終嫌蜩蚻喧吾耳。", "亟起振衣欲出門，赤日當空汗如洗。", "撥灰未炷瓦爐香，汲井先換銅匜水。", "也勝太史落南時，短檠夜對屠牛机。"]'),
('ab138d8c-ec0e-4a90-b664-916120dea82d','晨起行園中','陸游','宋','宋诗','song-poetry','','[]','老病厭囂煩，晨興步小園。',48,'全唐诗/poet.song.133000.json','["老病厭囂煩，晨興步小園。", "草深移舊路，竹茂失頹垣。", "未暇從魚樂，惟思與石言。", "人家尋每得，拄杖印苔痕。"]'),
('782d8642-10ce-4e42-b587-0935ec920b88','葺舍','陸游','宋','宋诗','song-poetry','','[]','蟻知將雨先移穴，燕護新雛迭守巢。',32,'全唐诗/poet.song.133000.json','["蟻知將雨先移穴，燕護新雛迭守巢。", "補漏支傾吾可笑，呼奴乘屋更添茅。"]'),
('ee6442f3-b1ac-4f4d-b016-1c02bdda3874','次韵林伯玉登卧龍','陸游','宋','宋诗','song-poetry','','[]','一紙臨門喜欲顛，詞源滾滾瀉長川。',64,'全唐诗/poet.song.133000.json','["一紙臨門喜欲顛，詞源滾滾瀉長川。", "旗旄外閫新元帥，風月名山古洞天。", "自笑屏居依近郭，每煩登望指孤烟。", "雄篇三復空興嘆，窮乃工詩似不然。"]'),
('dbc551fe-0721-439a-b855-bd0fe00603d1','道室雜詠六首  其一','陸游','宋','宋诗','song-poetry','','[]','精神有限惟當嗇，造化無心不汝私。',32,'全唐诗/poet.song.133000.json','["精神有限惟當嗇，造化無心不汝私。", "此事安須知决擇，雞鳴勿後老人期。"]'),
('09a96163-41af-45de-9853-7e3c2fa3faf0','道室雜詠六首  其二','陸游','宋','宋诗','song-poetry','','[]','黄褐長絳七尺身，袖中一劍隱紅塵。',32,'全唐诗/poet.song.133000.json','["黄褐長絳七尺身，袖中一劍隱紅塵。", "城門萬屨日來往，眾裏安知無此人。"]'),
('f96a7a2f-aaae-4193-9aaa-b30533af0cca','道室雜詠六首  其三','陸游','宋','宋诗','song-poetry','','[]','冰霜難與夏蟲語，晦朔豈容朝菌知。',32,'全唐诗/poet.song.133000.json','["冰霜難與夏蟲語，晦朔豈容朝菌知。", "忿慾至前能小忍，人人券內有期頤。"]'),
('c2014c72-4ceb-407e-bc4b-ec0b67c8e512','道室雜詠六首  其四','陸游','宋','宋诗','song-poetry','','[]','萬法元須一理通，長生極治本同功。',32,'全唐诗/poet.song.133000.json','["萬法元須一理通，長生極治本同功。", "廣成千歲無它術，祇在唐虞二典中。"]'),
('b409814e-c4ef-45bc-a50c-71f3b93b3c40','道室雜詠六首  其五','陸游','宋','宋诗','song-poetry','','[]','莫緣侯印學陰謀，生世惟須一釣舟。',32,'全唐诗/poet.song.133000.json','["莫緣侯印學陰謀，生世惟須一釣舟。", "輕用鏌铘終折缺，善刀何止解千牛。"]'),
('b14c1e5d-aaa1-4b75-b03d-6f3cc9660880','道室雜詠六首  其六','陸游','宋','宋诗','song-poetry','','[]','放翁耄齒猶朱顔，一物不留方寸間。',32,'全唐诗/poet.song.133000.json','["放翁耄齒猶朱顔，一物不留方寸間。", "已吞八九雲夢澤，更著百億須彌山。"]'),
('72ff7099-c5af-487a-822a-de521fa5614d','湖塘夜歸','陸游','宋','宋诗','song-poetry','','[]','漁翁江上佩笭箵，一卷新傳范蠡經。',64,'全唐诗/poet.song.133000.json','["漁翁江上佩笭箵，一卷新傳范蠡經。", "鬰鬰林間桑椹紫，芒芒水面稻苗青。", "雲邊筑舍分南北，陌上逢人半醉醒。", "莫恨西村歸路遠，行前點點有飛螢。"]'),
('1f4c567d-a92e-4c24-a862-6f4fa245109f','東軒','陸游','宋','宋诗','song-poetry','','[]','僻巷地無喧，閑人慮不煩。',48,'全唐诗/poet.song.133000.json','["僻巷地無喧，閑人慮不煩。", "刺舟回北渚，岸幘倚東軒。", "乳鵲行苔徑，馴麞觸筍藩。", "作勞憐野老，喚取倒清樽。"]'),
('332242a6-7256-4d04-b21c-f8bc592a079b','夏日','陸游','宋','宋诗','song-poetry','','[]','例謝門前客，深藏篋裏書。',48,'全唐诗/poet.song.133000.json','["例謝門前客，深藏篋裏書。", "衣穿但重補，飯足不求餘。", "山溜鳴庭際，藤陰接屋除。", "何勞厭三伏，俯仰即秋初。"]'),
('83bf7509-ee5d-4f22-8382-f93b24bdbb71','斫膾','陸游','宋','宋诗','song-poetry','','[]','玉盤行膾簇青紅，輸與山家淡煮菘。',32,'全唐诗/poet.song.133000.json','["玉盤行膾簇青紅，輸與山家淡煮菘。", "要識坐堂哀觳觫，試來臨水看噞喁。"]'),
('396387a5-e0ab-4865-9c71-b194626abcfa','野飯','陸游','宋','宋诗','song-poetry','','[]','六十日白可續飯，三千年清何與人。',32,'全唐诗/poet.song.133000.json','["六十日白可續飯，三千年清何與人。", "堪笑此翁頑似鐵，還山又食一番新。"]'),
('87806609-400e-42bc-9fd9-d6f68e94a0b8','村酒','陸游','宋','宋诗','song-poetry','','[]','亂山落日漁歌長，平疇遠風粳稻香。',32,'全唐诗/poet.song.133000.json','["亂山落日漁歌長，平疇遠風粳稻香。", "酒旗摇摇截官道，歸家未遲君試嘗。"]'),
('5e1a70a1-9491-4e68-9461-a7430268dd02','避雨','陸游','宋','宋诗','song-poetry','','[]','雲如壞山欲塞海，樹似奇鬼將搏人。',32,'全唐诗/poet.song.133000.json','["雲如壞山欲塞海，樹似奇鬼將搏人。", "急投民家雨隨至，燎衣不覺雞唱晨。"]'),
('80ee6473-d401-4220-9408-95c67bd51001','雨中短歌','陸游','宋','宋诗','song-poetry','','[]','昨夕雨大如車軸，今旦雨細如牛毛。',96,'全唐诗/poet.song.133000.json','["昨夕雨大如車軸，今旦雨細如牛毛。", "人言愈細愈澤物，天公爲此非徒勞。", "泥深入市路欲絕，壞簷敗壁風蕭騷。", "豈惟蛙黽矜得意，坐覺藜莠無由薅。", "剝床供爨嗟婢子，持傘上學憐兒曹。", "村場酒貴賒不得，且解布囊尋弊袍。"]'),
('a2c7c88b-3537-4ac3-83de-db4982956ba9','散懷','陸游','宋','宋诗','song-poetry','','[]','少年已遂遯山林，何况霜毛兩鬢侵。',64,'全唐诗/poet.song.133000.json','["少年已遂遯山林，何况霜毛兩鬢侵。", "習氣尚存詩入夢，病根未去藥關心。", "猿知秋近啼先苦，鶴閱年多頂漸深。", "不忍頓疏風月在，粗能扶杖即登臨。"]'),
('35d8957a-7f87-43f7-8858-3cdacc924e9e','南堂','陸游','宋','宋诗','song-poetry','','[]','空堂寂寂暑氣清，祇有燕雀無人聲。',96,'全唐诗/poet.song.133000.json','["空堂寂寂暑氣清，祇有燕雀無人聲。", "雲頭忽移簾影失，雨點亂集荷盤傾。", "溝坑水溢魚鱉喜，庭戶風送蛟龍腥。", "衣巾汗垢爲一洗，呼奴舉榻臨前楹。", "取泉石井試日鑄，吾詩邂逅亦已成。", "何由探借中秋月，與子同遊白玉京。"]'),
('39170815-a310-4c42-aecf-d4480023a742','門屋納凉','陸游','宋','宋诗','song-poetry','','[]','機裂齊紈如素月，床敷蘄簟起微瀾。',64,'全唐诗/poet.song.133000.json','["機裂齊紈如素月，床敷蘄簟起微瀾。", "行人遠不分眉目，過鳥高猶響羽翰。", "新長庭槐夾門綠，無窮陂稻際天寬。", "今年項里楊梅熟，火齊驪珠已滿盤。"]'),
('f03dc7f5-19b2-4ae5-a686-8ff72b5d7bac','幽居','陸游','宋','宋诗','song-poetry','','[]','孤村野徑不曾鋤，惡草從來一寸無。',64,'全唐诗/poet.song.133000.json','["孤村野徑不曾鋤，惡草從來一寸無。", "每爲遊魚疏港瀆，更緣啼鳥植楸梧。", "閑門猶有僧時到，殘產渾無賦未輸。", "浪走人間真誤計，暮年猶足補東隅。"]'),
('008b59bc-b748-4fa7-8cce-eddccaff7bc0','露坐','陸游','宋','宋诗','song-poetry','','[]','殘月久方上，幽花時自零。',48,'全唐诗/poet.song.133000.json','["殘月久方上，幽花時自零。", "風枝驚宿鳥，露草溼流螢。", "浩氣吞雲夢，危途塞井陘。", "菱歌何處起，及我醉初醒。"]'),
('77324939-5c02-449b-aa1b-ebeaec927db9','暑中久不把酒盆池千葉白蓮忽開一枝欣然小酌因賦絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','千葉芙蕖白玉膚，一樽沆瀣碧琳腴。',32,'全唐诗/poet.song.133000.json','["千葉芙蕖白玉膚，一樽沆瀣碧琳腴。", "極知俱出氛埃外，我亦秋風山澤臞。"]'),
('ca18f566-ee8f-4ddd-8cdf-ef213cbcbb45','暑中久不把酒盆池千葉白蓮忽開一枝欣然小酌因賦絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','我讀淵明止酒篇，知渠未識玉池僊。',32,'全唐诗/poet.song.133000.json','["我讀淵明止酒篇，知渠未識玉池僊。", "誰言見面無多子，高壓天魔萬二千。"]'),
('f3902b1e-5efe-492a-a0b6-7dce303b3338','老馬','陸游','宋','宋诗','song-poetry','','[]','貧家畜老馬，枯萁風雨噍。',72,'全唐诗/poet.song.133000.json','["貧家畜老馬，枯萁風雨噍。", "本非百金產，安用三品料。", "馬固忘華廄，士亦安蓬藋。", "兩窮適相遭，萬事付一笑。", "少游御款段，作計無此妙。", "可憐杜陵翁，妄想追風驃。"]'),
('bfa93e98-2110-40a5-bc50-e7c214bcedc1','大熱','陸游','宋','宋诗','song-poetry','','[]','五月頗閔雨，炎風吹旱塵。',72,'全唐诗/poet.song.133000.json','["五月頗閔雨，炎風吹旱塵。", "氣羸不給喘，流汗沾衣巾。", "呼婢使具浴，報以未買薪。", "汝事雖不恪，亦坐乃翁貧。", "汲井掬寒泉，自足忘我嗔。", "譬如寓逆旅，百事聽主人。"]'),
('fcd5b286-2ee5-4a22-9de1-08edb9541754','大雨','陸游','宋','宋诗','song-poetry','','[]','今年景氣佳，有禱神必答。',144,'全唐诗/poet.song.133000.json','["今年景氣佳，有禱神必答。", "時時雖閔雨，顧盼即霑洽。", "綿地千里間，四月秧盡插。", "季夏雨三日，凄爽欲忘箑。", "潴水如塞河，决水如放閘。", "几席亂蛙黽，庭除泳鵝鴨。", "舍邊魚受釣，戶外鷗可狎。", "飛螢最得意，終夕自開闔。", "蕭蕭菰蒲聲，怳若船入夾。", "嗟予亦耐事，堅坐書滿榻。", "懸知䆉䅉收，已足供伏臘。", "會約張志和，清風泛苕霅。"]'),
('2362c953-a349-4f29-ae4d-e40ca3030bcc','午睡','陸游','宋','宋诗','song-poetry','','[]','梅黄雨足喜初晴，投枕華胥夢已成。',64,'全唐诗/poet.song.133000.json','["梅黄雨足喜初晴，投枕華胥夢已成。", "帳底香雲凝未散，手中書卷墮無聲。", "簟紋似水飛蠅避，鼻息如雷稚子驚。", "癡腹便便竟何有，已將嘲弄付諸生。"]'),
('8888e6d0-7143-4737-8b3d-fc3f3b5a3f29','書意','陸游','宋','宋诗','song-poetry','','[]','疏慵久矣卧郊扉，暫出人間輒免歸。',64,'全唐诗/poet.song.133000.json','["疏慵久矣卧郊扉，暫出人間輒免歸。", "梵志放花常恨晚，士師分鹿又成非。", "平生舊學寧當負，同志良箴亦重違。", "說與吾兒勤念此，負禾勿恨露沾衣。"]'),
('32e5d913-7b33-45e2-8939-742ce510746c','卜居三山已四十年矣暇日有感聊賦五字二首  其一','陸游','宋','宋诗','song-poetry','','[]','薄宦非初志，幽居不計年。',48,'全唐诗/poet.song.133000.json','["薄宦非初志，幽居不計年。", "稚松成偃蓋，小豎亦華顛。", "生理憑耕稼，光陰付醉眠。", "從來慕園綺，一著要爭先。"]'),
('e202149c-e2b3-4dc3-b7e7-8a286fdc30e7','卜居三山已四十年矣暇日有感聊賦五字二首  其二','陸游','宋','宋诗','song-poetry','','[]','泥古衰猶學，開荒夜亦耕。',48,'全唐诗/poet.song.133000.json','["泥古衰猶學，開荒夜亦耕。", "屋芟生草蓋，釜擷野蔬烹。", "白稻雨中熟，黄鴉桑下鳴。", "殘雲忽吐日，喜對小窗明。"]'),
('118847d3-8abd-4419-8a2d-af74e981353b','北窗','陸游','宋','宋诗','song-poetry','','[]','北窗無俗物，三伏有餘凉。',48,'全唐诗/poet.song.133000.json','["北窗無俗物，三伏有餘凉。", "玉麈消長日，風漪可一床。", "盞分新作茗，爐撥欲殘香。", "却岸紗巾去，翛然野水傍。"]'),
('5867cd6f-3f74-4af1-ac0d-a9c1a2152700','睡起已亭午終日凉甚有賦','陸游','宋','宋诗','song-poetry','','[]','飯罷頹然付一床，曠懷真足傲羲皇。',64,'全唐诗/poet.song.133000.json','["飯罷頹然付一床，曠懷真足傲羲皇。", "松棚盡日常如暮，荷沼無風亦自香。", "倚杖月生人影瘦，岸巾露透髮根凉。", "頗聞王旅徂征近，敷水條山興已狂。"]'),
('1fb72b85-90be-4e96-ad9a-594545990bb4','殘雨','陸游','宋','宋诗','song-poetry','','[]','五更殘雨滴簷頭，探借天公一月秋。',32,'全唐诗/poet.song.133000.json','["五更殘雨滴簷頭，探借天公一月秋。", "只道風吹雲散盡，數聲桑下又鳴鳩。"]'),
('8d14e082-4115-47a4-a978-0fba19ab7ab2','溪上避暑二首  其一','陸游','宋','宋诗','song-poetry','','[]','暮年事業轉悠悠，盡日投竿杜若洲。',64,'全唐诗/poet.song.133000.json','["暮年事業轉悠悠，盡日投竿杜若洲。", "世上漫言天愛酒，古來寧有地埋憂。", "全家只合雲山老，萬事空驚歲月遒。", "褫带脫冠猶病暍，正平頗憶著岑牟。"]'),
('9bafdc1d-9fc7-4cfa-9258-8ed435217e7d','溪上避暑二首  其二','陸游','宋','宋诗','song-poetry','','[]','短髮颼颼徹頂凉，悠哉隨處據胡床。',64,'全唐诗/poet.song.133000.json','["短髮颼颼徹頂凉，悠哉隨處據胡床。", "但憐鵲影翻殘月，不恨蟬聲送夕陽。", "門巷陰陰桐葉暗，汀洲漠漠藕花香。", "寓形宇內終煩促，安得騎鯨下大荒。"]'),
('d7e6a3ba-0c81-4584-b9fa-cce7aae5c5a6','龜堂避暑','陸游','宋','宋诗','song-poetry','','[]','縹緲紗厨覆象床，蠻童擎粥進黄粱。',64,'全唐诗/poet.song.133000.json','["縹緲紗厨覆象床，蠻童擎粥進黄粱。", "硯池湛湛一泓墨，衣焙霏霏半篆香。", "團扇題詩無滯思，清泉灑地有餘凉。", "更須風伯開雲陣，準擬今宵月滿廊。"]'),
('9ca559b6-2ac6-4565-96bc-f23e9fb4d8a1','旅舍偶題','陸游','宋','宋诗','song-poetry','','[]','野店山橋策蹇驢，浩然聊喜遂吾初。',64,'全唐诗/poet.song.133000.json','["野店山橋策蹇驢，浩然聊喜遂吾初。", "童顔幾歲已辭鏡，胎髮今朝還入梳。", "小甕謾營秋社酒，斷編閑理小年書。", "白雲可笑猶多事，常向人間耐卷舒。"]'),
('8b177baf-1cf9-452b-be3d-73704fd98f1d','溪月','陸游','宋','宋诗','song-poetry','','[]','天風吹髮冷颼颼，獨向沙邊上釣舟。',32,'全唐诗/poet.song.133000.json','["天風吹髮冷颼颼，獨向沙邊上釣舟。", "愁絕平羌江上月，向人依舊半輪秋。"]'),
('aef4654a-256f-4bf9-9db7-d1823836f2c8','砭愚','陸游','宋','宋诗','song-poetry','','[]','儲藥如丘壟，人愚未易醫。',48,'全唐诗/poet.song.133000.json','["儲藥如丘壟，人愚未易醫。", "信書安用盡，見事可憐遲。", "錯自彈冠日，憂從識字時。", "今朝北窗卧，句句味陶詩。"]'),
('57c7c3a1-f5c9-4d26-9fd4-bb7407d35ae2','雜興十首  其一','陸游','宋','宋诗','song-poetry','','[]','早遇齊侯遊柏寢，晚從漢帝祀甘泉。',32,'全唐诗/poet.song.133000.json','["早遇齊侯遊柏寢，晚從漢帝祀甘泉。", "不須苦學飛騰術，更看泥金檢玉年。"]'),
('b6e054c9-ac54-4555-bc06-e7afca399f49','雜興十首  其二','陸游','宋','宋诗','song-poetry','','[]','南山手自斸蒼苔，竹閣柴扉次第開。',32,'全唐诗/poet.song.133000.json','["南山手自斸蒼苔，竹閣柴扉次第開。", "二十里間雲不斷，豈容一點市塵來。"]'),
('0961f565-f5ad-49ea-8764-22c139b6c11d','雜興十首  其三','陸游','宋','宋诗','song-poetry','','[]','靈府寧容一物侵，此身只合老山林。',32,'全唐诗/poet.song.133000.json','["靈府寧容一物侵，此身只合老山林。", "何由挽得銀河水，凈洗群生忿慾心。"]'),
('51a169a2-c4c1-4e41-9755-b9b7f79f0d90','雜興十首  其四','陸游','宋','宋诗','song-poetry','','[]','赤米熟炊元自軟，黄齏頻倒不多酸。',32,'全唐诗/poet.song.133000.json','["赤米熟炊元自軟，黄齏頻倒不多酸。", "縱令酒負尋常債，也勝人求本分官。"]'),
('5ab0a340-d167-4e37-bba1-fda28ac69282','雜興十首  其五','陸游','宋','宋诗','song-poetry','','[]','冰壺冷浸玉芙蕖，三伏炎蒸一點無。',32,'全唐诗/poet.song.133000.json','["冰壺冷浸玉芙蕖，三伏炎蒸一點無。", "凈洗硯池潴墨瀋，乘凉要答故人書。"]'),
('45edeb3a-e8bf-40c4-b088-c09e1731330a','雜興十首  其六','陸游','宋','宋诗','song-poetry','','[]','硯傳百歲璽闕角，筆擅一時錐出囊。',32,'全唐诗/poet.song.133000.json','["硯傳百歲璽闕角，筆擅一時錐出囊。", "紙欲窮時瘦蛟舉，已看雷雨跨蒼茫。"]'),
('fb51b55e-cd3e-4891-970d-99297358049c','雜興十首  其七','陸游','宋','宋诗','song-poetry','','[]','扁舟夜載石帆月，雙屨曉穿天柱雲。',32,'全唐诗/poet.song.133000.json','["扁舟夜載石帆月，雙屨曉穿天柱雲。", "八十老翁能辦此，不須身將渡遼軍。"]'),
('e86ebe61-5f5c-4b30-8d5f-0c8e19245e6a','雜興十首  其八','陸游','宋','宋诗','song-poetry','','[]','犀象本安山海遠，楩楠豈願棟梁材。',32,'全唐诗/poet.song.133000.json','["犀象本安山海遠，楩楠豈願棟梁材。", "伏波病困壺頭日，應有嚴光入夢來。"]'),
('44f4f941-b876-417a-853a-ec2153efd05d','雜興十首  其九','陸游','宋','宋诗','song-poetry','','[]','粟無人饋方差快，門有僧敲未絕幽。',32,'全唐诗/poet.song.133000.json','["粟無人饋方差快，門有僧敲未絕幽。", "豈是耄荒深絕物，從來不慣惹閑愁。"]'),
('e5cc77f6-3a4e-4e27-acb8-7969384694a2','雜興十首  其一○','陸游','宋','宋诗','song-poetry','','[]','瞿聃楊墨寧非學，治獄行兵亦有師。',32,'全唐诗/poet.song.133000.json','["瞿聃楊墨寧非學，治獄行兵亦有師。", "惟是儒生知擇術，百年窮達守書詩。"]'),
('5a901031-bcbf-4ed1-883b-e3552ac46a65','病瘧兩作而愈','陸游','宋','宋诗','song-poetry','','[]','久出天魔境，胡爲瘧鬼來。',48,'全唐诗/poet.song.133000.json','["久出天魔境，胡爲瘧鬼來。", "亦知無妄疾，畢竟不爲災。", "引睡須書卷，支羸賴粥杯。", "微風起秋色，樽酒亦時開。"]'),
('7cf7f054-1d3f-4145-89f5-65ffbb132f76','露坐','陸游','宋','宋诗','song-poetry','','[]','略彴方塘北，篔簹小塹東。',48,'全唐诗/poet.song.133000.json','["略彴方塘北，篔簹小塹東。", "荷盤傾夕露，芡觜坼秋風。", "磔磔禽移樹，芒芒月墮空。", "詩材隨處足，盡付苦吟中。"]'),
('090005d1-5bff-4527-a614-f50ae3cf9931','戲詠','陸游','宋','宋诗','song-poetry','','[]','歲曆還逾半，人生但可悲。',48,'全唐诗/poet.song.133000.json','["歲曆還逾半，人生但可悲。", "此身猶老健，隨處且兒嬉。", "累瓦初成塔，埋盆又作池。", "惟應上庭樹，不及髧髦時。"]'),
('27009c61-c717-4973-9986-0378e47b1e69','初秋書感','陸游','宋','宋诗','song-poetry','','[]','流年冉冉不容追，餘息厭厭只自知。',64,'全唐诗/poet.song.133000.json','["流年冉冉不容追，餘息厭厭只自知。", "馬革裹尸違壯志，鹿門采藥卜幽期。", "林蟬委蛻仙何遠，巢燕成雛去已遲。", "觸事爾來多感慨，北窗閑賦早秋詩。"]'),
('65f10463-f899-4a5c-8413-2f7aa638c7df','湖上','陸游','宋','宋诗','song-poetry','','[]','石帆山下舊苔磯，回首平生念念非。',64,'全唐诗/poet.song.133000.json','["石帆山下舊苔磯，回首平生念念非。", "秋早明河低接地，夜深白露冷侵衣。", "風生古戍笳爭發，月過橫塘鵲獨飛。", "却看宦途傾奪地，怳然敗將脫重圍。"]'),
('feed4768-9d73-408d-980a-a4ab26cde54b','枕上','陸游','宋','宋诗','song-poetry','','[]','紗幮竹簟不勝清，卧看殘缸翳復明。',64,'全唐诗/poet.song.133000.json','["紗幮竹簟不勝清，卧看殘缸翳復明。", "兩樹梧桐鳴急雨，一林鴝鵒噪疏更。", "靜無狂蝶妨幽夢，懶有群鷗責舊盟。", "待旦欲尋梅市路，小舟先向步頭橫。"]'),
('678f972e-471c-4c2a-b04d-3f1cb98e74b1','書懷','陸游','宋','宋诗','song-poetry','','[]','無事自能心太平，有爲終蔽性光明。',64,'全唐诗/poet.song.133000.json','["無事自能心太平，有爲終蔽性光明。", "皮膚脫盡見真理，粱肉掃空甘菜羹。", "處處浮家成野宿，時時策蹇作山行。", "平生常笑羊裘老，史冊猶存後世名。"]'),
('7033c839-71e2-4e57-922c-528a0dae24d7','游昭牛圖','陸游','宋','宋诗','song-poetry','','[]','游昭木石師李唐，畫牛乃自其所長。',160,'全唐诗/poet.song.133000.json','["游昭木石師李唐，畫牛乃自其所長。", "出欄初聽一聲笛，意氣已無千頃荒。", "客居京口老益困，衣不揜脛鬚眉蒼。", "時時弄筆眼力健，蹄角毛骨分毫芒。", "我無沙堤金絡馬，拂拭此幅喜欲狂。", "乞骸幸蒙優詔許，置身忽在烟林傍。", "日落飲牛水滿塘，夜半飯牛天雨霜。", "俚醫灌藥美水草，老巫訶禁祓不祥。", "願我孫子勤農桑，願汝生犢筋脈强。", "碓聲驚破五更夢，歲負玉粒輸官倉。"]'),
('f4ecbb1b-1045-4594-a2be-94cf21ca0ce4','唐希雅雪鵲','陸游','宋','宋诗','song-poetry','','[]','烈風大雪吞江湖，巨木摧折竹葦枯。',128,'全唐诗/poet.song.133000.json','["烈風大雪吞江湖，巨木摧折竹葦枯。", "烏鳶瑟縮墮地死，豈復能顧卵與雛。", "棘枝拔出亂石罅，凜凜生氣獨有餘。", "耐寒兩鵲亦異稟，羽族有此山澤癯。", "神凝氣勁中自足，不待晴日相鳴呼。", "深知畫手亦怪偉，用意直刮造化爐。", "氄毛雖細爪翮健，落筆豈獨今所無。", "我評此畫如奇書，顔筋柳骨追歐虞。"]'),
('e9d40da9-ba4e-404d-91f7-b5261c2dc044','菖蒲','陸游','宋','宋诗','song-poetry','','[]','雁山菖蒲崑山石，陳叟持來慰幽寂。',96,'全唐诗/poet.song.133000.json','["雁山菖蒲崑山石，陳叟持來慰幽寂。", "寸根蹙密九節瘦，一拳突兀千金直。", "清泉碧缶相發揮，高僧野人動顔色。", "盆山蒼然日在眼，此物一來俱掃迹。", "根蟠葉茂看愈好，向來恨不相從早。", "所嗟我亦飽風霜，養氣無功日衰槁。"]'),
('e41e054b-7a47-41f3-82b3-343fe72270b4','吾廬東北皆修竹茂木羽族來栖者不可數計感而有作','陸游','宋','宋诗','song-poetry','','[]','遶舍皆茂林，萬數栖鳥雀。',72,'全唐诗/poet.song.133000.json','["遶舍皆茂林，萬數栖鳥雀。", "詰旦輒爭鳴，未暝紛已泊。", "清陰交欲暗，丹實熟可啄。", "吾廬少人迹，媿爾肯見託。", "雖無惠養德，亦免彈射虐。", "結巢俯可窺，淳風今豈薄。"]'),
('447c33c2-47ee-41e1-82fd-fd348a49621e','秋夜聞蘭亭天章寺鐘','陸游','宋','宋诗','song-poetry','','[]','絕湖上蘭亭，不過一炊頃。',72,'全唐诗/poet.song.133000.json','["絕湖上蘭亭，不過一炊頃。", "湖廢繚隄行，往返常畢景。", "猶有古寺鐘，迢迢下重嶺。", "烟雲含莽蒼，風露共凄冷。", "蕭然草堂卧，度此清夜永。", "百念一洗空，於焉發深省。"]'),
('d0965de9-290e-4257-8fe6-aa0c689485b1','閔雨','陸游','宋','宋诗','song-poetry','','[]','歲秋固多雨，每恨不及時。',96,'全唐诗/poet.song.133000.json','["歲秋固多雨，每恨不及時。", "黄塵蔽赤日，苗槁已不遲。", "踏車聲如雷，力盡真何爲。", "天豈不念民，雲族風散之。", "窮民守稼泣，便恐化棘茨。", "妻子不望活，所懼尊老饑。", "我願上天仁，顧哀民語悲。", "鞭龍起風霆，尚繼豐年詩。"]'),
('6fca559e-0368-4ab7-b551-6a2fa874042a','徒行短歌次前輩韵','陸游','宋','宋诗','song-poetry','','[]','風吹短衣雙鬢白，老人徒步歸鄉國。',64,'全唐诗/poet.song.133000.json','["風吹短衣雙鬢白，老人徒步歸鄉國。", "數樹丹楓野店西，一川紅蓼溪橋北。", "芒鞋有賣百無憂，過盡青山到渡頭。", "更求款段真多事，堪笑當年馬少游。"]'),
('7c6b8358-d2d7-4308-bd93-cdc8d38720b9','江樓次前輩韵','陸游','宋','宋诗','song-poetry','','[]','一日千回上庭樹，城南尚記嬉遊處。',64,'全唐诗/poet.song.133000.json','["一日千回上庭樹，城南尚記嬉遊處。", "俯仰人間八十年，鏡中未許朱顔去。", "甲第侵雲多貴人，朝回撲帽軟紅塵。", "江樓月夜吹長笛，誰似儂家不負身。"]'),
('2658dcc4-dbd5-48ce-8002-8a1f27de222e','七月四日夜賦','陸游','宋','宋诗','song-poetry','','[]','樓角西南月一鈎，晚瓜落刃酒新篘。',64,'全唐诗/poet.song.133000.json','["樓角西南月一鈎，晚瓜落刃酒新篘。", "仙家又愴銀河別，太史新班玉曆秋。", "衰病歲時良冉冉，窮愁身世轉悠悠。", "莫因乞巧嘲兒女，我亦飄然水上浮。"]'),
('19ce90bb-1ff8-467a-bf22-c6903a15d6cd','出近村歸偶作','陸游','宋','宋诗','song-poetry','','[]','朝騎小蹇涉烟村，擁路爭看八十身。',64,'全唐诗/poet.song.133000.json','["朝騎小蹇涉烟村，擁路爭看八十身。", "似我猶爲一好漢，問君曾見幾閑人。", "楊梅線紫開園晚，蓴菜絲長入市新。", "莫笑堅頑推不倒，天教日日享常珍。"]'),
('d6b906da-bac6-4af3-b240-d24356170c20','送子修入閩','陸游','宋','宋诗','song-poetry','','[]','士生萬里合鵬摶，憔悴青衫且自寬。',64,'全唐诗/poet.song.133000.json','["士生萬里合鵬摶，憔悴青衫且自寬。", "薄祿及親雖共喜，遠途將父亦誠難。", "關山可厭風塵惡，蓬蓽應思菽水歡。", "只道耄年心似鐵，詩成也作鼻辛酸。"]'),
('f495f909-16e8-40ef-b9b1-2490badf98e2','書志','陸游','宋','宋诗','song-poetry','','[]','飲水蕭然卧曲肱，桑村麥野醉騰騰。',64,'全唐诗/poet.song.133000.json','["飲水蕭然卧曲肱，桑村麥野醉騰騰。", "老身長子知無憾，泛宅浮家苦未能。", "南畝服勞勝乞食，腐儒垂死恥依僧。", "柴荆常閉斜陽裏，剝啄雖聞亦懶譍。"]');
